export interface ExamQuestion {
  id: number;
  domain: 1 | 2 | 3 | 4;
  domainName: string;
  question: string;
  options: [string, string, string, string];
  answer: 0 | 1 | 2 | 3;
  explanation: string;
}

export interface CamsExam {
  id: number;
  title: string;
  description: string;
  questions: ExamQuestion[];
}

const D1 = 'Risks & Methods of ML/TF';
const D2 = 'AML/CFT Compliance Programs';
const D3 = 'Financial Investigations';
const D4 = 'Law Enforcement Support';

// ═══════════════════════════════════════════════════════════════════════════
// EXAM 1  (IDs 6001–6120)
// ═══════════════════════════════════════════════════════════════════════════
const exam1: ExamQuestion[] = [
  // ── Domain 1 (31 Qs) ──────────────────────────────────────────────────
  { id:6001, domain:1, domainName:D1, question:"Which stage of money laundering involves the initial entry of illicit proceeds into the financial system?", options:["Integration","Layering","Placement","Structuring"], answer:2, explanation:"Placement is the first stage, where cash or other illicit proceeds are introduced into the financial system — typically the most vulnerable stage for detection because the funds are closest to their criminal origin." },
  { id:6002, domain:1, domainName:D1, question:"The Vienna Convention (1988) was the first international treaty to require countries to criminalize money laundering related to which predicate offense?", options:["Human trafficking","Drug trafficking","Terrorism financing","Corruption"], answer:1, explanation:"The 1988 UN Convention Against Illicit Traffic in Narcotic Drugs (Vienna Convention) first obligated signatory countries to criminalize money laundering derived from drug trafficking proceeds." },
  { id:6003, domain:1, domainName:D1, question:"What is the KEY distinction between terrorism financing (TF) and traditional money laundering (ML)?", options:["TF involves larger amounts than ML","TF only uses cryptocurrency","Funds in TF may come from legitimate sources and the goal is violence; ML conceals criminal origins","TF and ML are identical processes"], answer:2, explanation:"Unlike ML, where funds originate from crime and are being 'cleaned,' TF may involve funds from legitimate sources (e.g., donations, business income) being used to fund violent activity. The direction of value flow is fundamentally different." },
  { id:6004, domain:1, domainName:D1, question:"FATF has identified how many categories of designated predicate offenses?", options:["10","15","21","40"], answer:2, explanation:"FATF identified 21 categories of designated predicate offenses in its Recommendations, including drug trafficking, human trafficking, corruption, fraud, and tax crimes, among others." },
  { id:6005, domain:1, domainName:D1, question:"In trade-based money laundering (TBML), 'over-invoicing' allows value to move because:", options:["Exporters pay more taxes on overstated invoice values","The exporter receives more money than the goods are worth, transferring value to the exporting country","Under-invoicing hides the true value of goods","Trade invoices are not subject to AML scrutiny"], answer:1, explanation:"In over-invoicing, the importer pays more than the goods are worth. The excess value is effectively transferred to the exporter's country, enabling the movement of funds disguised as legitimate trade payments." },
  { id:6006, domain:1, domainName:D1, question:"A shell company used for money laundering is BEST characterized as:", options:["A company with many employees but no actual products","A legally incorporated entity with no meaningful business activity or genuine operations","An offshore bank account registered as a corporation","A holding company with subsidiaries in multiple jurisdictions"], answer:1, explanation:"Shell companies have legal existence on paper but conduct no real commercial activity. They are used to obscure beneficial ownership and create layers between illicit funds and their criminal origin." },
  { id:6007, domain:1, domainName:D1, question:"The hawala system is BEST described as:", options:["A cryptocurrency exchange regulated by FinCEN","A wire transfer service operating under SWIFT","An informal value transfer system based on trust networks with settlement outside formal banking channels","A legitimate remittance service exclusive to the Middle East"], answer:2, explanation:"Hawala (and similar systems like fei-ch'ien or hundi) operates on trust and a network of brokers. Funds are transferred without physical movement of money, relying on settlement through debts between brokers. It creates minimal paper trails." },
  { id:6008, domain:1, domainName:D1, question:"Which customer type MOST likely requires Enhanced Due Diligence (EDD) under FATF standards?", options:["A domestic retail customer opening a basic checking account","A foreign politically exposed person seeking a private banking relationship","A small domestic business with $20,000 monthly transactions","A nonprofit registered in the institution's home country"], answer:1, explanation:"Foreign PEPs present elevated ML/corruption risk due to their access to public funds and government power. FATF Recommendation 12 specifically requires EDD for PEPs including identifying sources of wealth and funds." },
  { id:6009, domain:1, domainName:D1, question:"The 'Black Market Peso Exchange' (BMPE) is a classic example of which ML typology?", options:["Real estate laundering","Casino chip laundering","Trade-based money laundering","Virtual asset mixing"], answer:2, explanation:"The BMPE is a sophisticated TBML scheme originating in Latin American drug trafficking, where drug dollars are sold to peso brokers who use them to purchase U.S. goods exported to Colombia, integrating funds through trade." },
  { id:6010, domain:1, domainName:D1, question:"Under FATF standards, which of the following is classified as a Designated Non-Financial Business or Profession (DNFBP)?", options:["Commercial banks","Credit unions","Real estate agents","Securities broker-dealers"], answer:2, explanation:"DNFBPs include real estate agents, lawyers, accountants, trust and company service providers, dealers in precious metals/stones, and casinos — non-bank sectors that can be exploited for ML/TF." },
  { id:6011, domain:1, domainName:D1, question:"'Smurfing' refers to which money laundering technique?", options:["Using shell companies to layer funds through multiple jurisdictions","Breaking large cash sums into smaller deposits made by multiple individuals to avoid CTR filing thresholds","Using nominee shareholders to conceal beneficial ownership","Transferring funds through cryptocurrency mixers"], answer:1, explanation:"Smurfing (also called structuring using multiple individuals) involves recruiting multiple people ('smurfs') to make cash deposits each below the $10,000 CTR threshold across multiple banks." },
  { id:6012, domain:1, domainName:D1, question:"Proliferation financing is defined as:", options:["Financing any terrorist organization","Providing funds or financial services to support the development, acquisition, or transfer of weapons of mass destruction","Financing weapons used in conventional armed conflicts","The spread of money laundering through multiple financial institutions"], answer:1, explanation:"Proliferation financing (PF) involves financing the spread of WMDs — biological, chemical, nuclear, or radiological weapons. FATF Recommendation 7 specifically addresses targeted financial sanctions related to PF." },
  { id:6013, domain:1, domainName:D1, question:"Which FATF list identifies jurisdictions subject to enhanced international scrutiny due to strategic AML/CFT deficiencies?", options:["The Basel AML Index","The FATF grey list (increased monitoring list)","The OFAC SDN List","The Wolfsberg Principles list"], answer:1, explanation:"FATF's 'grey list' (formally the list of jurisdictions under increased monitoring) identifies countries that have committed to resolving strategic deficiencies in their AML/CFT regimes under FATF oversight." },
  { id:6014, domain:1, domainName:D1, question:"'All-cash' real estate purchases raise AML concerns PRIMARILY because:", options:["They trigger automatic CTR filing with FinCEN","Real estate cannot legally be purchased without bank financing","They allow buyers to avoid mortgage lender scrutiny and integrate illicit funds into a stable high-value asset","All-cash purchases are prohibited in most U.S. states"], answer:2, explanation:"Cash real estate purchases bypass the scrutiny of mortgage lenders (who conduct CDD), allow rapid asset acquisition, and integrate illicit funds into a tangible asset that can later be sold for seemingly legitimate proceeds." },
  { id:6015, domain:1, domainName:D1, question:"Correspondent banking creates ML risk PRIMARILY because:", options:["It requires banks to share confidential customer data","Respondent bank customers are essentially unknown to the correspondent bank, creating anonymity layers","Correspondent banking accounts cannot be monitored for suspicious activity","OFAC sanctions do not apply to correspondent banking relationships"], answer:1, explanation:"The correspondent bank serves the respondent bank's customers without knowing them directly — creating 'nested' layers that can be exploited. The correspondent has limited visibility into the underlying customers and transactions." },
  { id:6016, domain:1, domainName:D1, question:"The Egmont Group is BEST described as:", options:["A group of 40 countries subject to FATF mutual evaluation","A UN committee overseeing global AML standards","An international network of financial intelligence units (FIUs) facilitating exchange of financial intelligence","A private sector AML compliance organization"], answer:2, explanation:"The Egmont Group is a network of FIUs (currently 170+ members) that facilitates the secure sharing of financial intelligence between member FIUs to combat ML, TF, and other financial crimes." },
  { id:6017, domain:1, domainName:D1, question:"Which FATF Recommendation specifically addresses virtual assets and virtual asset service providers (VASPs)?", options:["Recommendation 10","Recommendation 15","Recommendation 20","Recommendation 40"], answer:1, explanation:"FATF Recommendation 15 was updated in 2018-2019 to explicitly address virtual assets, requiring countries to apply AML/CFT measures to VASPs and implement the 'Travel Rule' for virtual asset transfers." },
  { id:6018, domain:1, domainName:D1, question:"'De-risking' in the AML context refers to:", options:["Implementing a risk-based approach to AML compliance","Financial institutions terminating or restricting entire customer categories to avoid AML risk rather than managing it","Reducing the number of SARs filed by improving transaction monitoring","Lowering the CTR threshold to capture more suspicious transactions"], answer:1, explanation:"De-risking occurs when banks exit entire market segments (e.g., MSBs, correspondent banking in high-risk regions) rather than applying risk-based management. FATF and regulators have expressed concern that de-risking drives transactions underground." },
  { id:6019, domain:1, domainName:D1, question:"The '25% threshold' for beneficial ownership collection refers to:", options:["The minimum foreign ownership percentage triggering PEP screening","The ownership threshold at which a natural person must be identified as a beneficial owner under FinCEN's CDD rule","The percentage of income a customer must disclose for EDD","The profit-sharing threshold for offshore accounts"], answer:1, explanation:"Under FinCEN's CDD rule, financial institutions must identify and verify the identity of natural persons who own 25% or more of a legal entity customer, plus any individual with significant control/management." },
  { id:6020, domain:1, domainName:D1, question:"A politically exposed person (PEP) is BEST defined as:", options:["Any foreign national opening a bank account","A U.S. government contractor with security clearance","An individual entrusted with a prominent public function, whose position creates elevated risk of bribery or corruption","Any customer who is a registered lobbyist or political donor"], answer:2, explanation:"FATF Recommendation 12 defines PEPs as individuals entrusted with prominent public functions — heads of state, senior government officials, judicial officials, military officers, senior executives of state-owned enterprises, and senior political party officials." },
  { id:6021, domain:1, domainName:D1, question:"Which ML stage involves physically transporting large amounts of cash across national borders?", options:["Smurfing","Bulk cash smuggling","Wire transfer layering","Real property integration"], answer:1, explanation:"Bulk cash smuggling — physically moving large amounts of currency across borders — is a placement method that bypasses the formal financial system entirely, avoiding CTR and SAR scrutiny." },
  { id:6022, domain:1, domainName:D1, question:"Insurance products are attractive for ML PRIMARILY because:", options:["Insurance companies are exempt from AML regulations","Premium payments provide a legitimacy veneer, and cash-value policies can be purchased then surrendered for seemingly legitimate refunds","Insurance companies cannot file SARs with FinCEN","Insurance payouts are tax-free regardless of source"], answer:1, explanation:"ML using insurance typically involves paying large premiums with illicit cash, then cancelling the policy and receiving a refund check from a legitimate insurance company — integrating funds with apparent legitimacy." },
  { id:6023, domain:1, domainName:D1, question:"A 'funnel account' is BEST characterized as:", options:["An account used exclusively for payroll disbursements","An account receiving numerous small deposits from multiple parties then rapidly wiring consolidated funds elsewhere","An offshore trust account used for estate planning","A business account with multiple authorized signatories"], answer:1, explanation:"Funnel accounts aggregate many small deposits (often from multiple parties or locations) then rapidly wire or transfer the consolidated amount, making source tracing extremely difficult — a key ML layering technique." },
  { id:6024, domain:1, domainName:D1, question:"The PRIMARY AML concern with professional gatekeepers such as attorneys and accountants is:", options:["They are exempt from AML reporting under attorney-client privilege","They can help criminals establish complex corporate structures and move funds while providing a veneer of legitimacy","They file more SARs than any other type of financial institution","They are directly supervised by FinCEN"], answer:1, explanation:"Gatekeepers — lawyers, accountants, notaries — can facilitate ML by helping set up shell companies, trusts, and complex ownership structures, and by conducting financial transactions on behalf of clients, lending professional credibility." },
  { id:6025, domain:1, domainName:D1, question:"'Layering' in the money laundering process is BEST described as:", options:["The initial deposit of cash proceeds into the financial system","The final return of funds to the criminal for legitimate use","A series of complex financial transactions designed to distance funds from their criminal origin and obscure the audit trail","Converting cash into a single wire transfer"], answer:2, explanation:"Layering involves multiple transactions — wire transfers, currency conversions, asset purchases — across multiple accounts and jurisdictions, designed to create a complex paper trail that makes tracing funds back to their criminal source extremely difficult." },
  { id:6026, domain:1, domainName:D1, question:"The 'ultimate beneficial owner' (UBO) refers to:", options:["The registered agent of a corporation","The investment broker managing an account","The natural person(s) who ultimately own or control a legal entity and on whose behalf a transaction is conducted","The corporate officer authorized to transact on behalf of a business"], answer:2, explanation:"The UBO is the real human being who ultimately owns, controls, or benefits from an entity — not the legal entity itself. Identifying UBOs is the primary objective of beneficial ownership requirements to prevent hiding behind legal structures." },
  { id:6027, domain:1, domainName:D1, question:"Which is a RED FLAG indicator for potential real estate money laundering?", options:["A buyer using a mortgage broker and obtaining conventional financing","A buyer seeking to purchase property significantly above its asking price while unconcerned about inspections","A property listed below market value in a declining neighborhood","A buyer who requests a 30-day closing timeline"], answer:1, explanation:"Overpaying for property (especially with cash), lack of concern about property condition, and rushing the transaction are classic real estate ML red flags — the buyer's priority is moving funds, not the property's value." },
  { id:6028, domain:1, domainName:D1, question:"Cryptocurrency 'mixing' or 'tumbling' services are used PRIMARILY to:", options:["Convert cryptocurrency to fiat currency at favorable exchange rates","Pool and randomly redistribute cryptocurrency to obscure transaction trails and break the link between senders and recipients","Speed up blockchain transaction confirmations","Provide custodial storage of cryptocurrency assets"], answer:1, explanation:"Mixers/tumblers pool transactions from multiple users and redistribute equivalent amounts, breaking the blockchain transaction trail. This is a key layering technique in virtual asset ML schemes." },
  { id:6029, domain:1, domainName:D1, question:"Which of the following is LEAST consistent with a legitimate money services business (MSB)?", options:["Maintaining AML policies reviewed annually by a compliance officer","Filing CTRs for cash transactions exceeding $10,000","Refusing to register with FinCEN citing belief it only applies to banks","Training employees to identify suspicious activity"], answer:2, explanation:"All MSBs — including money transmitters, check cashers, and currency dealers — must register with FinCEN. Refusing to register is a serious AML red flag and potential criminal violation." },
  { id:6030, domain:1, domainName:D1, question:"The Financial Action Task Force (FATF) currently consists of how many Recommendations?", options:["21","30","40","49"], answer:2, explanation:"FATF's 40 Recommendations (last substantially revised in 2012, with ongoing updates) are the internationally recognized standard for combating ML, TF, and proliferation financing." },
  { id:6031, domain:1, domainName:D1, question:"Which ML stage is MOST difficult for investigators to detect and prosecute?", options:["Placement","Layering","Integration","Structuring"], answer:1, explanation:"Layering is hardest to prosecute because by this stage, funds have been distanced from their criminal origin through numerous complex transactions. Proving the link between the funds and the original crime becomes extremely challenging." },
  // ── Domain 2 (28 Qs) ──────────────────────────────────────────────────
  { id:6032, domain:2, domainName:D2, question:"The FIVE pillars of an effective AML compliance program under the Bank Secrecy Act include:", options:["Internal controls, independent testing, BSA officer, ongoing training, and annual external audit","Internal controls, independent testing, BSA officer, ongoing training, and customer due diligence/beneficial ownership","Board governance, risk assessment, policies, SAR filing, and employee training","Internal controls, external audit, BSA officer, OFAC screening, and customer interviews"], answer:1, explanation:"The five BSA/AML program pillars are: (1) internal controls, (2) independent testing, (3) a designated BSA/AML compliance officer, (4) ongoing employee training, and (5) customer due diligence including beneficial ownership identification (added as 5th pillar in 2016)." },
  { id:6033, domain:2, domainName:D2, question:"A 'risk-based approach' (RBA) to AML compliance means:", options:["Applying identical due diligence to all customers regardless of risk","Filing SARs for every transaction that appears unusual","Allocating AML resources proportionally to the ML/TF risk presented by customers, products, and geographies","Reducing compliance costs by focusing only on transactions over $10,000"], answer:2, explanation:"The RBA is the cornerstone of modern AML compliance — institutions identify, assess, and understand their ML/TF risks, then apply measures commensurate with those risks, enabling efficient resource allocation." },
  { id:6034, domain:2, domainName:D2, question:"Under FinCEN's Customer Identification Program (CIP) rule, which information is required for ALL new customers?", options:["Verification of employment and income","Name, date of birth, address, and government-issued identification number","Fingerprinting and photo verification","Annual re-verification of identity documents"], answer:1, explanation:"The CIP rule (31 CFR 1020.220) requires collection of: name, date of birth (for individuals), address, and identification number (SSN for U.S. persons, passport number or similar for foreign persons)." },
  { id:6035, domain:2, domainName:D2, question:"The PRIMARY purpose of Customer Due Diligence (CDD) is:", options:["To screen all customers against the OFAC SDN List","To understand the nature and purpose of customer relationships and identify unusual or suspicious activity","To determine whether customers are required to file SARs","To comply with state licensing requirements for financial institutions"], answer:1, explanation:"CDD establishes a baseline understanding of who the customer is and what to expect from the relationship. This baseline enables the institution to detect anomalous activity that may indicate ML, TF, or other financial crime." },
  { id:6036, domain:2, domainName:D2, question:"Under FinCEN's CDD rule effective 2018, the beneficial ownership threshold for legal entity customers is:", options:["10% or more","20% or more","25% or more","50% or more"], answer:2, explanation:"The FinCEN CDD rule requires covered financial institutions to collect beneficial ownership information for legal entity customers — identifying natural persons who own 25% or more, plus one individual with significant managerial control." },
  { id:6037, domain:2, domainName:D2, question:"Enhanced Due Diligence (EDD) is SPECIFICALLY required for which category under U.S. regulations?", options:["Any customer with monthly transactions exceeding $50,000","Foreign financial institutions maintaining U.S. correspondent accounts","Any business customer with more than 10 employees","Domestic customers with more than 5 years of banking history"], answer:1, explanation:"USA PATRIOT Act Section 312 requires U.S. financial institutions to apply EDD to foreign financial institutions maintaining correspondent accounts, including assessment of their AML controls, ownership, and customer base." },
  { id:6038, domain:2, domainName:D2, question:"A PEP screening program should be:", options:["A one-time check conducted only at account opening","Ongoing — continuously monitoring for new PEP status among current customers and their beneficial owners","Limited to foreign nationals only","Applied only to customers transacting above $50,000 monthly"], answer:1, explanation:"PEP status can change (a customer may become a PEP post-onboarding), and relationships with PEPs can be established for new customers who are already PEPs. Continuous monitoring is required throughout the customer lifecycle." },
  { id:6039, domain:2, domainName:D2, question:"The MAXIMUM civil money penalty for a single willful violation of the Bank Secrecy Act can be:", options:["$10,000","$25,000","$100,000","The greater of $1 million or twice the transaction amount"], answer:3, explanation:"Under 31 U.S.C. § 5321, willful BSA violations can result in civil penalties up to the greater of $1 million or twice the amount of the transaction. The severity reflects the seriousness of intentional non-compliance." },
  { id:6040, domain:2, domainName:D2, question:"Which characteristic BEST describes an effective AML employee training program?", options:["Annual training delivered exclusively via written policy memo","Risk-based training tailored to employee roles, updated when regulations or typologies change","Training limited to BSA officers and senior management only","Training focused exclusively on SAR completion forms"], answer:1, explanation:"Effective training must be role-specific (front-line staff need different training than compliance officers), risk-appropriate, and current. Generic or infrequent training fails to adequately prepare employees to recognize and respond to ML/TF." },
  { id:6041, domain:2, domainName:D2, question:"A SAR must be filed with FinCEN within how many calendar days of initial detection of suspicious activity?", options:["15 calendar days","30 calendar days (60 if no suspect identified)","48 hours for terrorism, 30 days for all other activity","90 calendar days"], answer:1, explanation:"Under 31 CFR 1020.320, SARs must be filed within 30 calendar days of initial detection. If no suspect can be identified, the filing deadline extends to 60 calendar days from the date of the initial detection of suspicious activity." },
  { id:6042, domain:2, domainName:D2, question:"The 'safe harbor' protection for SAR filers under 31 U.S.C. § 5318(g)(3) means:", options:["SAR filers are immune from all legal liability including criminal prosecution","SAR filers are protected from civil liability for filing incorrect SARs","Financial institutions and employees are protected from civil liability for reporting suspicious activity in good faith","SAR filers are protected from OFAC enforcement actions"], answer:2, explanation:"The safe harbor protects SAR filers from civil liability (not criminal liability) when filing in good faith. This protection is essential for encouraging timely and complete SAR reporting without fear of retaliation from subjects." },
  { id:6043, domain:2, domainName:D2, question:"A financial institution is PROHIBITED from:", options:["Filing a SAR for activity below the filing threshold if the institution believes it is suspicious","Filing multiple SARs on the same subject","Notifying the subject of a SAR that a report has been filed, requested, or considered","Amending a previously filed SAR"], answer:2, explanation:"The SAR tipping-off prohibition (31 U.S.C. § 5318(g)(2)) forbids institutions from notifying the subject or related parties that a SAR has been filed or is being considered. This protects the integrity of law enforcement investigations." },
  { id:6044, domain:2, domainName:D2, question:"Which cash transaction MUST trigger a Currency Transaction Report (CTR)?", options:["A $12,000 wire transfer from a domestic correspondent bank","A $9,500 cash deposit plus a $1,000 cash withdrawal by one customer in a single business day","A $10,000 deposit made entirely by check","A $15,000 ACH transfer between two business accounts"], answer:1, explanation:"CTRs are required for cash (currency) transactions exceeding $10,000 in a single business day, including multiple transactions that aggregate to more than $10,000. Multiple cash transactions in one day are aggregated. Wire and ACH transfers are not 'cash' for CTR purposes." },
  { id:6045, domain:2, domainName:D2, question:"'Structuring' is a federal crime even if:", options:["The funds being structured are entirely from legitimate sources","The amounts structured are below $1,000 each","The customer is unaware of the CTR reporting threshold","The transactions occur at different financial institutions"], answer:0, explanation:"Under 31 U.S.C. § 5324, structuring is illegal regardless of the source of the funds — the crime is the act of intentionally breaking up transactions to evade reporting, whether or not the underlying funds are from criminal activity." },
  { id:6046, domain:2, domainName:D2, question:"Financial institutions are required to block OFAC SDN-listed transactions and:", options:["File a SAR instead of blocking when a customer matches the SDN List","Notify the customer that their transaction is blocked","Report blocked transactions and accounts to OFAC","Only block transactions over $10,000 involving SDN List matches"], answer:2, explanation:"When a transaction is blocked due to an SDN match, institutions must report the blocking to OFAC (typically within 10 business days). Notifying the customer that their transaction was blocked due to sanctions would constitute tipping off." },
  { id:6047, domain:2, domainName:D2, question:"USA PATRIOT Act Section 312 requires U.S. banks to apply EDD to correspondent accounts for foreign banks that:", options:["Have fewer than 1,000 domestic customers","Are located in jurisdictions with weak AML controls or are shell banks","Have been in operation for fewer than 5 years","Are not members of the Wolfsberg Group"], answer:1, explanation:"Section 312 requires enhanced scrutiny for foreign banks in jurisdictions with weak AML controls or that are otherwise high-risk, including assessment of the foreign bank's ownership, AML program, and the nature of transactions conducted through the account." },
  { id:6048, domain:2, domainName:D2, question:"Which of the following is a 'covered financial institution' required by FinCEN to establish an AML program?", options:["A sole proprietorship providing informal payment services","A foreign bank with no U.S. operations","A federally insured credit union","A privately held real estate investment trust"], answer:2, explanation:"Federally insured credit unions are covered financial institutions required to maintain BSA/AML compliance programs. The BSA broadly covers banks, credit unions, broker-dealers, money services businesses, and certain other financial institutions." },
  { id:6049, domain:2, domainName:D2, question:"The BEST indicator of an effective independent AML testing function is:", options:["Testing conducted by the same team that designed the AML program","Annual self-assessments completed by the BSA officer","Testing by a qualified party independent of the AML function, conducted on a risk-based schedule with results reported to the board","External audits mandated every five years by regulation"], answer:2, explanation:"Independence is critical — the AML program cannot effectively self-audit. The tester must be free from the day-to-day compliance function, and results must reach the board so deficiencies receive appropriate governance attention." },
  { id:6050, domain:2, domainName:D2, question:"USA PATRIOT Act Section 314(b) allows:", options:["FinCEN to share SAR data with law enforcement","Financial institutions to voluntarily share suspicious activity information with each other to identify ML/TF","Regulators to share examination findings with other agencies","BSA officers to access classified law enforcement databases"], answer:1, explanation:"Section 314(b) creates a voluntary information-sharing framework among financial institutions (after notifying FinCEN) to pool information about suspected ML or TF. This collaboration can reveal broader criminal patterns invisible to any single institution." },
  { id:6051, domain:2, domainName:D2, question:"'Know your customer's customer' (KYCC) is MOST relevant in which context?", options:["Background checks on all customers' family members","Understanding the customers of an institution's direct customers, particularly in correspondent banking","A FATF requirement to screen customers' customers for PEP status","Collecting identification from all third parties transacting through a customer's account"], answer:1, explanation:"KYCC is critical in correspondent banking — the U.S. correspondent bank must understand not just its respondent bank client, but also the types of customers the respondent serves, since those underlying customers ultimately transact through the correspondent." },
  { id:6052, domain:2, domainName:D2, question:"A Money Services Business (MSB) is REQUIRED to:", options:["Obtain a state banking license before operating","Register with FinCEN, develop an AML program, and file SARs and CTRs as applicable","Limit cash transactions to $5,000 per customer per day","Obtain written customer consent before filing CTRs"], answer:1, explanation:"MSBs must: register with FinCEN (within 180 days of establishing); implement an AML program with designated compliance officer, training, internal controls, and independent review; file SARs and CTRs as required." },
  { id:6053, domain:2, domainName:D2, question:"The PRIMARY reason to conduct an enterprise-wide AML risk assessment is:", options:["To satisfy regulatory examiners during routine examinations","To identify, assess, and prioritize ML/TF risks specific to the institution's products, services, customers, and geography as the foundation for the AML program","To determine the optimal number of SARs to file annually","To benchmark compliance costs against industry peers"], answer:1, explanation:"The risk assessment drives the entire AML program — without understanding the institution's specific risks, the program cannot be effectively tailored. Regulators view a robust risk assessment as the foundation of any credible AML compliance effort." },
  { id:6054, domain:2, domainName:D2, question:"Under the Bank Secrecy Act, records of wire transfers of $3,000 or more must be retained for:", options:["1 year","3 years","5 years","7 years"], answer:2, explanation:"The BSA generally requires financial institutions to retain most records — including wire transfer records of $3,000 or more — for five years from the date of the transaction. SAR-related records must also be retained for five years." },
  { id:6055, domain:2, domainName:D2, question:"'Willful blindness' in AML refers to:", options:["Deliberately avoiding knowledge of suspicious activity to avoid reporting obligations","A bank examiner's failure to detect AML deficiencies","Transaction monitoring systems unable to detect layering","Customer refusal to provide required identification"], answer:0, explanation:"Willful blindness (also called 'conscious avoidance') occurs when compliance personnel or management deliberately avoid learning facts that would create reporting obligations. It is treated the same as actual knowledge under the law." },
  { id:6056, domain:2, domainName:D2, question:"The BSA/AML compliance officer should ideally report to:", options:["The head of retail banking to maintain frontline accountability","The Chief Financial Officer to align compliance with financial reporting","Senior management or the board of directors to ensure independence and authority","The Chief Technology Officer who manages transaction monitoring systems"], answer:2, explanation:"The compliance officer must have sufficient authority and independence to challenge business lines. Reporting directly to senior management or the board ensures the function is not subordinated to revenue-generating units whose activities it monitors." },
  { id:6057, domain:2, domainName:D2, question:"When a compliance officer identifies that a customer's transactions are inconsistent with their stated business profile, the FIRST step should be:", options:["File a SAR immediately","Close the customer's account and report to law enforcement","Conduct a review to determine whether the activity is explainable before deciding whether to escalate and/or file a SAR","Contact the customer directly for an explanation before any further action"], answer:2, explanation:"The process is investigate first, then decide. A good-faith review of available information — transaction history, profile, public information — should precede the SAR filing decision. Filing without review may miss context; filing too late may constitute negligence." },
  { id:6058, domain:2, domainName:D2, question:"The 'travel rule' (31 CFR 1010.410) requires financial institutions to:", options:["Report all international wire transfers to OFAC","Transmit specified originator and beneficiary information for wire transfers of $3,000 or more","Obtain travel records from customers conducting international transactions","Verify the purpose of all international wire transfers over $10,000"], answer:1, explanation:"The travel rule requires institutions to 'pass along' identifying information about wire transfer originators and beneficiaries — name, account number, address, amount — with funds transmittal orders of $3,000 or more." },
  { id:6059, domain:2, domainName:D2, question:"The key difference between USA PATRIOT Act Section 314(a) and 314(b) is:", options:["314(a) is voluntary while 314(b) is mandatory","314(a) lets institutions share with each other; 314(b) requires institutions to respond to law enforcement requests","314(a) is a mandatory law enforcement information request mechanism; 314(b) is voluntary inter-institutional information sharing","314(a) applies to domestic institutions; 314(b) applies internationally"], answer:2, explanation:"314(a): law enforcement sends a request to FinCEN, which transmits to financial institutions, requiring them to search records and respond confidentially. 314(b): voluntary program where institutions notify FinCEN and may share ML/TF information with each other." },
  // ── Domain 3 (30 Qs) ──────────────────────────────────────────────────
  { id:6060, domain:3, domainName:D3, question:"A financial intelligence unit (FIU) serves which PRIMARY function?", options:["Prosecuting money laundering cases","Receiving, analyzing, and disseminating financial intelligence to combat ML/TF","Setting international AML standards","Licensing financial institutions"], answer:1, explanation:"FIUs are central to national AML/CFT systems — they serve as the hub for receiving STRs/SARs, analyzing financial intelligence, and sharing it with law enforcement, regulators, and foreign FIUs through the Egmont Group network." },
  { id:6061, domain:3, domainName:D3, question:"A 'Suspicious Transaction Report' (STR) is:", options:["The U.S.-specific term for all SAR filings","The equivalent of a SAR used by financial intelligence units in many non-U.S. jurisdictions","A report filed when a transaction exceeds the CTR threshold","A law enforcement report filed when criminal charges are anticipated"], answer:1, explanation:"Most countries outside the U.S. use the term 'STR' (Suspicious Transaction Report) for what the U.S. calls a SAR (Suspicious Activity Report). Both serve the same function: reporting suspected ML/TF to the national FIU." },
  { id:6062, domain:3, domainName:D3, question:"Under FinCEN's 314(a) program, upon receiving a request an institution must:", options:["Respond within 5 business days and may share results with other financial institutions","Search its records and respond within 14 days, maintaining strict confidentiality about the inquiry","File a SAR before responding","Decline to respond if no matching accounts are found"], answer:1, explanation:"Institutions must search their records going back 12 months for accounts and transactions matching subjects identified in 314(a) requests, and respond to FinCEN within 14 days. The existence of the request must be kept confidential." },
  { id:6063, domain:3, domainName:D3, question:"Transaction monitoring systems in AML are designed to:", options:["Prevent all suspicious transactions from being processed","Automatically file SARs when suspicious activity is detected","Flag unusual activity patterns based on rules or behavioral analytics for human review and investigation","Verify customer identity in real time for every transaction"], answer:2, explanation:"Transaction monitoring systems generate alerts for human review — they do not automatically file SARs or block transactions. Analysts then investigate alerts and make filing decisions based on all available information." },
  { id:6064, domain:3, domainName:D3, question:"The 'reasonable basis to suspect' standard for SAR filing means:", options:["Law enforcement must confirm suspicious activity before a SAR is filed","Suspicion must be based on documented facts that a reasonable person in the same position would find suspicious","SAR filing requires consensus among multiple compliance officers","The standard is equivalent to 'probable cause' used in criminal law"], answer:1, explanation:"Financial institutions are not required to prove criminal activity — they must have a reasonable, documented basis for suspicion. This is a lower standard than probable cause, recognizing that institutions lack investigative authority." },
  { id:6065, domain:3, domainName:D3, question:"Which scenario BEST supports a SAR filing for structuring?", options:["A customer making a single deposit of $9,500 with no other unusual indicators","A customer making daily $9,800 cash deposits for two weeks despite running a business that primarily accepts electronic payments","A business customer with declining revenues making smaller deposits","A customer making regular payroll deposits that vary slightly each month"], answer:1, explanation:"The combination of: (1) amounts just below $10,000; (2) daily frequency; (3) inconsistency with the customer's stated business type (electronic payments); and (4) the pattern over multiple weeks — together provide a reasonable basis to suspect deliberate structuring." },
  { id:6066, domain:3, domainName:D3, question:"A SAR continuation or 'follow-up' filing is typically appropriate when:", options:["The suspicious activity has been resolved","New information about a previously reported subject has been discovered that is unrelated to the original SAR","The same subject continues to exhibit suspicious activity after the initial SAR was filed","Law enforcement requests additional information about a prior SAR"], answer:2, explanation:"When suspicious activity continues after an initial SAR is filed, SAR filers should file continuation SARs — typically every 90 days — to keep law enforcement informed of ongoing suspicious conduct by the same subject." },
  { id:6067, domain:3, domainName:D3, question:"When law enforcement presents a grand jury subpoena for customer records, the institution should:", options:["Notify the customer immediately and give them the opportunity to object","Refuse to comply until a court order is separately obtained","Comply with the subpoena and generally refrain from notifying the customer, unless legally permitted","File a SAR before producing any records"], answer:2, explanation:"Grand jury subpoenas are compulsory legal process — institutions must comply. Notifying the customer without legal authorization could obstruct the investigation and may violate the court's implied confidentiality. Legal counsel should be consulted." },
  { id:6068, domain:3, domainName:D3, question:"'Link analysis' in financial investigations refers to:", options:["Analyzing hyperlinks on a suspect's social media","Identifying relationships and connections between individuals, accounts, entities, and transactions","A regulatory tool used by FinCEN to connect SAR filings","Software that links transaction monitoring alerts to specific regulations"], answer:1, explanation:"Link analysis (network analysis) maps and visualizes the relationships between people, accounts, and transactions to reveal patterns invisible in raw data — critical for identifying criminal networks, co-conspirators, and fund flows." },
  { id:6069, domain:3, domainName:D3, question:"The Financial Crimes Enforcement Network (FinCEN) is a bureau of which U.S. department?", options:["Department of Justice","Department of Homeland Security","Department of the Treasury","Federal Reserve Board"], answer:2, explanation:"FinCEN is a bureau of the U.S. Department of the Treasury. It administers the BSA, collects and analyzes financial intelligence, and serves as the U.S. FIU in the Egmont Group." },
  { id:6070, domain:3, domainName:D3, question:"A CTR must be filed for cash transactions exceeding $10,000. 'Cash' for CTR purposes includes:", options:["Wire transfers in any currency","ACH transfers aggregating over $10,000","Currency (coins and paper money), as well as cashier's checks, money orders, and traveler's checks in certain circumstances","Only U.S. dollar-denominated transactions"], answer:2, explanation:"'Cash' for CTR purposes is primarily currency (coins and paper money). Under specific rules, cashier's checks, money orders, and traveler's checks with face values of $3,000-$10,000 may also be treated as cash in certain transactions." },
  { id:6071, domain:3, domainName:D3, question:"Which is NOT a valid reason to grant a customer a CTR exemption?", options:["The customer is a bank or government agency","The customer is a listed public company","The customer is a business that regularly makes large cash transactions","The customer has never been the subject of a SAR"], answer:3, explanation:"CTR exemptions (Phase I and Phase II) are available for banks, government agencies, listed companies, and qualifying businesses with routine large cash needs — but never solely based on clean SAR history. SAR history is irrelevant to exemption eligibility." },
  { id:6072, domain:3, domainName:D3, question:"'Financial profiling' in AML investigations involves:", options:["Conducting credit checks on suspected money launderers","Comparing actual transaction activity against the customer's expected activity profile to identify anomalies","Publishing information about suspected money launderers","Profiling customers by race or national origin to determine risk"], answer:1, explanation:"Financial profiling builds an expected behavior baseline for a customer or suspect, then identifies deviations. This is the analytical foundation for transaction monitoring and is used in investigations to establish patterns of criminal financial behavior." },
  { id:6073, domain:3, domainName:D3, question:"The Egmont Group Principles for Information Exchange establish that:", options:["FIUs may share information freely with any requesting country","FIU-to-FIU information exchange should be reciprocal and used only for the purposes for which it was provided","FIU information may be used as evidence in criminal proceedings without restriction","FIUs must share all received information with their domestic law enforcement"], answer:1, explanation:"Egmont Group principles require that exchanged information be used only for the stated purpose, that confidentiality be maintained, and that the sharing relationship be reciprocal — protecting the integrity of the international FIU network." },
  { id:6074, domain:3, domainName:D3, question:"A 'funds flow analysis' in financial investigation is used to:", options:["Determine a suspect's net worth for tax assessment","Trace the movement of funds from criminal activity through financial channels to their ultimate destination","Quantify the total amount of currency transactions above the CTR threshold","Establish the market value of seized assets for forfeiture proceedings"], answer:1, explanation:"Funds flow analysis traces the 'follow the money' path — from the criminal proceeds' origin, through each financial transaction and institution, to the point where funds are ultimately spent or converted — building the factual basis for prosecution and asset recovery." },
  { id:6075, domain:3, domainName:D3, question:"SAR data filed with FinCEN can be accessed by:", options:["The public via FOIA requests","The subject of a SAR upon request","Law enforcement, regulatory examiners, and FinCEN analysts for authorized purposes","Any financial institution that files a 314(b) notice"], answer:2, explanation:"SAR data is highly confidential. Access is restricted to law enforcement, regulatory examiners conducting AML oversight, FinCEN analysts, and intelligence community members with proper legal authorization — not the public or SAR subjects." },
  { id:6076, domain:3, domainName:D3, question:"A 'high-risk country' for AML purposes is BEST identified by reference to:", options:["Countries with GDP below the World Bank poverty threshold","Countries with populations under 10 million","Countries identified by FATF as having strategic AML/CFT deficiencies or subject to increased monitoring","Countries without a central bank"], answer:2, explanation:"FATF's grey and black lists are the primary internationally recognized reference for high-risk jurisdictions. Institutions also use other sources: OFAC sanctions lists, Basel AML Index, Transparency International Corruption Perceptions Index, and State Department reports." },
  { id:6077, domain:3, domainName:D3, question:"'Proactive SAR filing' refers to:", options:["Filing SARs before suspicious activity is confirmed, as a precaution","An institution identifying and reporting suspicious activity without waiting for a law enforcement inquiry or customer complaint","Law enforcement requesting that institutions file SARs on specific subjects","Filing a SAR for every transaction flagged by the automated monitoring system"], answer:1, explanation:"Proactive SAR filing is the ideal — the institution independently identifies and reports suspicious activity through its own monitoring and investigation, not simply in response to external pressure or law enforcement requests." },
  { id:6078, domain:3, domainName:D3, question:"A 'money mule' is BEST described as:", options:["A drug cartel's financial controller","A person who transfers illegally acquired money on behalf of others, often unknowingly","A bank employee who accepts bribes to facilitate money laundering","A shell company used to hold criminal proceeds"], answer:1, explanation:"Money mules are individuals (often recruited via romance scams, job scams, or other deception) who transfer funds on behalf of criminals, typically believing they are doing legitimate work. They facilitate placement and layering of criminal proceeds." },
  { id:6079, domain:3, domainName:D3, question:"'Red flags' in AML represent:", options:["Transactions that automatically require SAR filing","Indicators that, individually or in combination, suggest possible money laundering or other financial crime warranting further investigation","Customers placed on FinCEN's watch list","Transactions blocked by OFAC"], answer:1, explanation:"Red flags are indicators of potential suspicious activity — not proof of a crime. They trigger enhanced scrutiny and investigation. A single red flag may be insufficient for SAR filing, but combinations or patterns of red flags strengthen the basis for reporting." },
  { id:6080, domain:3, domainName:D3, question:"A customer relationship manager observes a longtime business customer has begun making daily cash deposits of $9,500, significantly above their historical pattern. The RM should FIRST:", options:["Accept the activity as a business decision","Immediately close the account","Escalate the observation to compliance for review of possible structuring","Ask the customer to reduce their deposit amounts"], answer:2, explanation:"The RM is the first line of defense. Noticing a pattern inconsistent with the customer's history — especially amounts just below the CTR threshold at daily frequency — is a structuring red flag requiring escalation to the compliance team for investigation." },
  { id:6081, domain:3, domainName:D3, question:"'Network analysis' in AML investigations BEST describes:", options:["Analyzing computer network logs for cybersecurity vulnerabilities","Mapping relationships between accounts, entities, and individuals to identify the full scope of suspected ML activity","Reviewing international wire transfer networks for unusual patterns","Analyzing the geographic distribution of branches for compliance risk"], answer:1, explanation:"Network analysis is a core financial investigation technique that reveals criminal networks by visualizing connections between suspects, accounts, and transactions — exposing shell company ownership chains, money mule networks, and co-conspirator relationships." },
  { id:6082, domain:3, domainName:D3, question:"A SAR narrative should contain:", options:["The compliance officer's personal opinion on the customer's guilt","Objective facts — who, what, when, where, and why — regarding the suspicious activity in clear narrative form","A recommendation for criminal prosecution","Only transactions over $10,000"], answer:1, explanation:"The SAR narrative is the most critical section for law enforcement utility. It should be factual, clear, and comprehensive — describing the suspicious activity, the parties involved, the pattern, and the basis for suspicion without unsupported legal conclusions." },
  { id:6083, domain:3, domainName:D3, question:"Which of the following BEST describes 'layering through securities transactions'?", options:["Purchasing securities in an offshore account and immediately converting to cash","Rapidly buying and selling securities with proceeds wired to multiple offshore accounts to create a complex audit trail","Using nominee shareholders to hold securities in a trust","Investing illicit funds in index funds to generate legitimate returns"], answer:1, explanation:"Securities-based layering exploits the complexity and speed of capital markets — a criminal can make numerous trades, moving funds across accounts and jurisdictions, creating a web of transactions that are individually legitimate but collectively designed to obscure the money trail." },
  { id:6084, domain:3, domainName:D3, question:"The final step before filing a SAR should be:", options:["Notifying the customer of the pending SAR","Obtaining a court order authorizing the filing","Reviewing the SAR for accuracy and completeness, and obtaining required supervisory approval","Waiting for law enforcement to confirm an existing investigation"], answer:2, explanation:"SAR filing is an important legal act with legal protections. Before submitting, the narrative should be reviewed for factual accuracy, completeness, and relevance, and the filing should be approved by a designated supervisor per the institution's SAR decision-making policy." },
  { id:6085, domain:3, domainName:D3, question:"Transaction monitoring systems generate excessive 'false positives' when:", options:["They miss genuinely suspicious transactions that should be investigated","They flag legitimate transactions as suspicious, creating unnecessary investigative workload","They file SARs automatically without human review","They fail to aggregate related transactions from the same customer"], answer:1, explanation:"False positives (alerts on non-suspicious activity) reduce investigative efficiency and can mask real suspicious activity amid alert volume. High false positive rates indicate that monitoring scenarios need tuning — calibrating thresholds to the institution's specific risk profile." },
  { id:6086, domain:3, domainName:D3, question:"An institution's AML lookback review ordered following an enforcement action typically involves:", options:["Reviewing only current customer CIP documentation","A retrospective review of historical transactions to identify suspicious activity that was not previously detected and reported","A forward-looking review of expected future transaction patterns","Reviewing only accounts closed since the enforcement action"], answer:1, explanation:"A lookback review is a remediation tool — re-examining historical transaction data using improved detection methods to identify any suspicious activity that the institution's prior program failed to detect, with SAR filings made as appropriate for newly identified suspicious activity." },
  { id:6087, domain:3, domainName:D3, question:"The primary difference between a 'blocked' account and a 'rejected' transaction under OFAC rules is:", options:["There is no meaningful difference; the terms are interchangeable","A blocked account involves a match to the SDN List (funds held); a rejected transaction involves a prohibited transaction that must be declined but funds need not be held","Rejected transactions are reported to OFAC but blocked accounts are not","Blocking applies only to accounts while rejection applies only to wire transfers"], answer:1, explanation:"Blocking applies when OFAC-prohibited parties' property is involved — the funds/property must be frozen in a blocked account. Rejection applies to transactions that must be refused (e.g., involving certain countries) but where no property blocking is required." },
  { id:6088, domain:3, domainName:D3, question:"Under FinCEN's CDD rule, which entity type is explicitly EXEMPT from beneficial ownership requirements?", options:["Foreign corporations operating in the U.S.","Domestic companies listed on major U.S. exchanges subject to SEC reporting requirements","Limited partnerships with fewer than 10 partners","Non-profit organizations registered with the IRS"], answer:1, explanation:"The CDD rule exempts publicly traded domestic companies (and their subsidiaries) from beneficial ownership collection because they are already subject to SEC disclosure requirements that make their ownership transparent." },
  { id:6089, domain:3, domainName:D3, question:"'Adverse media screening' in AML compliance refers to:", options:["Monitoring for negative news coverage of the financial institution itself","Reviewing news sources and public records for negative information about customers indicating possible involvement in financial crime","Screening customer communications for threatening language","Reviewing social media for customers' political content"], answer:1, explanation:"Adverse media (negative news) screening supplements transaction monitoring and CDD by identifying public information about a customer — criminal charges, regulatory actions, civil lawsuits, or unfavorable associations — that may indicate elevated ML/TF risk." },
  // ── Domain 4 (31 Qs) ──────────────────────────────────────────────────
  { id:6090, domain:4, domainName:D4, question:"Asset forfeiture in money laundering cases may be:", options:["Criminal forfeiture only, requiring a conviction","Civil forfeiture only, not requiring a conviction","Either criminal forfeiture (requiring conviction) or civil forfeiture (not requiring conviction)","Only available after a federal conviction for drug trafficking"], answer:2, explanation:"Both criminal and civil forfeiture are available. Criminal forfeiture follows a conviction and is in personam. Civil forfeiture is an in rem action against the property itself and does not require a criminal conviction — a lower burden of proof applies." },
  { id:6091, domain:4, domainName:D4, question:"A 'mutual legal assistance treaty' (MLAT) is used to:", options:["Share regulatory examination findings between countries","Request formal legal assistance from a foreign country — including evidence gathering, witness statements, and asset restraint — in criminal investigations","Allow law enforcement to physically pursue criminals across borders","Facilitate FATF mutual evaluation reviews between member countries"], answer:1, explanation:"MLATs are bilateral or multilateral treaties providing the formal legal mechanism for international cooperation in criminal matters — including obtaining evidence, serving process, executing searches, restraining assets, and facilitating extradition." },
  { id:6092, domain:4, domainName:D4, question:"The PRIMARY tool by which U.S. law enforcement obtains account records from domestic financial institutions is:", options:["A supervisory subpoena","An administrative subpoena, grand jury subpoena, or court order","A FinCEN 314(a) request","An MLAT request"], answer:1, explanation:"Law enforcement uses various compulsory legal process to obtain financial records: administrative subpoenas (for certain agencies), grand jury subpoenas, and court orders. The 314(a) process is an information query, not a document production mechanism." },
  { id:6093, domain:4, domainName:D4, question:"USA PATRIOT Act Section 311 gives the Secretary of the Treasury authority to:", options:["Impose criminal penalties on foreign financial institutions","Designate foreign financial institutions or jurisdictions as 'primary money laundering concerns' and apply special measures","Freeze assets of domestic financial institutions with AML deficiencies","Revoke the operating licenses of non-compliant financial institutions"], answer:1, explanation:"Section 311 is a powerful regulatory tool allowing Treasury to designate jurisdictions or institutions as primary ML concerns and impose up to five 'special measures' — including prohibiting U.S. banks from maintaining correspondent accounts with the designated entity." },
  { id:6094, domain:4, domainName:D4, question:"The primary U.S. federal statute criminalizing money laundering is:", options:["18 U.S.C. § 1956 and § 1957","31 U.S.C. § 5318","12 C.F.R. § 326","26 U.S.C. § 6050I"], answer:0, explanation:"18 U.S.C. § 1956 (money laundering) and § 1957 (engaging in monetary transactions in criminally derived property) are the core federal ML criminal statutes. § 1956 covers concealment, transactional, and international ML; § 1957 covers transactions over $10,000 in criminally derived property." },
  { id:6095, domain:4, domainName:D4, question:"In a U.S. civil forfeiture action, who bears the burden of proof?", options:["The government must prove beyond a reasonable doubt that property is connected to crime","The property owner must prove the property is clean","The government must show probable cause that property is connected to crime, after which the burden shifts to the owner","Civil forfeiture is automatic upon law enforcement seizure"], answer:2, explanation:"Civil forfeiture (under 18 U.S.C. § 981 and 984) requires the government to establish probable cause — the property is connected to crime. The burden then shifts to the owner to prove the property is not subject to forfeiture by a preponderance of evidence." },
  { id:6096, domain:4, domainName:D4, question:"A 'letter rogatory' differs from an MLAT request in that:", options:["Letters rogatory are faster than MLATs","A letter rogatory is a formal judicial request transmitted through diplomatic channels, while an MLAT provides a treaty-based mechanism with more reliable and timely results","MLATs apply only to criminal investigations; letters rogatory cover civil matters","Letters rogatory require the target country's central bank consent"], answer:1, explanation:"Letters rogatory are slower and less reliable because they depend on diplomatic channels and the foreign court's discretion. MLATs provide treaty obligations and typically produce results more quickly and with greater certainty." },
  { id:6097, domain:4, domainName:D4, question:"USA PATRIOT Act Section 326 requires financial institutions to implement:", options:["Enhanced due diligence for all foreign correspondent banks","Customer Identification Programs (CIPs) to verify customer identity at account opening","Ongoing monitoring of all PEP accounts","Transaction monitoring systems capable of detecting structuring"], answer:1, explanation:"Section 326 mandated the CIP rules implemented by FinCEN and regulators — requiring financial institutions to verify the identity of persons opening accounts, using both documentary and non-documentary methods as appropriate." },
  { id:6098, domain:4, domainName:D4, question:"When a financial institution receives a National Security Letter (NSL), it:", options:["Must notify the customer immediately","May file a SAR but is not required to","Must provide the requested information and is subject to a gag order prohibiting disclosure of the NSL's existence","May decline to respond if the request is outside its service area"], answer:2, explanation:"NSLs are administrative subpoenas issued by the FBI without judicial approval for national security investigations. Recipients are legally prohibited (gag order) from disclosing that they received an NSL. The institution must comply and produce responsive records." },
  { id:6099, domain:4, domainName:D4, question:"International asset recovery is MOST effectively pursued through:", options:["Direct negotiation between countries' law enforcement without formal treaties","Filing a FinCEN SAR with an international flag","MLATs, the Egmont Group FIU network, and other formal international cooperation mechanisms","Private legal action in the country where assets are held"], answer:2, explanation:"International asset recovery requires formal legal cooperation — MLATs for evidence and asset restraint, Egmont FIU network for financial intelligence, and international law enforcement networks (e.g., INTERPOL) for coordination. Informal approaches are rarely effective for significant asset recovery." },
  { id:6100, domain:4, domainName:D4, question:"'Parallel financial investigation' means:", options:["Two agencies conducting separate, unrelated investigations","Simultaneously investigating both the underlying predicate offense and the associated money laundering","Coordinating investigations between the IRS and FinCEN","Conducting civil and criminal forfeiture simultaneously"], answer:1, explanation:"Parallel financial investigation — pursuing both the predicate crime and the money laundering concurrently — maximizes the strength of the case, enables asset recovery, and often reveals the full criminal network more effectively than investigating them sequentially." },
  { id:6101, domain:4, domainName:D4, question:"The Anti-Money Laundering Act of 2020 (AMLA) made all of the following changes EXCEPT:", options:["Strengthened whistleblower protections and created reward programs","Directed FinCEN to establish a beneficial ownership registry","Required reporting companies to disclose beneficial ownership to FinCEN","Eliminated the CTR filing requirement for transactions over $10,000"], answer:3, explanation:"The AMLA 2020 strengthened whistleblower provisions, created the Corporate Transparency Act beneficial ownership registry, modernized AML priorities, and expanded BSA jurisdiction. It did NOT eliminate CTR reporting requirements." },
  { id:6102, domain:4, domainName:D4, question:"OFAC's '50 percent rule' states that:", options:["An entity is subject to sanctions if sanctioned persons own 50% or more, individually or in the aggregate","Penalties for OFAC violations are 50% of the transaction value","Institutions must screen 50% of their customer base against the SDN List monthly","Blocked assets must be reported to OFAC within 50 days"], answer:0, explanation:"Under OFAC's 50% rule, any entity owned 50% or more (directly or indirectly, individually or in aggregate) by a blocked person is itself treated as blocked, even if not explicitly listed. This prevents circumvention through majority-ownership vehicles." },
  { id:6103, domain:4, domainName:D4, question:"When a financial institution discovers it has processed transactions for an SDN-listed entity, it should:", options:["File a SAR and continue the relationship with enhanced monitoring","Block remaining funds, file an OFAC report, and refrain from tipping off the customer","Notify the customer and allow them to resolve the matter before reporting to OFAC","Contact law enforcement and await instructions before blocking funds"], answer:1, explanation:"OFAC violations require immediate action: block all remaining funds/assets, file an OFAC blocking/rejection report, and do not inform the customer (to avoid tipping off, which could impede a law enforcement investigation). An OFAC report is distinct from but may be accompanied by a SAR." },
  { id:6104, domain:4, domainName:D4, question:"Criminal penalties under the BSA for willful violations include up to:", options:["$100,000 fine and 5 years imprisonment","$250,000 fine and 5 years imprisonment","$1,000,000 fine and 10 years imprisonment","$500,000 fine and 3 years imprisonment"], answer:1, explanation:"31 U.S.C. § 5322 provides for criminal penalties for willful BSA violations: up to $250,000 in fines and up to 5 years imprisonment, or both. For violations committed while violating another U.S. law (e.g., drug trafficking), penalties increase to $500,000 and 10 years." },
  { id:6105, domain:4, domainName:D4, question:"Law enforcement 'financial profiling' of a money laundering suspect is MOST commonly used to:", options:["Determine whether to add the suspect to the OFAC SDN List","Establish a pattern of criminal financial behavior supporting charges and asset forfeiture","Calculate the exact dollar amount laundered for sentencing","Identify every financial institution used by the suspect"], answer:1, explanation:"Financial profiles — establishing known income versus expenditures and assets — allow investigators to demonstrate that a suspect's lifestyle and assets cannot be explained by legitimate income, supporting both ML charges and forfeiture of ill-gotten gains." },
  { id:6106, domain:4, domainName:D4, question:"A bank employee violates the SAR tipping-off prohibition by:", options:["Discussing a SAR filing with the BSA officer","Sharing SAR information with external auditors during an AML program review","Mentioning to a customer that a SAR was filed about their account","Including SAR information in a regulatory examination response"], answer:2, explanation:"Disclosing the existence of a SAR to its subject (or to third parties associated with the subject) is a federal crime under 31 U.S.C. § 5318(g)(2). Internal sharing with appropriate compliance personnel and sharing with regulators and auditors are permissible." },
  { id:6107, domain:4, domainName:D4, question:"A 'consent order' for AML deficiencies typically requires:", options:["Criminal prosecution of responsible officers","Immediate closure of the institution","Remediation of identified AML deficiencies under regulatory supervision within specified timeframes, often with civil money penalties","Automatic civil forfeiture of connected assets"], answer:2, explanation:"Consent orders are negotiated settlements between financial institutions and their regulators — the institution agrees to specific remediation actions (enhanced controls, governance improvements, lookback reviews) and potentially civil money penalties, without the need for contested enforcement proceedings." },
  { id:6108, domain:4, domainName:D4, question:"Which provision of the USA PATRIOT Act allows financial institutions to voluntarily share suspicious activity information with EACH OTHER?", options:["Section 311","Section 312","Section 314(a)","Section 314(b)"], answer:3, explanation:"Section 314(b) creates a safe harbor for financial institutions to voluntarily share information about persons and their transactions when they believe the transactions may involve ML or TF, after giving FinCEN notice of their intent to share." },
  { id:6109, domain:4, domainName:D4, question:"U.S. financial institutions are PROHIBITED from opening or maintaining correspondent accounts with:", options:["Foreign banks without deposit insurance","Shell banks with no physical presence and not affiliated with a regulated financial institution","Foreign banks not registered with FinCEN","Foreign banks that hold correspondent accounts with other U.S. banks"], answer:1, explanation:"USA PATRIOT Act Section 313 explicitly prohibits U.S. financial institutions from maintaining correspondent accounts with foreign shell banks (those with no physical presence in any country and no regulatory oversight). Section 319 requires due diligence to ensure this." },
  { id:6110, domain:4, domainName:D4, question:"A SAR narrative must clearly describe:", options:["The compliance officer's legal conclusions about the customer","The who, what, when, where, and why of the suspicious activity to enable effective law enforcement use","Only the specific transaction that triggered the alert","A recommendation for account closure"], answer:1, explanation:"Law enforcement relies on SAR narratives to build investigations. A strong narrative describes the subject(s) involved, the transactions/pattern, the time period, why the activity is suspicious, and how it relates to potential ML/TF — providing actionable intelligence." },
  { id:6111, domain:4, domainName:D4, question:"A financial institution that willfully fails to file a required SAR may face:", options:["Only regulatory sanctions, not criminal penalties","Both civil penalties and potential criminal prosecution for the institution and responsible individuals","Automatic loss of its banking charter","Only penalties from its primary federal regulator"], answer:1, explanation:"Willful failure to file SARs can result in: civil money penalties from FinCEN/banking regulators, and potentially criminal prosecution under 31 U.S.C. § 5322. Individuals responsible for the willful failure may also face personal criminal liability." },
  { id:6112, domain:4, domainName:D4, question:"'Source of funds' (SOF) due diligence is MOST critical for:", options:["All domestic retail customers with low-value accounts","Any business customer regardless of transaction volume","High-risk customers — including PEPs, private banking clients, and correspondent banking relationships","Any customer conducting more than 10 transactions per month"], answer:2, explanation:"SOF verification is a key EDD measure for high-risk relationships where the risk of ML is elevated. Understanding how funds were generated helps assess whether wealth is consistent with the customer's profile and business activities." },
  { id:6113, domain:4, domainName:D4, question:"The PRIMARY goal of AML investigations from a law enforcement perspective is:", options:["Maximizing the number of SARs filed by financial institutions","Identifying, prosecuting, and convicting money launderers while seizing and forfeiting criminal proceeds","Imposing civil penalties on financial institutions with weak AML programs","Deterring money laundering by increasing CTR reporting thresholds"], answer:1, explanation:"The criminal justice goal of AML investigations is to prosecute offenders, remove the incentive for crime (asset forfeiture), disrupt criminal organizations, and deter future criminal activity — not simply increasing reporting volume." },
  { id:6114, domain:4, domainName:D4, question:"If a financial institution has reason to believe a customer is involved in terrorism financing, it should:", options:["First contact the customer to understand their transactions","Immediately file a SAR and check OFAC lists without alerting the customer","Report directly to the FBI before filing a SAR","Contact FinCEN directly instead of filing a SAR"], answer:1, explanation:"For suspected TF, institutions should file a SAR immediately upon developing a reasonable basis for suspicion, screen OFAC lists, and take appropriate account action — all without tipping off the customer. In urgent situations, law enforcement may be contacted directly while a SAR is simultaneously prepared." },
  { id:6115, domain:4, domainName:D4, question:"The Corporate Transparency Act (enacted as part of AMLA 2020) directed FinCEN to:", options:["Require all financial institutions to conduct annual external AML audits","Create a national beneficial ownership registry for U.S. companies","Impose mandatory penalties for late SAR filings","Expand CTR reporting to all electronic funds transfers"], answer:1, explanation:"The CTA created FinCEN's national beneficial ownership registry — requiring most U.S. corporations, LLCs, and similar entities to report their beneficial owners to FinCEN, addressing the opacity of shell company ownership that has long facilitated ML." },
  { id:6116, domain:4, domainName:D4, question:"A 'deferred prosecution agreement' (DPA) between a financial institution and DOJ typically requires:", options:["The institution to plead guilty to all charges","The institution to cease operations pending investigation","The institution to pay penalties, implement compliance improvements, and cooperate with the investigation — in exchange for DOJ agreeing to defer prosecution for a specified period","The institution's executives to face personal criminal indictments"], answer:2, explanation:"DPAs are a common resolution tool in corporate AML enforcement — they impose real consequences (financial penalties, mandated reforms, independent monitors) while avoiding the potentially destabilizing effect of a criminal conviction on a large financial institution." },
  { id:6117, domain:4, domainName:D4, question:"FATF evaluates countries' AML/CFT compliance through:", options:["The UN Office on Drugs and Crime","The Basel Committee on Banking Supervision","FATF and its associated FATF-Style Regional Bodies (FSRBs) mutual evaluation processes","The International Monetary Fund"], answer:2, explanation:"FATF and its 9 FATF-Style Regional Bodies (FSRBs like MONEYVAL, APG, GAFILAT) conduct mutual evaluations — peer reviews of countries' technical compliance with FATF Recommendations and effectiveness of their AML/CFT systems." },
  { id:6118, domain:4, domainName:D4, question:"The Wolfsberg Group principles are BEST described as:", options:["Mandatory international AML standards adopted by the G20","Voluntary AML guidance developed by a group of major global private financial institutions","FATF Recommendations adapted for private sector use","UN conventions on money laundering"], answer:1, explanation:"The Wolfsberg Group — 13 major global banks — develops voluntary anti-financial crime standards and guidance on correspondent banking, PEPs, monitoring, and other AML topics. While voluntary, Wolfsberg principles reflect industry best practice and are widely referenced by regulators." },
  { id:6119, domain:4, domainName:D4, question:"When responding to a law enforcement production order for BSA records, a financial institution should:", options:["Delay until legal counsel reviews everything for attorney-client privilege","Include a SAR if not already filed on the subject","Comply with the order by producing responsive records within the timeframe while consulting legal counsel","Notify the customer subject of the production order"], answer:2, explanation:"Complying with lawful legal process is a legal obligation. The institution should produce records as required, consult with legal counsel on scope and privilege questions, and ensure the response is complete and timely — without informing the customer (which could obstruct the investigation)." },
  { id:6120, domain:4, domainName:D4, question:"KYC documentation PRIMARILY helps law enforcement because:", options:["KYC is a sales tool to help bankers understand customer needs","KYC documentation provides a paper trail of customer identity and expected behavior enabling investigators to trace assets and build prosecution cases","KYC is primarily a data privacy regulation","KYC requirements apply only to high-risk customers"], answer:1, explanation:"Strong KYC records are an essential investigative resource — they establish who the customer is, their business, their expected transaction profile, and their source of wealth. When combined with SAR narratives and transaction records, they enable investigators to trace ML schemes and build criminal cases." },
];

// ═══════════════════════════════════════════════════════════════════════════
// EXAM 2  (IDs 6121–6240)
// ═══════════════════════════════════════════════════════════════════════════
const exam2: ExamQuestion[] = [
  // ── Domain 1 (31 Qs) ──────────────────────────────────────────────────
  { id:6121, domain:1, domainName:D1, question:"'Mirror trading' as a money laundering typology involves:", options:["Buying and selling identical securities simultaneously on the same exchange","Buying securities in one currency then selling equivalent securities in another currency to transfer value across borders","Using identical shell companies in two jurisdictions to move funds","Replicating legitimate transactions to conceal criminal proceeds"], answer:1, explanation:"Mirror trades simultaneously buy securities in one currency and sell equivalent securities in another currency, effectively moving value across borders. A 2017 Deutsche Bank enforcement action involved $10 billion in Russian mirror trades used for capital flight and potential ML." },
  { id:6122, domain:1, domainName:D1, question:"Trade-based money laundering (TBML) is particularly difficult to detect because:", options:["Trade transactions are entirely exempt from AML regulations","Banks do not process international trade payments","The complexity and volume of global trade make it difficult to verify the accuracy of trade documents and prices","TBML always involves amounts below the CTR threshold"], answer:2, explanation:"Global trade generates millions of invoices and shipping documents annually. Without trade expertise or inter-agency cooperation, financial institutions cannot routinely verify whether prices, quantities, or goods descriptions on trade finance documents are accurate." },
  { id:6123, domain:1, domainName:D1, question:"The 'layering' stage is MOST effectively disrupted by:", options:["Strict cash deposit limits at account opening","Enhanced customer identification requirements","Robust transaction monitoring detecting unusual patterns across accounts and jurisdictions","Mandatory customer interviews before all wire transfers"], answer:2, explanation:"Layering typically occurs through financial transactions — wires, currency conversions, securities trades. Transaction monitoring that identifies these patterns across multiple accounts and systems, combined with cross-border information sharing, is the most effective countermeasure." },
  { id:6124, domain:1, domainName:D1, question:"'Carousel fraud' in the context of money laundering involves:", options:["Casino chips exchanged for cash multiple times","Goods repeatedly imported and exported through multiple jurisdictions to claim fraudulent VAT refunds while layering illicit funds","Rotating illicit funds through multiple nominee accounts","Using amusement parks and entertainment venues to launder cash"], answer:1, explanation:"Carousel fraud (also called VAT carousel fraud) exploits VAT/GST systems by creating circular supply chains — goods move between jurisdictions with fraudulent VAT refund claims, layering illicit funds through seemingly legitimate trade while also generating fraudulent tax refunds." },
  { id:6125, domain:1, domainName:D1, question:"Which financial product is LEAST vulnerable to money laundering misuse?", options:["Anonymous prepaid cards with high reload limits","Bearer shares of offshore corporations","Insured certificates of deposit at a regulated domestic bank","Single-premium life insurance policies"], answer:2, explanation:"Federally insured CDs are subject to full CIP/CDD requirements, cannot be transferred anonymously, and generate clear records. In contrast, anonymous prepaid cards, bearer shares, and single-premium insurance policies have historically presented significant ML vulnerabilities." },
  { id:6126, domain:1, domainName:D1, question:"Real estate investment trusts (REITs) can be misused in ML schemes because:", options:["REITs are exempt from securities regulations","REITs can obscure beneficial ownership of property while integrating large sums through real estate","REIT transactions are invisible to regulators","REITs are not required to file SARs"], answer:1, explanation:"REITs aggregate multiple investors' capital into pooled real estate investments, which can make tracing the source of specific funds difficult. Complex REIT structures can obscure the identity of beneficial owners and integrate large amounts of illicit capital into legitimate real estate portfolios." },
  { id:6127, domain:1, domainName:D1, question:"An anonymous prepaid debit card with no customer identification is an AML red flag because:", options:["Prepaid cards are regulated by the FDIC and cannot legally be anonymous","Anonymous cards allow financial transactions without establishing identity, facilitating ML/TF","Prepaid cards cannot be used for wire transfers","Anonymous cards are legal only when purchased with cash"], answer:1, explanation:"Anonymous prepaid cards are a recognized ML/TF vehicle because they allow value to be stored and transferred without the card holder being identified — bypassing CIP requirements. FinCEN's prepaid card rules have specifically addressed this vulnerability." },
  { id:6128, domain:1, domainName:D1, question:"'Flipping' real estate as a money laundering technique involves:", options:["Purchasing a single property for cash","Quickly buying, renovating, and reselling properties to move funds through multiple transactions and obscure the original source","Using a real estate agent's client account to make deposits","Mortgaging a property to generate cash"], answer:1, explanation:"Flipping involves rapid purchase-renovation-resale cycles, potentially at manipulated prices, allowing illicit funds to be integrated through each transaction with capital gains appearing to explain accumulated wealth. Cash spent on renovations can also absorb illicit currency." },
  { id:6129, domain:1, domainName:D1, question:"'Cuckoo smurfing' is a ML technique where:", options:["Multiple individuals make cash deposits below the CTR threshold","An overseas criminal's funds are deposited into an innocent third party's account without that person's knowledge","Multiple financial institutions are used to structure large transactions","Criminal proceeds are placed into pension fund accounts"], answer:1, explanation:"In cuckoo smurfing, a money broker deposits overseas criminal proceeds into the account of an innocent person expecting a legitimate overseas payment (e.g., a family remittance). The innocent account holder receives the expected funds while criminal funds are effectively 'cleaned' in the process." },
  { id:6130, domain:1, domainName:D1, question:"The use of cryptocurrency 'tumblers' or 'mixers' is BEST classified as which ML stage?", options:["Placement, as it introduces funds into a new financial channel","Layering, as it obscures the transaction trail through a mixing process","Integration, as it results in seemingly legitimate cryptocurrency","Structuring, as it divides cryptocurrency into smaller amounts"], answer:1, explanation:"Cryptocurrency mixing is a layering technique — it takes funds already in the crypto ecosystem (already placed) and runs them through a mixing service to break the blockchain transaction trail, creating distance between the funds and their criminal origin." },
  { id:6131, domain:1, domainName:D1, question:"Which sector presents the HIGHEST ML risk associated with bulk cash handling?", options:["Online payment processors","Casinos and gaming establishments","Insurance companies","Investment banks"], answer:1, explanation:"Casinos are among the highest-risk DNFBPs for ML — they handle enormous volumes of cash, allow the conversion of illicit cash to chips and back to 'winnings' checks, create documented gambling proceeds, and are historically associated with organized crime." },
  { id:6132, domain:1, domainName:D1, question:"Complicit financial institution employees in ML schemes MOST commonly:", options:["Transport physical cash on behalf of criminal organizations","Facilitate transactions by ignoring red flags, overriding compliance controls, or actively assisting with structuring","Establish entirely new financial institutions for criminal use","Conduct independent audits of institution AML programs"], answer:1, explanation:"Insider facilitation is a serious ML vulnerability. Complicit employees may ignore or suppress suspicious activity alerts, approve transactions that should be blocked, help structure transactions, or accept bribes in exchange for ML facilitation — from inside the financial system's defenses." },
  { id:6133, domain:1, domainName:D1, question:"FATF Recommendation 24 requires countries to ensure:", options:["All financial institutions conduct annual ML risk assessments","Information on the beneficial ownership of legal persons (companies) is adequate, accurate, and available to authorities","FIUs receive and analyze all STRs within 24 hours","Criminal penalties for ML are harmonized across all FATF members"], answer:1, explanation:"Recommendation 24 specifically addresses the transparency of legal persons — countries must prevent the misuse of companies for ML and ensure that authorities can access timely and accurate beneficial ownership information." },
  { id:6134, domain:1, domainName:D1, question:"The 'layering' stage of money laundering typically does NOT include:", options:["Wire transfers between multiple accounts in different countries","Conversion of cash into monetary instruments","Direct deposit of illicit cash into a bank account","Purchase of high-value assets for subsequent resale"], answer:2, explanation:"The direct deposit of illicit cash into a bank account describes the 'placement' stage. Layering involves transactions AFTER the funds have entered the financial system — moving them through accounts, converting them, and otherwise obscuring their origin." },
  { id:6135, domain:1, domainName:D1, question:"The primary distinction between 'money laundering' and 'fraud' is:", options:["ML involves only drug proceeds while fraud involves any criminal proceeds","ML occurs after a predicate crime and conceals criminal proceeds; fraud uses deception to directly obtain money or property","Fraud is always a predicate offense for ML, while ML is always a separate crime","There is no meaningful distinction between them"], answer:1, explanation:"Fraud is the predicate crime — the act of deception that generates the illicit proceeds. Money laundering is what happens to those proceeds afterward — the process of concealing their origin to make them appear legitimate. They are distinct (though often related) offenses." },
  { id:6136, domain:1, domainName:D1, question:"'Payable-through accounts' offered by U.S. banks to foreign banks create AML risk because:", options:["They allow foreign customers to access U.S. banking services without being subject to U.S. CIP requirements","They bypass all wire transfer reporting requirements","They are exclusively used for ML rather than legitimate purposes","They are prohibited under the USA PATRIOT Act"], answer:0, explanation:"Payable-through accounts allow the foreign bank's customers to conduct transactions directly against the U.S. bank account — without those underlying customers being known to the U.S. bank. This creates a significant AML vulnerability addressed by Section 312's EDD requirements." },
  { id:6137, domain:1, domainName:D1, question:"A 'loan-back' scheme in money laundering involves:", options:["Using legitimate bank loans to purchase criminal assets","A criminal depositing illicit funds in a foreign bank, then borrowing against those deposits from a domestic bank, creating a seemingly legitimate loan","A bank knowingly lending to money launderers in exchange for a fee","Using fake loan applications to move criminal funds"], answer:1, explanation:"In a loan-back scheme, the criminal is technically 'borrowing' their own money back through a legitimate lending institution, creating a loan that appears on paper as a legitimate source of funds. The 'loan' may never be repaid, since it is collateralized by the criminal's own deposits." },
  { id:6138, domain:1, domainName:D1, question:"Terrorism financing organizations can source funds through:", options:["Exclusively drug trafficking proceeds","Charitable organizations, self-financing by operatives, and state sponsorship, among other sources","Exclusively amounts over $1 million","Never through formal banking systems"], answer:1, explanation:"TF sources are diverse: charitable solicitation (legitimate or fraudulent NPOs), legitimate business income, crime proceeds, self-funding, and state sponsorship. This diversity makes TF detection challenging — the funds may be clean, and amounts can be very small." },
  { id:6139, domain:1, domainName:D1, question:"'Nested correspondent banking' refers to:", options:["A bank holding correspondent accounts at another bank that in turn holds accounts at a major international bank","Two domestic banks sharing a single correspondent account","A bank providing correspondent services exclusively to domestic institutions","An offshore bank using a third party to access correspondent banking services"], answer:0, explanation:"Nested relationships create multiple layers of opacity: the major correspondent bank may not know the identity of the nested (third-tier) bank's customers, who are effectively accessing the global financial system with significant anonymity." },
  { id:6140, domain:1, domainName:D1, question:"The FATF '40 Recommendations' primarily serve to:", options:["Mandate criminal penalties for ML in all member countries","Provide an internationally agreed framework of measures for effective AML/CFT systems","Specify the exact form and content of STR filings in each member country","Require member countries to adopt identical domestic AML legislation"], answer:1, explanation:"The 40 Recommendations are standards, not mandates — they set out what measures countries should have in place, but allow flexibility in implementation to account for different legal systems and domestic contexts." },
  { id:6141, domain:1, domainName:D1, question:"Purchasing cryptocurrency at an ATM with illicit cash MOST likely represents which ML stage?", options:["Layering","Placement","Integration","Structuring"], answer:1, explanation:"Using cash to buy cryptocurrency (whether at an ATM or exchange) is a placement technique — converting physical illicit currency into a digital form that can then be moved more easily through the financial system or crypto ecosystem." },
  { id:6142, domain:1, domainName:D1, question:"Which of the following is NOT a typical red flag for trade-based money laundering?", options:["Payment in advance from an unrelated third party","Significant discrepancies between invoice description and actual shipment","Prices significantly above or below market value","Payment terms matching standard industry practice for the specific trade sector"], answer:3, explanation:"Standard industry-consistent payment terms suggest a legitimate commercial transaction. TBML red flags include unusual payment terms, third-party payments, price discrepancies, unusual routes, and goods descriptions inconsistent with the parties' business profiles." },
  { id:6143, domain:1, domainName:D1, question:"'Reverse money laundering' most commonly refers to:", options:["Converting legitimate funds into criminal proceeds for use in crime","Using legally obtained funds for criminal purposes such as terrorism financing","Moving criminal proceeds from foreign to domestic accounts","Converting traced criminal funds back to cash"], answer:1, explanation:"Reverse ML describes the process of taking clean, legitimate money and using it for criminal purposes — the opposite of traditional ML. Terrorism financing often involves this: legitimate funds (donations, business income) are used to finance violent acts." },
  { id:6144, domain:1, domainName:D1, question:"The MOST effective governmental approach to combating TBML is:", options:["Requiring banks to verify all international trade invoices before processing","Enhanced coordination between financial intelligence, customs, and law enforcement using a joint approach","Imposing higher fees on international trade payments","Prohibiting all-cash international trade payments"], answer:1, explanation:"TBML requires a multi-agency response: FIUs provide financial intelligence, customs authorities examine trade documents and goods, and law enforcement investigates suspected criminal enterprises. No single agency has the full picture needed to effectively detect and prosecute TBML." },
  { id:6145, domain:1, domainName:D1, question:"The FATF 'grey list' designation typically results in:", options:["Automatic application of sanctions by FATF member countries","Prohibition from participating in international banking","Increased scrutiny and monitoring, pressuring the country to address identified AML/CFT deficiencies","Automatic expulsion from the United Nations"], answer:2, explanation:"Grey-listed countries commit to implementing a time-bound action plan addressing identified deficiencies, with regular FATF reporting and monitoring. The reputational and financial pressure (higher correspondent banking costs, restricted access to capital markets) incentivizes reform." },
  { id:6146, domain:1, domainName:D1, question:"For domestic PEPs (as opposed to foreign PEPs), AML regulations typically require:", options:["The same mandatory EDD applied to foreign PEPs","A risk-based determination of whether EDD is warranted, based on the specific role and risk level","No enhanced scrutiny, as domestic PEPs are not covered by AML regulations","Automatic account closure upon identification as a PEP"], answer:1, explanation:"Most AML frameworks distinguish between domestic and foreign PEPs — domestic PEPs may require EDD, but the mandatory EDD requirements in FATF Recommendation 12 specifically apply to foreign PEPs. For domestic PEPs, risk-based judgment is typically applied." },
  { id:6147, domain:1, domainName:D1, question:"A financial institution should treat a close associate of a PEP as:", options:["A standard retail customer with no enhanced scrutiny","Presenting elevated risk similar to the PEP themselves, warranting consideration of EDD","Only requiring enhanced scrutiny if they share the same surname","Not subject to AML considerations since they are not the PEP themselves"], answer:1, explanation:"FATF Recommendation 12 extends PEP-related AML requirements to family members and close associates of PEPs, recognizing that corrupt PEPs often use family members and associates as nominees to hold and move illicit funds." },
  { id:6148, domain:1, domainName:D1, question:"'Professional money laundering networks' (PLMNs) are BEST characterized by:", options:["Operating exclusively within a single country","Providing ML services to a single criminal organization at a fixed price","Offering ML services to multiple criminal clients with global reach, financial sophistication, and connections to legitimate businesses","Specializing only in physical cash transport"], answer:2, explanation:"PLMNs are specialized criminal enterprises that offer ML as a service — managing the entire laundering process on behalf of multiple criminal organizations (drug traffickers, fraudsters, cybercriminals) for a fee, typically 15-25% of the amount laundered." },
  { id:6149, domain:1, domainName:D1, question:"The primary ML risk with high-value dealers in luxury goods, art, and precious stones is:", options:["They file CTRs for every cash transaction","Large cash purchases convert illicit currency into portable, high-value assets with minimal scrutiny","High-value dealers are subject to identical AML regulations as banks","Art and luxury goods are easily identifiable and difficult to resell"], answer:1, explanation:"Cash purchases of high-value, portable assets — art, jewelry, luxury watches, gems — allow rapid conversion of bulk illicit cash into assets that can be resold internationally, retain value, and are notoriously difficult to value and trace." },
  { id:6150, domain:1, domainName:D1, question:"Virtual asset peer-to-peer (P2P) transactions pose AML challenges because:", options:["P2P transactions are always completely anonymous","P2P transfers may bypass regulated VASPs subject to AML/CFT obligations, reducing monitoring effectiveness","P2P transactions automatically trigger SAR filing","P2P platforms are regulated in all jurisdictions"], answer:1, explanation:"P2P transactions — moving crypto directly between wallets without using a regulated exchange — bypass the KYC and transaction monitoring measures that VASPs are required to implement. This creates a regulatory gap that criminals exploit for layering and transfer of value." },
  { id:6151, domain:1, domainName:D1, question:"Under FATF Recommendation 16 (the 'Travel Rule' for virtual assets), VASPs are required to:", options:["Block all transactions involving jurisdictions on the FATF grey list","Obtain, hold, and transmit originator and beneficiary information for virtual asset transfers above applicable thresholds","Report all virtual asset transactions to the national FIU","Prohibit transactions with unhosted (private) wallets"], answer:1, explanation:"FATF's Travel Rule for virtual assets (Recommendation 16) requires VASPs to collect and transmit originator and beneficiary information (similar to the wire transfer travel rule) for crypto transfers above threshold, enabling law enforcement to trace virtual asset flows." },
  // ── Domain 2 (28 Qs) ──────────────────────────────────────────────────
  { id:6152, domain:2, domainName:D2, question:"'Risk appetite' in AML compliance refers to:", options:["The level of criminal proceeds a bank is willing to process before filing a SAR","The types and amounts of ML/TF risk the board and senior management determine the institution is willing to accept","The compliance department's tolerance for regulatory examination findings","The minimum AML resource level required by regulation"], answer:1, explanation:"Risk appetite statements — approved by the board — set the outer boundaries of what ML/TF risk is acceptable in pursuit of the institution's business objectives. They guide the AML program's calibration and resource allocation decisions." },
  { id:6153, domain:2, domainName:D2, question:"A financial institution's AML program must be approved by:", options:["The BSA/AML compliance officer","The institution's external auditors","The board of directors or equivalent governing body","The primary federal regulator"], answer:2, explanation:"Board approval of the AML program reflects governance accountability — the board is ultimately responsible for the institution's compliance culture and risk management. Board-level oversight ensures the AML program receives sufficient resources and authority." },
  { id:6154, domain:2, domainName:D2, question:"Under the CIP rule, acceptable documentary verification for individuals includes all of the following EXCEPT:", options:["An unexpired government-issued photo ID","A valid passport","A state-issued driver's license","A utility bill alone (without other supporting identification)"], answer:3, explanation:"A utility bill may serve as proof of address but is NOT an acceptable identity verification document under CIP. Acceptable documents include unexpired government-issued photo ID with name and photo — driver's licenses, passports, military IDs, and similar official documents." },
  { id:6155, domain:2, domainName:D2, question:"A financial institution may use 'non-documentary' verification methods under CIP when:", options:["A customer refuses to provide identification documents","The institution cannot review an original document or the customer cannot produce required identification","The customer's name matches the OFAC SDN List","The requested transaction is below the CTR threshold"], answer:1, explanation:"Non-documentary verification (e.g., database checks, credit checks, contacting references, obtaining a financial statement) is permitted when customers cannot produce standard documents — such as foreign nationals without standard U.S. ID, or customers not physically present." },
  { id:6156, domain:2, domainName:D2, question:"A bank onboarding an LLC with two members must collect beneficial ownership for:", options:["Members owning more than 50% only","All members owning 25% or more AND one individual with significant managerial control","All members owning 25% or more only, if the LLC has fewer than 5 members","No members, if the LLC is registered in the institution's home state"], answer:1, explanation:"The FinCEN CDD rule requires two types of beneficial ownership information for legal entity customers: (1) ownership — all natural persons with 25%+ ownership; and (2) control — one individual with significant managerial control (e.g., CEO, managing member)." },
  { id:6157, domain:2, domainName:D2, question:"A risk-based approach allows financial institutions to:", options:["Decide whether to comply with BSA filing requirements based on risk appetite","Apply simplified due diligence to all domestic customers regardless of individual risk","Apply enhanced measures to higher-risk situations while applying simplified measures to demonstrably lower-risk ones","Substitute judgment for regulatory requirements"], answer:2, explanation:"The RBA enables proportionate compliance — concentrating resources on highest-risk customers and transactions, while applying appropriately lighter-touch measures to demonstrably low-risk situations. The key is that the approach is documented, justified, and risk-informed." },
  { id:6158, domain:2, domainName:D2, question:"For a federally insured bank, a SAR is required when the institution knows, suspects, or has reason to suspect that a transaction involves funds from illegal activity AND the aggregate amount is at least:", options:["$2,000","$5,000","$10,000","$25,000"], answer:1, explanation:"The SAR filing threshold for banks is $5,000 (31 CFR 1020.320). There is no minimum dollar threshold for insider-related suspicious activity — SARs must be filed for any amount if the suspicious activity involves bank insiders." },
  { id:6159, domain:2, domainName:D2, question:"A SAR must typically be filed within:", options:["15 calendar days after initial detection","30 calendar days after initial detection, extendable to 60 days if no suspect can be identified","48 hours for terrorism-related and 30 days for all other activity","5 business days for terrorism financing and 60 days for all other activity"], answer:1, explanation:"The standard SAR filing deadline is 30 calendar days from the date of initial detection of the suspicious transaction or activity. If the subject cannot be identified, the deadline extends to 60 calendar days from initial detection." },
  { id:6160, domain:2, domainName:D2, question:"Which of the following is NOT included in a standard CTR filing?", options:["The customer's name and taxpayer identification number","The amount and type of transaction","The customer's annual income","The date of the transaction"], answer:2, explanation:"CTRs (FinCEN Form 112) require: identifying information about persons conducting/benefiting from the transaction, the financial institution, the transaction amount, type (cash in/out), and date. Income information is not part of CTR filing." },
  { id:6161, domain:2, domainName:D2, question:"A SAR narrative should NOT include:", options:["A detailed description of suspicious transactions and their patterns","The factual basis for the institution's suspicion","References to prior SARs filed on the same subject","A definitive legal conclusion that the activity constitutes money laundering"], answer:3, explanation:"SAR filers should NOT make legal determinations (e.g., 'customer is engaged in money laundering'). The narrative describes observed facts and patterns that suggest the suspicious activity. Legal conclusions are for law enforcement and prosecutors, not SAR filers." },
  { id:6162, domain:2, domainName:D2, question:"An AML 'lookback' review involves:", options:["A review of prior examination findings to track remediation progress","A retrospective review of historical transactions to identify previously missed suspicious activity that may require SAR filing","Ongoing real-time monitoring of high-risk customer accounts","A customer's review of their own transaction history"], answer:1, explanation:"A lookback review examines historical transaction data — either voluntarily or in response to regulatory direction — to identify suspicious activity that the institution's existing program failed to detect. SAR filings are made as appropriate for newly identified suspicious transactions." },
  { id:6163, domain:2, domainName:D2, question:"Which type of entity is explicitly EXEMPT from the FinCEN CDD rule's beneficial ownership requirements?", options:["Foreign corporations operating in the United States","Domestic publicly traded companies subject to SEC reporting disclosure requirements","Limited partnerships with fewer than 10 partners","Nonprofit organizations registered with the IRS"], answer:1, explanation:"The CDD rule exempts: publicly traded U.S. companies (and their U.S. subsidiaries) subject to SEC reporting, banks and credit unions, governmental authorities, and other highly regulated entities. These entities already provide transparency through existing regulatory frameworks." },
  { id:6164, domain:2, domainName:D2, question:"A 'customer risk rating' system in AML compliance assigns customers a risk level based on:", options:["Credit score and annual income level","Factors such as customer type, geography, products used, and transaction patterns guiding the level of due diligence applied","The number of SARs filed on the customer","The customer's relationship tenure with the institution"], answer:1, explanation:"Customer risk ratings are a core component of an effective AML program — they enable the institution to calibrate CDD, monitoring, and resource allocation to each customer's specific risk profile, consistent with the risk-based approach." },
  { id:6165, domain:2, domainName:D2, question:"'Ongoing monitoring' in AML compliance includes:", options:["Annual re-verification of all customer identity documents","Periodic review of customer relationships and transaction monitoring to detect activity inconsistent with the customer's profile","Filing a SAR every time a customer account is reviewed","Contacting all customers annually to confirm their transaction history"], answer:1, explanation:"Ongoing monitoring is a continuous process: transaction monitoring systems review activity in real time, and periodic CDD reviews (more frequent for higher-risk customers) ensure the institution's understanding of each customer remains current and accurate." },
  { id:6166, domain:2, domainName:D2, question:"The MOST important AML concern when onboarding a nonprofit organization customer is:", options:["Whether the organization files tax returns","Whether the organization's purpose, funders, beneficiaries, and geographic focus present TF risk","Whether the organization has more than 50 employees","Whether accounts will be used exclusively for domestic transactions"], answer:1, explanation:"Nonprofit organizations can be vulnerable to TF exploitation — either knowingly or unknowingly used to raise and transfer funds to terrorist organizations. Key risk factors: geographic focus (conflict regions), beneficiary populations, fundraising methods, and cross-border money movements." },
  { id:6167, domain:2, domainName:D2, question:"'Independent testing' of an AML program should be:", options:["Conducted by the BSA officer to maintain program continuity","Performed exclusively by external consultants for independence","Conducted by qualified staff independent of the AML function, with results reported to senior management and the board","Limited to reviewing SAR filing accuracy"], answer:2, explanation:"Independence means the tester cannot report to or be supervised by the AML compliance function. Independence may be achieved with internal audit or external consultants. Scope should be risk-based and cover all material aspects of the AML program, not just SAR filings." },
  { id:6168, domain:2, domainName:D2, question:"EDD for private banking customers typically includes:", options:["Requiring additional signed disclosures only","Identifying source of wealth and funds, understanding the customer's business activities, and conducting more frequent account reviews","Limiting the customer to domestic wire transfers only","Requiring a minimum account balance of $1 million"], answer:1, explanation:"Private banking EDD is comprehensive: source of wealth (how did they accumulate their fortune), source of funds (how are these specific deposits funded), expected account activity, ongoing review of transactions, and senior management approval for opening the relationship." },
  { id:6169, domain:2, domainName:D2, question:"When an institution's transaction monitoring system fails to flag a known ML pattern for 12 months, the BEST response is:", options:["Immediately replace the entire TMS","File SARs for all transactions during the 12-month period","Conduct a lookback of historical transactions, file SARs as appropriate, and remediate the system deficiency","Report the failure directly to FinCEN"], answer:2, explanation:"The response should be proportionate and systematic: (1) identify the gap through root cause analysis; (2) conduct a risk-based lookback to identify any transactions that should have been flagged; (3) file SARs for newly identified suspicious activity; and (4) fix the monitoring system." },
  { id:6170, domain:2, domainName:D2, question:"A well-designed AML transaction monitoring system is characterized by:", options:["Flagging 100% of transactions for human review to ensure nothing is missed","Risk-based scenarios calibrated to the institution's specific products, customers, and risk profile for efficient suspicious activity identification","Automatically filing SARs without human review to ensure timeliness","Focusing exclusively on cash transactions and wire transfers"], answer:1, explanation:"Effective TMS design balances sensitivity (catching suspicious activity) and specificity (minimizing false positives). Scenarios should be tailored to the institution's actual customer base, products, and known typologies — not generic off-the-shelf rules applied without customization." },
  { id:6171, domain:2, domainName:D2, question:"USA PATRIOT Act Section 312 EDD for private banking accounts requires U.S. institutions to:", options:["Conduct EDD on all domestic private banking customers","Establish EDD measures for private banking accounts held by non-U.S. persons, including identifying nominal and beneficial owners","File SARs on all non-U.S. private banking customers","Limit private banking relationships to U.S. persons only"], answer:1, explanation:"Section 312 specifically targets the risks of private banking with non-U.S. persons, requiring institutions to identify the account holders and beneficial owners, identify the source of funds, and review the account for suspicious activity." },
  { id:6172, domain:2, domainName:D2, question:"An AML program that is 'paper compliant' but not effectively implemented is MOST likely to be identified during:", options:["A review of filed SARs and CTRs only","Independent testing or regulatory examination including transaction testing and interviews","A review of the institution's written policies and procedures","An OFAC screening audit"], answer:1, explanation:"A 'paper compliant' program — one with policies on paper but inadequate implementation — often passes document reviews. It is transaction testing (verifying policies are actually followed), alert investigation quality reviews, and employee interviews that expose the implementation gaps." },
  { id:6173, domain:2, domainName:D2, question:"FinCEN's 314(a) program allows law enforcement to:", options:["Query financial institutions to search records for accounts or transactions of suspected ML/TF subjects","Require financial institutions to report all transactions over $10,000","Access any customer's account records without a subpoena","Mandate SAR filing by any institution that has a matching account"], answer:0, explanation:"The 314(a) process: law enforcement submits a request to FinCEN; FinCEN distributes to covered financial institutions; institutions search records (12 months for transactions, indefinitely for accounts) and report any matches to FinCEN within 14 days, maintaining confidentiality." },
  { id:6174, domain:2, domainName:D2, question:"A 'credit card factoring' ML scheme involves:", options:["A merchant processing credit card transactions at inflated values to create legitimate-appearing revenue from illicit sources","Using stolen credit cards to make cash advances","A bank issuing credit to entities controlled by money launderers","Factoring receivables through a shell company"], answer:0, explanation:"Credit card factoring (merchant capture fraud) involves a complicit or shell merchant processing transactions for goods/services that don't exist, converting illicit cash into apparent business revenue. The merchant account essentially provides a legitimacy veneer for cash deposits." },
  { id:6175, domain:2, domainName:D2, question:"When a TMS alert is investigated and determined to be non-suspicious, the analyst should:", options:["File a precautionary SAR to document the review","Document the investigation, facts considered, and rationale for closing the alert without SAR filing","Escalate to law enforcement as a precaution","Restrict the customer's account pending further review"], answer:1, explanation:"Documentation of the investigation and the rationale for not filing a SAR is essential. This creates an audit trail showing the institution took the alert seriously, conducted a good-faith review, and reached a reasoned judgment — protecting the institution in any subsequent regulatory examination." },
  { id:6176, domain:2, domainName:D2, question:"An institution operating in multiple jurisdictions must:", options:["Comply only with the AML laws of the jurisdiction where it is incorporated","Comply with the AML laws of each jurisdiction where it operates, applying the more stringent standard when laws conflict","Apply only FATF Recommendations, not domestic law","Apply U.S. BSA requirements everywhere regardless of operating jurisdiction"], answer:1, explanation:"Multi-jurisdictional financial institutions must comply with the AML laws of each jurisdiction where they operate. When home country and host country requirements differ, institutions typically apply the stricter standard and maintain policies that meet all applicable legal requirements." },
  { id:6177, domain:2, domainName:D2, question:"The FFIEC BSA/AML Examination Manual is:", options:["A legally binding set of regulations for financial institutions","Guidance used by federal bank examiners to assess financial institution AML program effectiveness","A voluntary industry standard developed by trade associations","A periodic update to the Bank Secrecy Act"], answer:1, explanation:"The FFIEC BSA/AML Examination Manual provides examiners with a framework for evaluating AML programs. While not law, it reflects regulatory expectations and is treated as near-binding in practice — institutions use it to benchmark their own programs." },
  { id:6178, domain:2, domainName:D2, question:"A risk-based approach to correspondent banking due diligence means:", options:["Applying identical EDD to all foreign correspondent banks","Applying EDD to all correspondent relationships regardless of risk level","Calibrating due diligence to the ML/TF risk of the foreign respondent bank, based on jurisdiction, AML controls, and customer base","Refusing correspondent banking services to any bank in a high-risk country"], answer:2, explanation:"Not all correspondent relationships present the same risk. A large regulated bank in a low-risk jurisdiction with strong AML controls requires less intensive due diligence than a smaller bank in a high-risk jurisdiction with limited regulatory oversight." },
  { id:6179, domain:2, domainName:D2, question:"A 'KYC refresh' refers to:", options:["Collecting new CIP information at account opening","Periodic review and update of customer due diligence information to ensure it remains current and accurate","A customer's request to update their account contact information","Refiling SARs when customer information changes"], answer:1, explanation:"CDD information must be kept current — customers' circumstances, business activities, ownership, and risk profiles change over time. Periodic KYC refreshes (more frequent for higher-risk customers) ensure the institution's understanding of the customer remains accurate and fit for monitoring." },
  // ── Domain 3 (30 Qs) ──────────────────────────────────────────────────
  { id:6180, domain:3, domainName:D3, question:"The SAR filing standard of 'reasonable suspicion' is LOWER than 'probable cause' because:", options:["Financial institutions are not law enforcement and are not expected to make definitive legal determinations","SAR thresholds are set by state law, which varies by jurisdiction","Financial institutions have more information than law enforcement","SAR filing is voluntary, so a lower threshold encourages more filing"], answer:0, explanation:"Financial institutions are required to report when they have a reasonable basis for suspicion — they lack investigative authority, subpoena power, or law enforcement resources. Setting the bar at probable cause would effectively prevent most SAR filings and eliminate their value as intelligence leads." },
  { id:6181, domain:3, domainName:D3, question:"The SAR tipping-off prohibition correctly states that:", options:["A bank may never discuss a SAR with any third party","A bank cannot disclose to the subject or related parties that a SAR has been filed, requested, or is being considered","A bank may not discuss SARs even with its board of directors","A bank cannot share SAR information with its external auditors"], answer:1, explanation:"The prohibition specifically prevents disclosure to persons who are or might be the subject of the SAR. Internal discussions with the board, senior management, compliance staff, and sharing with regulators and external auditors are all permissible and in many cases required." },
  { id:6182, domain:3, domainName:D3, question:"'Structuring analysis' in an AML investigation focuses on:", options:["Reviewing a customer's corporate structure for beneficial ownership","Identifying transaction patterns designed to evade the CTR threshold through deliberate amounts and timing","Analyzing the structure of the institution's compliance program","Investigating the organizational structure of suspected criminal enterprises"], answer:1, explanation:"Structuring analysis identifies cash deposit/withdrawal patterns that consistently fall just below $10,000, occur with suspicious frequency, or demonstrate other characteristics suggesting intentional CTR avoidance — particularly when the amounts and timing seem economically irrational absent the CTR motivation." },
  { id:6183, domain:3, domainName:D3, question:"When an institution identifies suspicious activity and decides to file a SAR, it should:", options:["Immediately close the customer's account","Continue monitoring and may maintain the relationship while filing, unless doing so creates unacceptable risk","Notify the customer their account is under review","Wait 60 days to confirm the activity continues before filing"], answer:1, explanation:"Filing a SAR does not require closing the account — in fact, maintaining the relationship may enable ongoing monitoring that generates additional intelligence for law enforcement. Account closure decisions should be made on risk grounds, not simply because a SAR is being filed." },
  { id:6184, domain:3, domainName:D3, question:"FinCEN's SAR database is PRIMARILY used by:", options:["Financial institutions to check if a customer has prior SARs","Regulatory examiners to determine if an institution's filing volume is appropriate","Law enforcement and intelligence agencies to identify investigative leads and link financial patterns to criminal activity","The public to access information about financial crimes"], answer:2, explanation:"FinCEN's BSA database is a law enforcement tool — investigators use SAR data to develop leads, corroborate existing investigations, identify criminal networks, and trace financial flows. The database contains millions of SAR filings spanning decades of financial crime reporting." },
  { id:6185, domain:3, domainName:D3, question:"A 'geographic information system' (GIS) approach to AML can help by:", options:["Identifying physical locations of cash deposit machines","Mapping transaction locations to identify geographic clusters consistent with known ML typologies","Verifying customer addresses against government databases","Plotting locations of regulatory-compliant financial institutions"], answer:1, explanation:"GIS mapping can reveal spatial patterns in financial crime — for example, identifying clusters of structuring activity near specific cash-intensive businesses, or geographic networks of money transmitters used in TF cases — adding a spatial dimension to financial investigation." },
  { id:6186, domain:3, domainName:D3, question:"When a departing relationship manager's exit interview occurs, it should include:", options:["A review of OFAC compliance policies","Questions about any customer relationships or compliance concerns the RM may be aware of","A final review of the RM's transaction monitoring training record","Signing an NDA about pending SAR filings"], answer:1, explanation:"Departing employees — especially those with customer relationships — may have valuable compliance information: concerns about customer activities, pressure from managers to ignore red flags, or knowledge of suspicious relationships they observed. Exit interviews capture this information before the employee departs." },
  { id:6187, domain:3, domainName:D3, question:"'FINTEL' (financial intelligence) refers to:", options:["A financial technology company in the fintech space","Intelligence derived from financial information used to detect, prevent, and investigate ML/TF","FinCEN's proprietary intelligence sharing system","A FATF working group on financial intelligence"], answer:1, explanation:"Financial intelligence — derived from SARs, CTRs, wire transfer records, open-source information, and other financial data — is a distinct intelligence discipline. FIUs specialize in producing FINTEL by analyzing financial flows to identify criminal networks and illicit activity." },
  { id:6188, domain:3, domainName:D3, question:"When assessing whether an alert should result in a SAR, an analyst should consider:", options:["Only the current transaction that triggered the alert","Only transactions that exceed $10,000","The customer's full transaction history, profile, account type, and any known explanations for the activity","Whether a law enforcement request has been received regarding the subject"], answer:2, explanation:"Effective SAR decision-making requires a holistic view — the current transaction in the context of the customer's historical activity, their profile and business, any prior SARs filed, external information (adverse media, 314(a) requests), and any explanations provided by the customer." },
  { id:6189, domain:3, domainName:D3, question:"The Egmont Group FIU information sharing process is governed by:", options:["FATF Recommendation 40 and the Egmont Group's Principles for Information Exchange","USA PATRIOT Act Section 314(b)","UN Security Council Resolution 1373","The Basel Accords"], answer:0, explanation:"FATF Recommendation 40 addresses international cooperation including FIU information exchange. The Egmont Group's Principles for Information Exchange provide the operational framework — covering how FIUs should request, receive, share, and protect exchanged financial intelligence." },
  { id:6190, domain:3, domainName:D3, question:"A customer provides an explanation for unusual activity. The analyst should:", options:["Accept the explanation and close the alert without further review","File a SAR immediately, as customer explanations are unreliable","Document the explanation and assess whether it is plausible, consistent with the customer's profile, and supported by any corroborating evidence","Require the customer to provide documentation before any further review occurs"], answer:2, explanation:"Customer-provided explanations must be evaluated critically — they are one input, not a conclusive answer. The analyst must assess plausibility (does it make sense?), consistency (does it fit the profile?), and verifiability (can it be corroborated?) before making a filing decision." },
  { id:6191, domain:3, domainName:D3, question:"'Network visualization' tools in AML investigations are used to:", options:["Monitor network security in financial institutions","Graphically display relationships between accounts, entities, and transactions to reveal patterns not easily identified in tabular data","Visualize geographic distribution of customers","Create diagrams of an institution's compliance program structure"], answer:1, explanation:"Visualization tools (e.g., link analysis software like Palantir, i2 Analyst Notebook) transform complex transaction data into graphic representations of networks, making criminal relationships and fund flows immediately visible to investigators." },
  { id:6192, domain:3, domainName:D3, question:"'Proactive intelligence gathering' in AML involves:", options:["Waiting for law enforcement to identify suspicious customers before conducting due diligence","Using open-source intelligence, adverse media, and public records to supplement transaction monitoring and CDD","Filing SARs before suspicious activity is confirmed as a proactive measure","Sharing SAR information with competitors to identify shared subjects"], answer:1, explanation:"Proactive OSINT (open-source intelligence) — news databases, court records, corporate filings, social media — supplements automated monitoring by providing context about customers that the transaction data alone cannot provide, enabling more informed suspicious activity assessments." },
  { id:6193, domain:3, domainName:D3, question:"When a financial institution receives a law enforcement informal inquiry about a customer, it should:", options:["Immediately disclose all account information to the requesting officer","Refuse to provide any information without formal legal process","Consult with legal counsel and refer law enforcement to the formal legal process for obtaining records","File a SAR on the customer before responding"], answer:2, explanation:"Privacy laws (e.g., the Right to Financial Privacy Act) restrict financial institutions from voluntarily disclosing customer information without proper legal process. The institution's legal counsel should advise on what, if anything, can be shared informally versus what requires a formal subpoena or court order." },
  { id:6194, domain:3, domainName:D3, question:"When building a case to support a SAR filing, analysts should:", options:["Rely exclusively on automated monitoring alerts","Document all relevant information: transaction data, customer profile, prior SARs, adverse media, and any explanations received","Consult with law enforcement before making the filing decision","Limit documentation to the specific transaction that triggered the alert"], answer:1, explanation:"Comprehensive documentation serves multiple purposes: it supports the SAR narrative quality, creates an audit trail of the analytical process, demonstrates good faith compliance, and preserves information that may be needed months later when law enforcement follows up." },
  { id:6195, domain:3, domainName:D3, question:"When an institution suspects a customer may be engaged in terrorism financing, it should:", options:["First contact the customer to understand their transactions","File a SAR with FinCEN and potentially contact the FBI if urgency warrants, without alerting the customer","Report directly to the FBI before filing a SAR","Contact FinCEN directly instead of filing a SAR"], answer:1, explanation:"For suspected TF: SAR filing is required (and should be prompt). In urgent cases — e.g., imminent risk of violence — the institution may also proactively contact law enforcement (typically the FBI's Financial Intelligence Unit) while simultaneously preparing the SAR, but without alerting the customer." },
  { id:6196, domain:3, domainName:D3, question:"Cryptocurrency layering often involves:", options:["Converting fiat currency to cryptocurrency at an exchange","Converting cryptocurrency to goods and services in the real economy","Passing cryptocurrency through multiple wallets, exchanges, and mixing services to obscure the original transaction trail","Converting cryptocurrency gains to taxable income"], answer:2, explanation:"Crypto layering exploits the pseudonymous nature of blockchain — multiple hops between wallets, exchanges in different jurisdictions, mixing services, cross-chain swaps, and conversion between different cryptocurrencies can effectively obscure the trail between the illicit origin and the ultimate beneficiary." },
  { id:6197, domain:3, domainName:D3, question:"An institution's AML program has 'gaps' identified during examination. The FIRST priority should be:", options:["Replacing the BSA officer","Immediately filing SARs on all high-risk customers","Developing and implementing a remediation plan with clear timelines, ownership, and progress tracking","Contracting with an external audit firm for an independent review"], answer:2, explanation:"Structured remediation — a documented plan with specific action items, responsible parties, deadlines, and progress metrics — is what regulators expect following examination findings. The plan should address root causes, not just symptoms, and should be approved at the appropriate governance level." },
  { id:6198, domain:3, domainName:D3, question:"Which describes a 'true positive' in the context of AML transaction monitoring?", options:["A transaction flagged that is determined non-suspicious upon review","A transaction flagged that represents genuine suspicious activity requiring SAR consideration","A suspicious transaction missed by the monitoring system","A transaction flagged in error due to a system malfunction"], answer:1, explanation:"A true positive is what the monitoring system is designed to produce — an alert that, upon investigation, turns out to be genuinely suspicious. The ratio of true positives to total alerts (vs. false positives) is a key effectiveness metric for TMS quality." },
  { id:6199, domain:3, domainName:D3, question:"A bank employee observing that a customer's cash deposits follow a pattern of $8,000 every Monday for three consecutive weeks should:", options:["Assume this is a normal weekly business cash-up pattern","File a CTR for each deposit since they may relate to the same week's business","Escalate the observation to compliance for review of potential structuring","Ask the customer to increase deposit amounts to avoid the appearance of structuring"], answer:2, explanation:"Deposits of consistent amounts below $10,000 on a regular schedule warrant scrutiny for structuring. The regularity and consistent below-threshold amount (especially if the customer's business doesn't clearly explain the pattern) are red flags requiring compliance review." },
  { id:6200, domain:3, domainName:D3, question:"Transaction monitoring 'scenarios' or 'rules' should be:", options:["Set by the primary federal regulator and uniformly applied to all institutions","Purchased from a vendor and implemented without modification","Designed based on the institution's specific risk profile, products, customer base, and known ML typologies, then regularly tested and tuned","Applied only to cash transactions and wire transfers"], answer:2, explanation:"Effective TMS scenarios require customization — off-the-shelf rules applied without calibration to an institution's specific risk profile generate excessive false positives and miss institution-specific suspicious patterns. Regular tuning based on investigation outcomes is essential." },
  { id:6201, domain:3, domainName:D3, question:"The 'net worth' method and 'expenditure' method are used by financial investigators to:", options:["Calculate the appropriate amount of a regulatory fine","Indirectly prove criminal income by demonstrating that expenditures and assets exceed known legitimate income","Determine the market value of seized assets in forfeiture proceedings","Calculate the total amount laundered for sentencing"], answer:1, explanation:"Indirect methods of proof — net worth analysis (assets increased more than income explains) and expenditure analysis (spending exceeds documented income) — allow investigators to establish criminal income without direct evidence of the predicate crime, supporting ML prosecution and asset forfeiture." },
  { id:6202, domain:3, domainName:D3, question:"A bank employee who reports AML concerns internally and then to a regulator in good faith is protected by:", options:["The BSA safe harbor for SAR filers","Whistleblower protection laws, including protections strengthened by AMLA 2020","Attorney-client privilege","Fifth Amendment protections against self-incrimination"], answer:1, explanation:"AMLA 2020 significantly strengthened BSA whistleblower protections — prohibiting retaliation and establishing a financial award program for original information leading to successful enforcement actions. The Dodd-Frank Act also provides whistleblower protections for securities-related disclosures." },
  { id:6203, domain:3, domainName:D3, question:"The 'Bank Secrecy Act Advisory Group' (BSAAG) serves to:", options:["Enforce BSA regulations on behalf of FinCEN","Represent private sector institutions in challenging BSA regulations","Facilitate dialogue between the private sector and government on BSA/AML implementation issues","Conduct independent audits of financial institution AML programs"], answer:2, explanation:"BSAAG is a public-private forum that brings together government agencies (FinCEN, law enforcement, regulators) and private sector representatives to share information, discuss operational issues, and develop practical approaches to BSA/AML implementation." },
  { id:6204, domain:3, domainName:D3, question:"A financial institution's AML lookback review should be:", options:["Limited to accounts that were the subject of previous SARs","Risk-based — focusing on higher-risk accounts and transaction types most likely to have exhibited undetected suspicious activity","Applied uniformly to all accounts regardless of risk","Limited to the 12 months prior to the regulatory examination"], answer:1, explanation:"Lookback scope should be determined by risk — where are the gaps most likely to have resulted in missed suspicious activity? High-risk customer segments, high-risk transaction types, and periods when known system deficiencies existed should receive the most intensive review." },
  { id:6205, domain:3, domainName:D3, question:"'Financial crime risk appetite statements' in a financial institution are BEST found in:", options:["SAR filing forms submitted to FinCEN","Board-approved AML policies defining the types and levels of risk the institution is willing to accept","FATF mutual evaluation reports","FinCEN SAR narratives"], answer:1, explanation:"Risk appetite statements are governance-level documents — approved by the board, incorporated into AML policies, and used to guide management decisions about which customer types, products, and geographies the institution will or will not serve." },
  { id:6206, domain:3, domainName:D3, question:"The primary difference between 'transaction monitoring' and 'surveillance monitoring' in financial institutions is:", options:["Transaction monitoring covers cash only; surveillance monitoring covers wire transfers","Transaction monitoring focuses on individual transaction attributes; surveillance monitoring analyzes behavior patterns across time and accounts to identify anomalies","Surveillance monitoring is required by law; transaction monitoring is optional","There is no meaningful difference between the terms"], answer:1, explanation:"While the terms are sometimes used interchangeably, transaction monitoring typically refers to rule-based flagging of individual transactions, while surveillance monitoring (or behavioral analytics) analyzes patterns of activity across time, accounts, and counterparties — enabling detection of more sophisticated ML schemes." },
  { id:6207, domain:3, domainName:D3, question:"Which of the following describes a 'false negative' in AML transaction monitoring?", options:["A transaction flagged as suspicious that turns out to be legitimate","A suspicious transaction that the monitoring system failed to detect","An alert generated by a system error","A transaction that was correctly identified as suspicious"], answer:1, explanation:"False negatives — missed suspicious transactions — are the most dangerous failure mode in AML monitoring. They may result from monitoring rules that are too narrowly calibrated, scenarios that don't cover emerging typologies, or data quality issues that prevent the system from seeing complete transaction patterns." },
  { id:6208, domain:3, domainName:D3, question:"FinCEN's '314(a)' process is initiated by:", options:["Financial institutions filing voluntary information requests","Law enforcement agencies through FinCEN","Regulatory examiners during AML examinations","FinCEN's own analytical team identifying suspicious patterns in SAR data"], answer:1, explanation:"Only authorized federal law enforcement agencies with open ML or TF investigations can submit 314(a) requests through FinCEN. FinCEN then disseminates the request to covered financial institutions, which must search their records and report any matches within 14 days." },
  { id:6209, domain:3, domainName:D3, question:"When an institution's AML monitoring generates an alert for a customer who is a legitimate high-volume cash business (e.g., a supermarket), the analyst should:", options:["File a SAR because cash activity is inherently suspicious","Immediately close the customer's account","Review the customer's profile, expected activity, and historical pattern to determine whether current activity is consistent with the business type before making a filing decision","Exempt the customer from CTR filing to reduce alert volume"], answer:2, explanation:"Context is everything — a supermarket's large cash deposits may be entirely consistent with its business model. The analyst must assess whether the current activity is consistent with the customer's established profile and expected behavior before concluding whether it is truly suspicious." },
  // ── Domain 4 (31 Qs) ──────────────────────────────────────────────────
  { id:6210, domain:4, domainName:D4, question:"A U.S. financial institution receiving a grand jury subpoena for customer records should:", options:["Notify the customer immediately and wait 30 days before producing records","Immediately produce records and file a SAR on the customer","Comply with the subpoena, generally without notifying the customer, and consult legal counsel","Challenge the subpoena in court before producing any records"], answer:2, explanation:"Grand jury subpoenas are compulsory — institutions must comply. Notifying the customer could constitute obstruction of justice. Legal counsel should review the scope and ensure the response is complete, timely, and appropriately documented." },
  { id:6211, domain:4, domainName:D4, question:"The Wolfsberg Principles on correspondent banking state that financial institutions should:", options:["Refuse correspondent relationships with banks in non-FATF member countries","Apply a risk-based approach to correspondent due diligence, assessing the respondent bank's ownership, AML controls, and customer base","Obtain prior FinCEN approval before establishing correspondent relationships","Conduct physical branch inspections of all foreign correspondent partners annually"], answer:1, explanation:"The Wolfsberg Correspondent Banking Principles (updated 2014) provide detailed guidance on the risk-based approach to correspondent banking due diligence — a key reference for global institutions establishing and maintaining correspondent relationships." },
  { id:6212, domain:4, domainName:D4, question:"FinCEN's 314(a) program is PRIMARILY designed to:", options:["Allow institutions to share information about suspicious activity with each other","Require institutions to search records for accounts or transactions of ML/TF suspects identified by law enforcement","Provide institutions with law enforcement intelligence about known money launderers","Mandate information sharing between FIUs of different countries"], answer:1, explanation:"314(a) is a targeted law enforcement tool — it enables investigators to quickly determine whether specific suspects (by name, address, or SSN) have financial accounts or transactions at any U.S. financial institution, generating leads across the entire financial system." },
  { id:6213, domain:4, domainName:D4, question:"Under 31 U.S.C. § 5324, which element is required for a criminal structuring conviction?", options:["Knowledge that structuring is a federal crime","Intent to evade the CTR reporting requirement, regardless of whether the underlying funds are from criminal activity","The total amount structured must exceed $50,000","Structuring must occur across multiple financial institutions"], answer:1, explanation:"Post-Ratzlaf Congressional amendments clarified that structuring convictions require proof of intent to evade reporting — but not necessarily knowledge that structuring itself is illegal. The underlying funds' legality is irrelevant; it is the evasive intent that is criminal." },
  { id:6214, domain:4, domainName:D4, question:"The primary federal statute criminalizing money laundering in the United States is:", options:["The Bank Secrecy Act (31 U.S.C. § 5311 et seq.)","18 U.S.C. §§ 1956 and 1957","The USA PATRIOT Act (Public Law 107-56)","The Racketeer Influenced and Corrupt Organizations Act (RICO)"], answer:1, explanation:"18 U.S.C. § 1956 (money laundering) criminalizes financial transactions with proceeds of specified unlawful activity with the intent to promote the predicate offense, evade taxes, or conceal the source. § 1957 separately prohibits transactions over $10,000 in criminally derived property." },
  { id:6215, domain:4, domainName:D4, question:"A deferred prosecution agreement (DPA) between a financial institution and the DOJ typically involves:", options:["A guilty plea and immediate criminal sentencing","The institution accepting reforms and penalties while DOJ agrees not to prosecute during a monitored compliance period","The institution being placed under conservatorship","Automatic revocation of the institution's banking charter"], answer:1, explanation:"DPAs allow DOJ to impose real consequences — financial penalties, mandated compliance improvements, independent monitors — while preserving the institution's ability to operate. This approach reflects DOJ's balancing of accountability with potential systemic harm from institutional criminal conviction." },
  { id:6216, domain:4, domainName:D4, question:"Under the AMLA 2020, FinCEN's new beneficial ownership registry is:", options:["A public registry accessible to any interested party","A non-public database accessible to authorized law enforcement, financial institutions with customer consent, and treasury officials","Required only for corporations with revenues over $1 million","Limited to foreign-owned domestic entities"], answer:1, explanation:"The CTA registry is non-public. Access is provided to: law enforcement for investigations; financial institutions with customer consent for CDD purposes; Treasury for national security purposes; and foreign governments through appropriate legal channels." },
  { id:6217, domain:4, domainName:D4, question:"A 'law enforcement model' FIU differs from an 'administrative model' FIU in that:", options:["Law enforcement FIUs operate under judicial authority; administrative FIUs report to finance ministries","Law enforcement FIUs directly conduct financial investigations and may have arrest authority; administrative FIUs receive and analyze information without law enforcement powers","Administrative FIUs have broader investigative powers than law enforcement FIUs","Law enforcement FIUs are exclusively found in common law countries"], answer:1, explanation:"FIU models vary globally: administrative FIUs (e.g., FinCEN) receive, analyze, and disseminate; law enforcement FIUs may directly investigate and prosecute; judicial FIUs operate within the judicial system; and hybrid models combine features. Each model has advantages and trade-offs." },
  { id:6218, domain:4, domainName:D4, question:"Which of the following would NOT typically constitute a 'predicate offense' for money laundering under FATF standards?", options:["Drug trafficking","Human trafficking","Corruption and bribery","A civil breach of contract"], answer:3, explanation:"FATF's 21 categories of predicate offenses are serious crimes — drug trafficking, human trafficking, terrorism, corruption, fraud, and others. Civil wrongs (breach of contract, tortious conduct) are not predicate offenses for ML even if they result in large monetary judgments." },
  { id:6219, domain:4, domainName:D4, question:"The Palermo Convention (UN Convention against Transnational Organized Crime) requires countries to:", options:["Criminalize all 21 FATF predicate offenses","Criminalize money laundering, including self-laundering (laundering one's own crime proceeds)","Establish FIUs connected to the Egmont Group","Implement all 40 FATF Recommendations"], answer:1, explanation:"The Palermo Convention (2000) requires signatory countries to criminalize ML in connection with organized crime, including self-laundering. It is a foundational international legal instrument for combating transnational organized crime and ML." },
  { id:6220, domain:4, domainName:D4, question:"'Asset freezing' as a counter-terrorism measure is authorized in the U.S. primarily through:", options:["The BSA and FinCEN regulations","Executive Orders under IEEPA and UN Security Council Resolutions implemented through OFAC","Section 311 of the USA PATRIOT Act","Criminal forfeiture proceedings under 18 U.S.C. § 981"], answer:1, explanation:"The International Emergency Economic Powers Act (IEEPA) authorizes the President to impose economic sanctions, and OFAC implements these through SDN listings and blocking orders. UN Security Council Resolutions (under Chapter VII) are domestically implemented through OFAC regulations." },
  { id:6221, domain:4, domainName:D4, question:"A 'suspicious transaction report' (STR) filed in a FATF member country serves the same purpose as:", options:["A CTR in the United States","A SAR in the United States","An OFAC blocking report","A FinCEN 314(a) response"], answer:1, explanation:"Most FATF member countries use the term STR (Suspicious Transaction Report) for financial institution reports of suspected ML/TF — functionally equivalent to the U.S. SAR. Both are filed with the national FIU and serve as the primary mechanism for financial intelligence collection." },
  { id:6222, domain:4, domainName:D4, question:"'Follow the money' investigative techniques aim to:", options:["Identify every financial institution used by the suspect","Calculate the suspect's tax liability","Trace the flow of funds from the predicate offense through the financial system to identify co-conspirators, recover assets, and build a criminal case","Determine whether a SAR has been filed on the suspect"], answer:2, explanation:"Following the money is a core law enforcement approach to financial crime — it reveals the full criminal network, identifies all parties involved, locates criminal assets available for forfeiture, and generates evidence of the ML conspiracy beyond the original predicate offense." },
  { id:6223, domain:4, domainName:D4, question:"'Civil money penalties' (CMPs) for BSA violations are:", options:["Always lower than criminal penalties for the same violation","Imposed exclusively by the Department of Justice","Assessed by FinCEN or banking regulators for failure to comply with BSA requirements","Limited to a maximum of $1,000 per violation"], answer:2, explanation:"CMPs are administrative penalties — FinCEN (for program deficiencies) and federal banking regulators (OCC, Fed, FDIC, NCUA) can assess CMPs for BSA violations. They are civil in nature (not requiring criminal intent) but can be substantial — millions or even billions of dollars for systemic failures." },
  { id:6224, domain:4, domainName:D4, question:"The USA PATRIOT Act was enacted in response to:", options:["The 1993 World Trade Center bombing","The September 11, 2001 terrorist attacks","A series of bank failures related to money laundering in the 1990s","The collapse of BCCI, used for money laundering and terrorism financing"], answer:1, explanation:"The Uniting and Strengthening America by Providing Appropriate Tools Required to Intercept and Obstruct Terrorism Act (USA PATRIOT Act) was passed just 45 days after September 11, 2001, significantly expanding AML requirements and law enforcement authorities to combat terrorism financing." },
  { id:6225, domain:4, domainName:D4, question:"Section 311 'primary money laundering concern' designations and special measures are administered by:", options:["The Egmont Group","OFAC through its sanctions lists","FinCEN and the Secretary of the Treasury","The Basel Committee on Banking Supervision"], answer:2, explanation:"Section 311 (31 U.S.C. § 5318A) gives the Secretary of the Treasury — in practice, through FinCEN — authority to designate entities or jurisdictions as primary ML concerns and impose special measures through rulemaking. These measures can effectively cut off designated entities from the U.S. financial system." },
  { id:6226, domain:4, domainName:D4, question:"Proactive voluntary information sharing between financial institutions and law enforcement is:", options:["Prohibited by privacy laws","Permitted in limited circumstances, including through 314(b) sharing and voluntary tips to law enforcement","Required whenever an institution suspects ML","Only permitted through formal MLAT processes"], answer:1, explanation:"Privacy laws generally restrict voluntary disclosure of customer information, but certain exceptions exist — including for national security (NSL), law enforcement exigent circumstances, and voluntary cooperation. Section 314(b) provides safe harbor for inter-institutional sharing. SAR filing is the primary mechanism for providing information to law enforcement." },
  { id:6227, domain:4, domainName:D4, question:"The FATF mutual evaluation process is designed to:", options:["Impose fines on countries with weak AML/CFT regimes","Assess the effectiveness and technical compliance of a country's AML/CFT system based on internationally agreed standards","Rank countries' AML/CFT regimes for investment purposes","Establish minimum mandatory ML penalties in member countries"], answer:1, explanation:"Mutual evaluations are peer reviews — conducted by FATF or its regional bodies — that assess both technical compliance (40 Recommendations) and effectiveness (11 Immediate Outcomes). Results inform FATF's grey/black listing decisions and provide countries with detailed improvement recommendations." },
  { id:6228, domain:4, domainName:D4, question:"USA PATRIOT Act Section 326 requires financial institutions to implement:", options:["EDD for all foreign correspondent banks","Customer Identification Programs (CIPs) to verify the identity of account holders","Ongoing monitoring of all PEP accounts","TMS capable of detecting structuring"], answer:1, explanation:"Section 326 gave Treasury and bank regulators authority to prescribe regulations requiring financial institutions to establish CIPs. The resulting CIP regulations set minimum identification and verification requirements for new account holders." },
  { id:6229, domain:4, domainName:D4, question:"Following an AML enforcement action, regulators will typically require:", options:["Immediate suspension of all business operations","Dismissal of the institution's board of directors","A remediation plan with enhanced AML controls, potential lookback, civil money penalties, and possibly an independent monitor","Merger with a compliant financial institution"], answer:2, explanation:"Enforcement action remedies are tailored to the deficiencies identified. Common elements: civil money penalties (reflecting severity of violations); mandated remediation with specific timelines; enhanced governance and oversight; a lookback review; and in severe cases, an independent compliance monitor." },
  { id:6230, domain:4, domainName:D4, question:"A financial institution that has established a correspondent relationship with a shell bank:", options:["Must file a SAR on the shell bank","Is in violation of the USA PATRIOT Act, which prohibits such relationships","Must apply EDD but may maintain the relationship with proper controls","Must report the relationship to OFAC"], answer:1, explanation:"Section 313 of the USA PATRIOT Act explicitly prohibits U.S. financial institutions from establishing or maintaining correspondent accounts with foreign shell banks (those with no physical presence in any jurisdiction and not regulated by any authority)." },
  { id:6231, domain:4, domainName:D4, question:"Financial institutions are required to maintain CTR records for:", options:["3 years","5 years","7 years","10 years"], answer:1, explanation:"The BSA requires financial institutions to retain CTRs for 5 years from the date of the report. This retention period ensures records are available for law enforcement investigations, regulatory examinations, and litigation that may occur years after the original transaction." },
  { id:6232, domain:4, domainName:D4, question:"'Proliferation financing' specifically refers to financing:", options:["Drug trafficking organizations operating across multiple countries","The spread of money laundering schemes through multiple institutions","The development, acquisition, manufacture, possession, or transfer of weapons of mass destruction","The growth of informal value transfer networks globally"], answer:2, explanation:"PF is financing related to WMD — nuclear, biological, chemical, or radiological weapons and their delivery systems. FATF Recommendation 7 and UN Security Council resolutions require countries to implement targeted financial sanctions to prevent PF." },
  { id:6233, domain:4, domainName:D4, question:"FinCEN 'Financial Trend Analysis' reports are PRIMARILY used to:", options:["Rank financial institutions by SAR filing volume","Identify emerging ML/TF trends and typologies from analysis of BSA data","Set industry benchmarks for AML compliance spending","Monitor compliance of foreign financial institutions with FATF standards"], answer:1, explanation:"FinCEN's analytical reports — including Financial Trend Analysis products, Advisories, and SAR Stats reports — share intelligence derived from BSA filings with financial institutions and law enforcement, helping both groups stay current on emerging ML/TF typologies and patterns." },
  { id:6234, domain:4, domainName:D4, question:"PRIMARY responsibility for investigating money laundering in the United States lies with:", options:["The FBI","The DEA","The IRS Criminal Investigation division","Multiple agencies including FBI, IRS-CI, HSI, and DEA, depending on the predicate offense"], answer:3, explanation:"ML investigation jurisdiction in the U.S. is shared: FBI (white collar crime, organized crime), IRS-CI (tax-related ML, currency violations), DEA (drug-related ML), HSI (human trafficking, customs-related), and Secret Service (financial fraud). The predicate offense determines primary jurisdiction." },
  { id:6235, domain:4, domainName:D4, question:"Under international standards, a country's FIU should be operationally independent from:", options:["The country's financial sector","Political and operational interference that could compromise its analytical independence and credibility","Other government agencies","The FATF evaluation process"], answer:1, explanation:"FIU operational independence is critical — political interference in STR/SAR analysis or intelligence dissemination could undermine the FIU's effectiveness and the integrity of the national AML/CFT system. FATF standards require FIUs to be protected from undue influence." },
  { id:6236, domain:4, domainName:D4, question:"A consent order for AML deficiencies typically requires:", options:["Criminal prosecution of compliance officers","Immediate institution closure","Implementation of specific remedial measures within defined timeframes with ongoing regulatory reporting","Automatic forfeiture of assets connected to AML deficiencies"], answer:2, explanation:"Consent orders are negotiated, not litigated — they specify exactly what the institution must do (and not do), when, and how. Regulators monitor compliance with the order, and failure to comply can result in additional enforcement action." },
  { id:6237, domain:4, domainName:D4, question:"Beneficial ownership information collected under the FinCEN CDD rule may be shared with:", options:["Any financial institution requesting it through 314(b)","Law enforcement, regulatory examiners, and FinCEN when lawfully requested","The public through FinCEN's public database","Credit reporting agencies for account management purposes"], answer:1, explanation:"CDD-collected beneficial ownership data is subject to confidentiality — it should not be freely shared. However, it must be made available to law enforcement through legal process, to regulators during examinations, and to FinCEN as requested." },
  { id:6238, domain:4, domainName:D4, question:"'AML culture' within a financial institution refers to:", options:["The institution's public reputation for AML compliance","The number of SARs filed annually relative to industry peers","The collective values, attitudes, and behaviors across the institution that shape how AML risks are understood, prioritized, and managed","The compliance department's professional culture within the institution"], answer:2, explanation:"A strong AML culture — sometimes called 'tone at the top' and 'culture throughout' — means AML is not just a compliance department obligation but a shared organizational responsibility. Senior leaders model the right behaviors, and all employees understand their role in the institution's AML defenses." },
  { id:6239, domain:4, domainName:D4, question:"Under the Corporate Transparency Act, 'reporting companies' are generally required to report beneficial ownership to FinCEN within:", options:["30 days of formation (for new companies after effective date) or by a specified deadline for existing companies","90 days for new companies and 5 years for existing companies","Only when the beneficial ownership changes","Annually, regardless of ownership changes"], answer:0, explanation:"The CTA requires newly formed companies (after the effective date of FinCEN's implementing rule) to file within 30 days of formation. Existing companies were given a one-year transition period. Updates must be filed within 30 days of any change in beneficial ownership or control." },
  { id:6240, domain:4, domainName:D4, question:"A Designated Non-Financial Business or Profession (DNFBP) is BEST described as:", options:["A business prohibited from providing financial services","A non-financial sector business (such as lawyers, accountants, real estate agents, and high-value dealers) subject to AML/CFT obligations due to ML/TF vulnerability","A business designated by FATF as a primary ML risk","Any business that handles cash transactions"], answer:1, explanation:"DNFBPs are non-bank businesses and professions that, because of the nature of their activities, can be exploited by money launderers and TF actors. FATF Recommendations 22 and 23 specify the AML/CFT obligations that countries must impose on DNFBPs." },
];

// ═══════════════════════════════════════════════════════════════════════════
// EXAM 3  (IDs 6241–6360)
// ═══════════════════════════════════════════════════════════════════════════
const exam3: ExamQuestion[] = [
  { id:6241, domain:1, domainName:D1, question:"Which UN Convention first used the term 'proceeds of crime' and required countries to criminalize ML beyond drug trafficking?", options:["Vienna Convention 1988","Palermo Convention 2000","Merida Convention 2003","Warsaw Convention 2005"], answer:1, explanation:"The Palermo Convention (2000) expanded the ML predicate offense beyond drugs to include all serious crimes, introduced the 'proceeds of crime' concept, and required countries to criminalize ML, corruption, and obstruction of justice." },
  { id:6242, domain:1, domainName:D1, question:"'Integration' as the final ML stage is BEST described as:", options:["Introducing cash into the financial system","Creating complex layers of transactions to obscure the audit trail","Reintroducing laundered funds into the legitimate economy in a form that appears clean","Converting cash to monetary instruments"], answer:2, explanation:"Integration is the final stage — the criminal now has apparently legitimate funds (from a property sale, business income, loan repayment, or investment returns) that can be freely used in the legitimate economy without obvious connection to the original crime." },
  { id:6243, domain:1, domainName:D1, question:"FATF Recommendation 1 requires countries to:", options:["Criminalize money laundering","Identify, assess, and understand their ML/TF risks and apply a risk-based approach","Establish a financial intelligence unit","Cooperate internationally on AML matters"], answer:1, explanation:"Recommendation 1 is the foundational recommendation — countries must assess their national ML/TF risks and base their AML/CFT measures on those risks. It establishes the risk-based approach as the foundation of the entire FATF framework." },
  { id:6244, domain:1, domainName:D1, question:"'Commingling' as a money laundering technique involves:", options:["Using multiple bank accounts to layer funds","Mixing illicit cash with legitimate business revenues so the criminal origin is obscured","Converting cash to cryptocurrency","Using multiple currencies to layer funds"], answer:1, explanation:"Commingling — blending criminal proceeds with legitimate business cash flows — is one of the oldest ML techniques. Cash-intensive businesses (restaurants, laundromats, parking lots) are frequently used because the volume of legitimate cash makes it difficult to identify the illicit component." },
  { id:6245, domain:1, domainName:D1, question:"Which of the following is a 'red flag' for potential money laundering in private banking?", options:["A customer who is a prominent local business owner with documented wealth","A customer declining to provide information about the source of large wire transfers received from multiple offshore jurisdictions","A customer maintaining multiple accounts at the same institution for business convenience","A customer with a long-standing relationship and consistent transaction history"], answer:1, explanation:"Unexplained large transfers from multiple offshore sources, especially combined with reluctance to disclose source of funds, is a major red flag in private banking. The high-value, lower-volume nature of private banking makes source of wealth verification particularly critical." },
  { id:6246, domain:1, domainName:D1, question:"Tax havens contribute to ML risk because:", options:["Tax havens are subject to no financial regulations whatsoever","They offer secrecy, low taxation, and weak AML oversight that make it easy to hide beneficial ownership and illicit funds","Tax havens automatically trigger FATF sanctions","All financial transactions through tax havens are presumed to be illegal"], answer:1, explanation:"Tax havens (offshore financial centers) typically offer: corporate secrecy laws; nominee director/shareholder arrangements; minimal reporting requirements; strong bank secrecy; and limited international information exchange — all features that facilitate the concealment of illicit wealth." },
  { id:6247, domain:1, domainName:D1, question:"A 'front company' used in ML schemes differs from a 'shell company' in that:", options:["Front companies have no legal existence; shell companies are legally incorporated","A front company has some real business activity to provide cover, while a shell company has no real operations","Shell companies are only used in illegal activities; front companies are always legitimate","There is no meaningful distinction between the two terms"], answer:1, explanation:"A front company actually operates — it has customers, employees, and business activity — but uses that legitimate business activity as cover to commingle and launder criminal proceeds. A shell company is purely a legal construct with no real business activity." },
  { id:6248, domain:1, domainName:D1, question:"The 'Achilles heel' of money laundering is BEST described as:", options:["Cryptocurrency transactions that create permanent records","The placement stage, where illicit cash is closest to its criminal origin and most vulnerable to detection","The integration stage, where funds re-enter the economy","The use of professional advisors who may file SARs"], answer:1, explanation:"Placement is considered the Achilles heel of ML because at this stage, the funds are physically closest to the crime, the criminal must interact with financial institutions directly with large amounts of cash, and cash transaction reporting requirements create the greatest detection risk." },
  { id:6249, domain:1, domainName:D1, question:"'Gatekeepers' in the AML context include all of the following EXCEPT:", options:["Lawyers","Accountants","Stock brokers (in their role as investment advisers)","Commercial bank tellers"], answer:3, explanation:"Gatekeepers are professionals who, by virtue of their professional roles, provide access to the financial system — lawyers, accountants, notaries, trust and company service providers, real estate agents. Bank tellers are employees of a financial institution, not an independent gatekeeper." },
  { id:6250, domain:1, domainName:D1, question:"'Cryptocurrency mining' in the context of ML is concerning because:", options:["Mining creates new cryptocurrency that has no transaction history and whose origin is inherently unclear, making it useful for introducing clean-seeming value","Mining requires identity verification that creates AML records","Cryptocurrency mining is exclusively controlled by sanctioned entities","Mining is always used for terrorist financing"], answer:0, explanation:"Mined cryptocurrency has no transaction history on the blockchain — it appears 'clean' from day one. This makes it attractive to money launderers who can mine using illicit proceeds (paying electricity bills with dirty money) and receive apparently clean cryptocurrency in return." },
  { id:6251, domain:1, domainName:D1, question:"The primary reason human trafficking proceeds are difficult to trace is:", options:["Human trafficking is not a predicate offense for money laundering","Proceeds are primarily generated and distributed in cash through multiple channels and exploited victims","Human traffickers exclusively use cryptocurrency","Human trafficking generates very small amounts that are below reporting thresholds"], answer:1, explanation:"Human trafficking (HT) is often cash-intensive, with proceeds distributed through multiple channels: individual traffickers, recruiters, corrupt officials. The proceeds are often deposited gradually through victim-controlled accounts, small businesses, or money service businesses, making tracing complex." },
  { id:6252, domain:1, domainName:D1, question:"Under FATF standards, 'terrorist financing' must be criminalized even when:", options:["The amounts are small and used for specific operational needs","The funds come from legitimate sources and are used for lawful purposes in the country of origin","There is no connection to an actual terrorist attack","All of the above circumstances"], answer:3, explanation:"FATF Recommendation 5 requires countries to criminalize TF regardless of: the amount; whether the funds are from legal or illegal sources; whether the financing is successful (no actual attack required); and whether funds are used for legitimate purposes in the financing country." },
  { id:6253, domain:1, domainName:D1, question:"A 'straw man' (or 'nominee') in a money laundering scheme serves to:", options:["Provide investment advice to criminals","Act as the apparent owner of assets or accounts to conceal the true beneficial owner's identity","Conduct financial transactions on behalf of a financial institution","Manage criminal organizations' day-to-day operations"], answer:1, explanation:"Nominees (straw men) lend their names and identities to accounts, property, and companies owned by criminals — creating a layer of separation between the beneficial owner (the criminal) and the visible owner (the nominee). They may be willing participants or coerced/deceived individuals." },
  { id:6254, domain:1, domainName:D1, question:"Which FATF Recommendation specifically addresses politically exposed persons?", options:["Recommendation 6","Recommendation 12","Recommendation 15","Recommendation 22"], answer:1, explanation:"Recommendation 12 addresses PEPs — requiring institutions to have risk-based systems to determine whether a customer is a PEP, obtain senior management approval for high-risk PEP relationships, establish source of wealth/funds, and conduct enhanced ongoing monitoring." },
  { id:6255, domain:1, domainName:D1, question:"The 'Wolfsberg AML Principles' for private banking address:", options:["Mandatory CTR filing thresholds for private banking transactions","The risk-based approach to KYC, client acceptance, and ongoing monitoring for private banking relationships","Automatic SAR filing requirements for offshore private banking clients","Mandatory beneficial ownership disclosure for all private banking clients"], answer:1, explanation:"The Wolfsberg Private Banking AML Principles (2012) provide voluntary guidance on managing ML/TF risk in private banking — covering client acceptance policies, source of wealth/funds verification, due diligence standards, and ongoing monitoring for this high-risk customer segment." },
  { id:6256, domain:1, domainName:D1, question:"Which feature of a free-trade zone (FTZ) creates the GREATEST ML/TBML risk?", options:["High transaction volumes","Reduced customs oversight and minimal record-keeping requirements for goods moving within the zone","Mandatory AML compliance similar to banks","All FTZ transactions are subject to FATF oversight"], answer:1, explanation:"FTZs typically operate with reduced customs controls, minimal AML requirements, limited supervision, and ease of re-invoicing — making them ideal for TBML, phantom shipments, and other trade-based laundering schemes that exploit gaps in trade document scrutiny." },
  { id:6257, domain:1, domainName:D1, question:"The primary ML risk associated with 'over-the-counter' (OTC) cryptocurrency trading desks is:", options:["OTC trades are always anonymous and exempt from AML regulations","OTC desks handle large cryptocurrency transactions directly between parties, potentially with limited KYC compared to regulated exchanges","OTC trading is exclusively used by institutional investors who are exempt from AML requirements","OTC cryptocurrency transactions automatically trigger SAR filing"], answer:1, explanation:"OTC crypto trading desks facilitate large block trades directly between buyers and sellers. Some operate with minimal KYC/AML controls, allowing criminals to convert large amounts of illicit cryptocurrency to fiat (or vice versa) with limited scrutiny." },
  { id:6258, domain:1, domainName:D1, question:"'Smishing' and 'vishing' in the context of ML refer to:", options:["Money laundering techniques specific to the fishing industry","Social engineering attacks (SMS-based phishing and voice phishing) used to recruit money mules or steal financial credentials","Methods of structuring cryptocurrency transactions","Types of trade-based money laundering schemes"], answer:1, explanation:"Smishing (SMS phishing) and vishing (voice call phishing) are social engineering techniques used by cybercriminals — often to recruit unwitting money mules, steal banking credentials, or defraud victims. Cybercrime proceeds are then laundered through the financial system." },
  { id:6259, domain:1, domainName:D1, question:"A customer conducting multiple cash exchanges for foreign currency just below the CTR threshold across several bank branches on the same day is MOST likely engaged in:", options:["Legitimate foreign travel preparation","Structuring — deliberately breaking up transactions to avoid triggering CTR filing","Legal foreign currency arbitrage","Standard currency exchange activity for an import/export business"], answer:1, explanation:"Multiple sub-threshold currency exchange transactions at multiple branches in a single day strongly suggests structuring — the customer is deliberately splitting transactions to stay below the $10,000 CTR threshold. This pattern is a well-known structuring red flag." },
  { id:6260, domain:1, domainName:D1, question:"'Misuse of legal persons' as an ML typology refers to:", options:["Criminals falsely claiming to be attorneys in financial transactions","Exploiting corporations, LLCs, trusts, and other legal entities to obscure beneficial ownership and channel illicit funds","Filing false incorporation documents with state authorities","Using legal entities to claim false tax deductions"], answer:1, explanation:"FATF Recommendation 24 specifically addresses this — legal persons (corporations, LLCs) are used to create layers of ownership that obscure who ultimately controls the assets. Chains of shell companies across multiple jurisdictions are a classic ML architecture." },
  { id:6261, domain:1, domainName:D1, question:"'Correspondent banking' in the context of AML is BEST defined as:", options:["A bank hiring external consultants to provide AML compliance services","A banking relationship where one bank (the correspondent) provides banking services to another bank (the respondent) in a different jurisdiction","A FATF mutual evaluation process for assessing national AML programs","A FinCEN program for sharing financial intelligence with international FIUs"], answer:1, explanation:"Correspondent banking allows banks to provide services in jurisdictions where they don't operate directly. The correspondent bank essentially acts as an agent for the respondent bank — processing payments, holding accounts, and providing other banking services." },
  { id:6262, domain:1, domainName:D1, question:"'Misuse of charities' as a TF typology typically involves:", options:["Charities investing in volatile assets","Using charitable organizations to solicit donations and transfer funds to terrorist organizations, either knowingly or through exploitation","Charities evading taxation on investment income","Using charitable status to avoid SAR filing requirements"], answer:1, explanation:"Charitable organizations present TF risk because: they raise funds from the public based on their stated legitimate mission; they may transfer funds internationally to conflict zones; they often receive little financial oversight; and their donors may not know how funds are ultimately used." },
  { id:6263, domain:1, domainName:D1, question:"The Basel AML Index primarily measures:", options:["A country's capital adequacy ratio for money laundering risk","The risk of money laundering and terrorism financing in countries, based on multiple data sources including FATF evaluations and governance indicators","The number of SARs filed by financial institutions in each country","Financial institutions' adherence to Basel Committee AML guidelines"], answer:1, explanation:"The Basel AML Index (published by the Basel Institute on Governance) is a composite risk score ranking countries by their vulnerability to ML/TF, drawing on 18+ indicators from FATF, Transparency International, World Bank, and other sources. It is widely used by financial institutions for correspondent banking and CDD risk assessment." },
  { id:6264, domain:1, domainName:D1, question:"The 'Egmont Group' requires member FIUs to:", options:["Adopt identical ML laws","Share financial intelligence with other member FIUs on a reciprocal basis following established protocols","Submit annual reports to FATF","Conduct joint law enforcement operations against money launderers"], answer:1, explanation:"Egmont Group membership commits FIUs to: secure information exchange with other member FIUs; protection of shared information; reciprocal assistance; and adherence to the Egmont Principles — enabling the trusted international network of financial intelligence exchange." },
  { id:6265, domain:1, domainName:D1, question:"Which ML typology involves using a third country as an intermediary to disguise the origin of funds?", options:["Placement through cash deposits","Round-tripping through an offshore jurisdiction","Direct wire transfers to the beneficial owner","Commingling with legitimate business revenues"], answer:1, explanation:"Round-tripping involves moving funds out of a country, through one or more intermediary jurisdictions, and back into the originating country — making the funds appear to be a legitimate foreign investment. It is commonly used to conceal domestic criminal proceeds or evade capital controls." },
  { id:6266, domain:1, domainName:D1, question:"The term 'Designated Persons' in OFAC sanctions programs refers to:", options:["U.S. government employees designated to enforce sanctions","Individuals and entities specifically listed by OFAC as subject to U.S. sanctions","Financial institutions designated as primary money laundering concerns under Section 311","Compliance officers designated as responsible for OFAC screening"], answer:1, explanation:"Designated persons are those specifically listed on OFAC's SDN List or other sanctions lists — their assets are blocked and U.S. persons are generally prohibited from transacting with them. The SDN List contains thousands of individuals, entities, vessels, and aircraft subject to U.S. sanctions." },
  { id:6267, domain:1, domainName:D1, question:"Which is the MOST common red flag for insurance-based money laundering?", options:["A customer purchasing a small term life insurance policy","A customer purchasing a large single-premium cash-value insurance policy, then cancelling it shortly after and requesting a refund check","A customer making regular monthly premium payments via automatic bank transfer","A customer naming a family member as beneficiary on a life insurance policy"], answer:1, explanation:"The single-premium, early-surrender scheme is classic insurance ML: the criminal pays a large premium in cash or from an obscure source, immediately surrenders the policy, and receives a check from the insurance company — creating the appearance that the refund is a legitimate insurance payment." },
  { id:6268, domain:1, domainName:D1, question:"'Self-laundering' refers to:", options:["Criminals using their own bank accounts to structure deposits","A person laundering the proceeds of crimes they themselves committed","Automated money laundering systems that operate without human involvement","A financial institution laundering its own funds"], answer:1, explanation:"Self-laundering — the same person commits both the predicate offense and the laundering — is a key issue for jurisdictions that require a predicate offense by someone OTHER than the launderer for ML prosecution. Most modern AML frameworks criminalize self-laundering." },
  { id:6269, domain:1, domainName:D1, question:"FATF's 'immediate outcomes' measure:", options:["The speed of enforcement actions following ML detection","Whether a country's AML/CFT system is actually achieving meaningful results in preventing and prosecuting ML/TF","The immediate financial impact of FATF grey-listing on a country","The number of STRs filed within 30 days of suspicious activity detection"], answer:1, explanation:"FATF's 11 Immediate Outcomes are the results that an effective AML/CFT system should achieve — covering risk understanding, policy coordination, financial intelligence, investigations, asset recovery, terrorism financing prevention, and proliferation financing prevention. They assess effectiveness, not just technical compliance." },
  { id:6270, domain:1, domainName:D1, question:"'Loan sharking' proceeds enter the financial system MOST commonly through:", options:["Direct wire transfers from borrowers to lenders","Cash deposits structured to avoid CTR thresholds, commingling with legitimate business income, or placement through check cashing services","Offshore bank accounts in tax havens","Insurance premium payments on behalf of victims"], answer:1, explanation:"Loan shark proceeds (high-interest cash payments from borrowers) are collected in cash and must be placed into the financial system. Common methods include structuring cash deposits, operating cash businesses that commingle the payments, or using MSBs." },
  { id:6271, domain:1, domainName:D1, question:"A 'concentration account' at a financial institution can create ML risk because:", options:["Concentration accounts automatically generate CTR filings","Multiple customer transactions are pooled, obscuring the link between individual customer transactions and their original source","Concentration accounts are only available to high-risk customers","Concentration accounts cannot be monitored for suspicious activity"], answer:1, explanation:"Concentration accounts (also called 'omnibus accounts') aggregate multiple customers' transactions — potentially obscuring the beneficial owners and creating a mixing mechanism within the institution itself. This requires specific internal controls to maintain transaction traceability." },
  // Domain 2 for exam3 (28 questions)
  { id:6272, domain:2, domainName:D2, question:"A financial institution's AML compliance program is MOST effective when:", options:["It is designed primarily to satisfy regulatory examinations","It is embedded in the institution's culture with governance, resources, accountability, and continuous improvement","It focuses exclusively on filing SARs and CTRs","It applies identical measures to all customers regardless of risk"], answer:1, explanation:"Effectiveness goes beyond technical compliance. An effective program has: board and senior management ownership; adequate staffing and resources; clear accountability; ongoing testing and improvement; and a culture where every employee understands their role in preventing financial crime." },
  { id:6273, domain:2, domainName:D2, question:"'Customer acceptance policy' (CAP) in AML compliance refers to:", options:["A policy requiring all customers to accept the institution's terms of service","A risk-based framework defining what types of customers the institution will and will not accept, and what due diligence is required for each risk tier","A policy requiring customers to accept EDD conditions as a condition of account opening","A FinCEN-mandated disclosure that customers must sign at account opening"], answer:1, explanation:"CAP (also called customer selection policy or onboarding policy) defines the institution's risk appetite for customers — which customer types are acceptable, which require EDD, and which are prohibited — based on the institution's AML risk assessment and regulatory requirements." },
  { id:6274, domain:2, domainName:D2, question:"'Dual control' in AML processes refers to:", options:["Having two compliance officers review every transaction","Requiring two separate approvals for high-risk decisions — such as SAR filing or account closure — to prevent errors and ensure appropriate oversight","Using both automated and manual monitoring systems","Having both domestic and foreign regulators review AML programs"], answer:1, explanation:"Dual control (or four-eyes principle) ensures that high-stakes decisions — approving high-risk customer relationships, filing SARs, closing accounts for AML reasons — involve at least two qualified reviewers, reducing the risk of individual error, bias, or corruption." },
  { id:6275, domain:2, domainName:D2, question:"An AML 'typology' study is MOST useful for:", options:["Determining the exact number of SARs an institution should file annually","Identifying patterns and methods used in ML/TF to inform detection scenarios, training, and risk assessments","Setting CTR thresholds at the institutional level","Calculating the compliance department's budget requirements"], answer:1, explanation:"Typology studies (conducted by FATF, UNODC, FIUs, and financial sector bodies) document real-world ML/TF methods — how criminals use specific financial products, industries, or geographic routes. This intelligence directly informs TMS scenario design, employee training, and risk assessment calibration." },
  { id:6276, domain:2, domainName:D2, question:"'Enhanced ongoing monitoring' for a high-risk customer includes:", options:["Checking the customer against the OFAC SDN List once a year","More frequent review of transactions, lower alert thresholds, more regular CDD reviews, and senior management visibility into the relationship","Requiring the customer to provide monthly bank statements","Conducting a law enforcement background check on the customer"], answer:1, explanation:"EDD for high-risk customers is not a one-time event — it must be ongoing. This means: more sensitive TMS scenarios (lower thresholds, more typology-specific rules); more frequent CDD reviews (annual or more); periodic relationship reviews at senior management or relationship committee level." },
  { id:6277, domain:2, domainName:D2, question:"The 'front-line defense' concept in AML compliance refers to:", options:["The compliance department's primary role in identifying suspicious activity","Business-line employees (relationship managers, tellers, customer service representatives) as the first point of contact who can identify and escalate potential suspicious activity","The automated transaction monitoring system as the primary detection tool","Law enforcement agencies as the ultimate line of defense against money laundering"], answer:1, explanation:"The three lines of defense model: First line = business units (relationship managers, tellers) who know their customers and observe anomalous behavior; Second line = compliance/AML team that investigates, monitors, and reports; Third line = internal audit that tests both. All three must function effectively." },
  { id:6278, domain:2, domainName:D2, question:"'De-risking' is considered problematic by FATF because:", options:["It increases the overall risk of money laundering in the financial system by driving transactions to unregulated channels","It reduces the number of SARs filed with financial intelligence units","It increases the cost of financial products for consumers","It violates AML regulations by refusing service to high-risk customers"], answer:0, explanation:"When banks exit high-risk market segments (e.g., MSB accounts, correspondent banking with smaller nations), those transactions don't stop — they migrate to less-regulated channels, reducing financial system transparency and actually increasing the systemic risk of ML/TF." },
  { id:6279, domain:2, domainName:D2, question:"A financial institution discovers that an employee has been structuring their own payroll deposits to avoid CTR reporting. The institution should:", options:["Issue the employee a written warning and continue their employment","File a SAR immediately and consider termination and notification of regulators and law enforcement","Increase the employee's compliance training requirements","Consult with the employee about their motivations before taking any action"], answer:1, explanation:"Employee structuring is a serious violation of the BSA and is a crime. The institution must file a SAR, notify its primary federal regulator, consider immediate termination, and may face its own liability if the violation was facilitated by systemic failures." },
  { id:6280, domain:2, domainName:D2, question:"'Know your employee' (KYE) programs in AML are designed to:", options:["Monitor employees' personal financial transactions for potential ML","Screen employees for criminal backgrounds, conflicts of interest, and financial difficulties that could make them vulnerable to corruption or complicit in financial crime","Conduct AML training assessments for all employees annually","Verify employee identity using the same CIP standards applied to customers"], answer:1, explanation:"KYE programs recognize that employees are a significant insider threat in AML — they have access to accounts, compliance systems, and customer data. Background checks, financial stress monitoring, conflict-of-interest declarations, and clear ethics policies all help mitigate insider risk." },
  { id:6281, domain:2, domainName:D2, question:"A financial institution should review and update its AML risk assessment:", options:["Every five years, when major regulatory changes occur","Periodically, and whenever significant changes occur in the institution's products, services, customers, geographies, or the external risk environment","Only when directed to do so by a regulatory examiner","Once at program inception and then only when new regulations are enacted"], answer:1, explanation:"AML risk assessments should be living documents — refreshed periodically (often annually for most institutions) and triggered by material changes: new products, entry into new markets, significant shifts in customer mix, major regulatory developments, or emerging typologies identified through external intelligence." },
  { id:6282, domain:2, domainName:D2, question:"Which of the following best describes 'simplified due diligence' (SDD)?", options:["A process for quickly opening accounts without any identity verification","Applying reduced CDD measures to low-risk customers or relationships where the ML/TF risk is demonstrably minimal","Eliminating beneficial ownership requirements for small transactions","A process for customers who refuse to provide standard KYC documentation"], answer:1, explanation:"SDD allows institutions to apply lighter-touch due diligence for demonstrably low-risk customers (e.g., government entities, regulated financial institutions, certain low-value accounts) — consistent with the risk-based approach of allocating more resources where risk is higher." },
  { id:6283, domain:2, domainName:D2, question:"When must a financial institution verify customer identity under its CIP?", options:["Within 30 days of account opening","Before the account is opened, or in some cases within a reasonable time after account opening where verification is not feasible at opening","Only when the customer conducts a transaction over $10,000","When the customer's first transaction occurs"], answer:1, explanation:"CIP requires identity verification at account opening. For certain account types (e.g., credit facilities, accounts opened for individuals not physically present), verification may be completed within a reasonable time after opening, but the institution cannot open the account without beginning the verification process." },
  { id:6284, domain:2, domainName:D2, question:"'Correspondent banking due diligence' under Wolfsberg Principles should include:", options:["Only assessment of the foreign bank's financial stability","Assessment of the foreign bank's AML/CFT controls, ownership, regulatory status, management, products, customer base, and the purpose of the relationship","Requesting that the foreign bank conduct EDD on all its customers","Automatic refusal of any bank from a jurisdiction with a FATF warning"], answer:1, explanation:"Comprehensive correspondent due diligence assesses the full risk profile of the respondent bank — not just financial health, but AML governance, regulatory compliance history, ownership transparency, and the nature of the services being provided through the correspondent relationship." },
  { id:6285, domain:2, domainName:D2, question:"'Tipping off' a subject about a SAR may constitute:", options:["A best practice in customer relationship management","A federal crime under 31 U.S.C. § 5318(g)(2) regardless of whether harm results","A civil violation only, subject to regulatory action","A minor procedural violation subject to compliance training requirements"], answer:1, explanation:"Tipping off is a serious federal crime — not just a compliance violation. Even if no harm results from the disclosure, it is a criminal offense that can result in prosecution of the individual who disclosed the SAR's existence to its subject." },
  { id:6286, domain:2, domainName:D2, question:"A 'beneficial owner' for CDD purposes is ALWAYS:", options:["The registered agent listed on corporate formation documents","The individual with the highest ownership percentage","A natural person (a human being, not a legal entity) who ultimately owns or controls a legal entity customer","The customer's authorized signatory"], answer:2, explanation:"Beneficial owners must be natural persons — the CDD rule requires working through all layers of corporate structure (companies owning companies) to identify the actual human beings who own or control the entity. Legal entities themselves cannot be UBOs." },
  { id:6287, domain:2, domainName:D2, question:"An institution's BSA/AML compliance program should be documented in:", options:["Only internal emails between the BSA officer and relevant departments","Written policies and procedures approved at the appropriate governance level, accessible to relevant staff","Verbal instructions from senior management communicated during staff meetings","The institution's annual report to shareholders"], answer:1, explanation:"Written, documented policies and procedures are essential — they establish standards, guide employee decision-making, demonstrate regulatory compliance, and serve as evidence in examinations and enforcement proceedings. Oral instructions are insufficient and unverifiable." },
  { id:6288, domain:2, domainName:D2, question:"Which event would MOST likely trigger an immediate review of a customer's AML risk rating?", options:["The customer making a small unusual deposit on one occasion","A news report linking the customer to a criminal investigation or sanction action","The customer opening a new savings account at the same institution","A minor change in the customer's business address"], answer:1, explanation:"Adverse media — news coverage of criminal investigations, arrests, sanctions, regulatory actions, or other negative events — requires prompt reassessment of the customer's risk profile. The new information may require escalation to EDD, enhanced monitoring, or account closure." },
  { id:6289, domain:2, domainName:D2, question:"'Account monitoring orders' differ from 'information requests' in that:", options:["Account monitoring orders require immediate SAR filing; information requests do not","Account monitoring orders direct institutions to monitor and report future account activity; information requests seek information about past transactions","Account monitoring orders are issued by FinCEN; information requests come from the courts","There is no meaningful difference between the two"], answer:1, explanation:"Account monitoring orders (issued under some jurisdictions' laws) prospectively direct institutions to monitor and report future suspicious activity on specific accounts — a powerful but legally complex law enforcement tool. Information requests typically seek historical records through subpoena or court order." },
  { id:6290, domain:2, domainName:D2, question:"A financial institution's AML policies should specify:", options:["The exact dollar threshold above which SARs must always be filed","The process for identifying, escalating, reviewing, and deciding on suspicious activity, including who has authority at each stage of the process","The names of all law enforcement contacts the institution works with","The specific ML typologies that the institution considers most likely in its market"], answer:1, explanation:"AML policies must define the SAR decision-making process clearly — who identifies suspicious activity, how it is escalated, who reviews and approves SAR filing decisions, what documentation is required, and within what timeframes. Ambiguity in the process leads to inconsistent, defensible, and potentially late SAR filings." },
  { id:6291, domain:2, domainName:D2, question:"An 'AML officer' designation at a small community bank:", options:["Requires a full-time staff member dedicated exclusively to BSA/AML compliance","May be a part-time role for a small institution, but requires sufficient authority, expertise, and resources to effectively manage the AML program","Must be a position held by the institution's CEO or CFO","Requires specific CAMS certification as a minimum qualification"], answer:1, explanation:"The BSA requires designation of a qualified compliance officer with sufficient authority — but the role may be part-time at smaller, simpler institutions if the workload allows and the officer has genuine knowledge and authority. CAMS certification is not legally required, though it is a best practice." },
  { id:6292, domain:2, domainName:D2, question:"When a financial institution determines that a SAR should NOT be filed on a reviewed alert, it should:", options:["Delete all records of the alert and investigation to avoid creating a paper trail","Document the alert, investigation steps taken, information reviewed, and the rationale for not filing a SAR","Continue to monitor the customer without documenting the review","Consult law enforcement before deciding not to file"], answer:1, explanation:"Non-filing decisions must be documented with the same rigor as filing decisions. The documentation demonstrates good faith — that the institution took the alert seriously, conducted a genuine review, and reached a reasoned judgment. This documentation is essential during regulatory examinations." },
  { id:6293, domain:2, domainName:D2, question:"The 'AML 5th Pillar' (CDD) was added to the BSA four pillars because:", options:["Regulators determined that existing SARs were insufficient to identify suspicious activity","Knowing your customer is foundational to detecting suspicious activity — without understanding what normal looks like, identifying abnormal is impossible","Congress specifically required beneficial ownership collection in the BSA itself","The DOJ required beneficial ownership information for all federal criminal investigations"], answer:1, explanation:"The CDD/beneficial ownership rule (2016, effective 2018) formalized what was already good practice: you cannot effectively monitor transactions or detect suspicious activity if you don't know who you're doing business with. CDD is the foundation on which all subsequent monitoring and investigation rests." },
  { id:6294, domain:2, domainName:D2, question:"'Automated account opening' (without human review) for new customers creates AML risk because:", options:["Automated systems are subject to different BSA requirements than branch-based opening","Automated processes may fail to identify unusual customer characteristics, high-risk business types, PEP status, or SDN matches that a trained human reviewer might detect","Automated account opening is prohibited under BSA regulations","Automated systems cannot process the government-issued identification documents required by CIP"], answer:1, explanation:"Digital and automated onboarding increases operational efficiency but may reduce detection of red flags that require judgment — high-risk business types, unusual customer explanations, complex ownership structures, or characteristics that trigger enhanced scrutiny. Effective controls must be designed specifically for the automated environment." },
  { id:6295, domain:2, domainName:D2, question:"A SAR filed in 'good faith' is protected from civil liability even if:", options:["The institution files the SAR based on incorrect information","The suspicious activity is later determined not to be related to ML or other crime","The institution's determination was based on an unreasonable assessment of the facts","All of the above circumstances"], answer:1, explanation:"The safe harbor (31 U.S.C. § 5318(g)(3)) protects SAR filers from civil liability when filing in good faith. If the activity is later explained innocently, the filer is still protected — the key is that the filing was made in good faith based on the information available at the time." },
  { id:6296, domain:2, domainName:D2, question:"The recommended approach when a compliance officer disagrees with a business line's assessment of customer risk is:", options:["Always defer to the business line, as they know the customer best","Always escalate to law enforcement immediately","Follow the institution's escalation process, with the compliance function having final authority on AML/BSA decisions","Accept the business line's assessment if they provide any written justification"], answer:2, explanation:"Compliance must maintain independence from business lines. Escalation processes typically resolve disagreements at higher management levels, but BSA/AML determinations must ultimately rest with the compliance function — not be overridden by revenue-focused business decisions." },
  { id:6297, domain:2, domainName:D2, question:"Which of the following is an example of a 'transaction monitoring scenario' targeting trade-based money laundering?", options:["Alerting on cash deposits over $9,000","Alerting on wire transfers from jurisdictions on the FATF grey list without a corresponding trade relationship","Alerting when a customer's account balance exceeds $1 million","Alerting on customers who have been the subject of prior SARs"], answer:1, explanation:"TBML-specific TMS scenarios might include: alerts on wire transfers from trade-related accounts to jurisdictions inconsistent with the customer's stated trade routes; unusual trade finance volumes; payments to/from parties unrelated to documented trade relationships; or price discrepancies in trade finance documents." },
  { id:6298, domain:2, domainName:D2, question:"Under FinCEN's MSB registration requirements, the term 'money services business' includes:", options:["All financial institutions regulated by a federal banking regulator","Dealers in foreign exchange, check cashers, money transmitters, issuers and sellers of traveler's checks, and sellers and redeemers of money orders","Only international wire transfer companies","All companies that accept cash payments for any service"], answer:1, explanation:"FinCEN's MSB definition (31 CFR 1010.100) covers: currency dealers/exchangers; check cashers; issuers/sellers/redeemers of traveler's checks; issuers/sellers/redeemers of money orders; money transmitters; and U.S. Postal Service (for money order purposes)." },
  { id:6299, domain:2, domainName:D2, question:"The PRIMARY purpose of AML 'independent testing' is to:", options:["Maximize the number of SARs filed to demonstrate program effectiveness","Identify weaknesses in the AML program before regulators do and recommend improvements","Provide a legal basis for dismissing compliance officers whose programs underperform","Replace the BSA officer's day-to-day compliance responsibilities"], answer:1, explanation:"Independent testing (audit) provides an objective assessment of program effectiveness — identifying gaps, weaknesses, and areas for improvement that the compliance function itself may not see. Results should drive program enhancement, not just document compliance." },
  // Domain 3 for exam3 (30 questions)
  { id:6300, domain:3, domainName:D3, question:"The primary purpose of a financial investigation's 'asset tracing' phase is to:", options:["Determine the suspect's tax liability","Identify and locate assets connected to criminal activity for potential seizure and forfeiture","Calculate the total amount of money laundered for sentencing purposes","Establish the paper trail required for SAR filing"], answer:1, explanation:"Asset tracing identifies where criminal proceeds have gone — through bank accounts, real estate, investments, vehicles, and other assets — enabling law enforcement to freeze and ultimately forfeit those assets, removing the financial benefit of crime." },
  { id:6301, domain:3, domainName:D3, question:"A 'Suspicious Activity Report' filed for structuring should:", options:["Include a photograph of the subject","Contain detailed transaction records, the pattern identified, and the specific analysis supporting the structuring conclusion","Identify the exact criminal proceeds being structured","Include law enforcement's confirmation that the activity is criminal"], answer:1, explanation:"A structuring SAR should document: the exact transactions (amounts, dates, accounts), the pattern across time, why the analyst concluded the amounts appear deliberately chosen to avoid CTR thresholds, and any additional red flags (customer behavior, business inconsistency)." },
  { id:6302, domain:3, domainName:D3, question:"'Counter-terrorism financing' (CTF) differs from standard AML in that:", options:["CTF focuses on larger transactions than standard AML","CTF may involve monitoring very small transactions and transactions from legitimate sources, since TF amounts can be minimal and funds may come from legal origins","CTF applies only to transactions involving designated terrorist organizations","CTF has higher SAR filing thresholds than standard AML"], answer:1, explanation:"TF is qualitatively different from ML: amounts can be very small (individual attack funding may be a few hundred dollars); the funds may be entirely legitimate in origin (donations, wages, savings); and the connection to terrorism may not be apparent from the transaction alone." },
  { id:6303, domain:3, domainName:D3, question:"Which of the following is an example of 'financial intelligence' that might support a terrorism financing investigation?", options:["A suspect's social media posts about political views","Multiple small wire transfers from unrelated sources to the same account in a conflict zone, followed by rapid withdrawal of funds","The suspect's employment history","The suspect's criminal record for non-financial offenses"], answer:1, explanation:"Financial intelligence in a TF investigation identifies the funding mechanism — how money is collected, transferred, and used to support terrorist activity. Patterns of collection (many small transfers from diverse sources) followed by rapid movement to conflict regions is a characteristic TF financial signature." },
  { id:6304, domain:3, domainName:D3, question:"The 'Egmont Secure Web' (ESW) is:", options:["A cybersecurity tool used by financial institutions to protect AML systems","A secure platform used by Egmont Group member FIUs to exchange financial intelligence internationally","A FATF database tracking ML/TF enforcement actions globally","A web portal for financial institutions to file SARs with multiple jurisdictions simultaneously"], answer:1, explanation:"The Egmont Secure Web is the secure, dedicated communication platform that enables FIUs in the Egmont Group to exchange sensitive financial intelligence information securely and efficiently, in compliance with the Egmont Principles for Information Exchange." },
  { id:6305, domain:3, domainName:D3, question:"An AML analyst discovers that a customer's wire transfer patterns closely match a known TBML typology. The analyst should:", options:["File a SAR immediately without further investigation","Contact the customer to explain the concern and ask for clarification before taking any action","Conduct further investigation to document the specific facts supporting the typology match before making a SAR filing decision","Report directly to law enforcement without filing a SAR"], answer:2, explanation:"A typology match is a red flag — not automatic proof. The analyst must investigate further: does the customer's stated business involve international trade? Is the counterparty in a jurisdiction consistent with the customer's business profile? Does the amount and timing make commercial sense? Only then can a SAR decision be well-supported." },
  { id:6306, domain:3, domainName:D3, question:"'Behavioral analytics' in AML transaction monitoring differ from traditional rule-based monitoring in that:", options:["Behavioral analytics only apply to cash transactions","Behavioral analytics establish dynamic baselines for each customer and flag deviations from that individual's pattern, rather than applying static thresholds to all customers","Behavioral analytics are exclusively used for high-risk customers","Behavioral analytics replace the need for human review of alerts"], answer:1, explanation:"Traditional rules apply fixed thresholds (e.g., alert on all transactions over $50,000 to foreign accounts). Behavioral analytics create individualized models of each customer's expected behavior and alert when actual behavior deviates significantly — reducing false positives and catching sophisticated ML that evades static rules." },
  { id:6307, domain:3, domainName:D3, question:"A financial institution's 'SAR decision-making committee' typically includes:", options:["The institution's board of directors and external auditors","Senior compliance staff, legal counsel, and potentially relevant business line management, with final authority resting with compliance","Only the BSA officer with no committee structure needed","Law enforcement representatives who advise on suspicious activity determinations"], answer:1, explanation:"SAR committees (or similar governance structures) ensure that complex SAR decisions benefit from multiple perspectives — legal analysis, business context, compliance expertise — while maintaining the compliance function's independence in the final determination." },
  { id:6308, domain:3, domainName:D3, question:"'Money laundering through real estate' is MOST effectively detected by:", options:["Requiring all-cash real estate transactions to be reported to FinCEN","Coordination between financial institutions, title companies, real estate agents, and law enforcement, combined with geographic targeting orders (GTOs)","Prohibiting foreign nationals from purchasing U.S. real estate","Requiring mortgage brokers to file SARs on all cash-financed transactions"], answer:1, explanation:"Real estate ML requires a multi-institutional approach. FinCEN's Geographic Targeting Orders (GTOs) require title companies to report beneficial owners in cash real estate transactions above threshold in targeted markets, significantly improving transparency in this historically opaque sector." },
  { id:6309, domain:3, domainName:D3, question:"'Placement indicators' that should be monitored in transaction monitoring systems include:", options:["Complex layering transactions across multiple jurisdictions","Large, frequent, or structured cash deposits inconsistent with the customer's business profile","End-stage investment in real estate or securities","Wire transfers aggregating from multiple sources to a single account"], answer:1, explanation:"Placement-stage monitoring focuses on cash entry points — deposits, cash exchanges, MSB transactions — where illicit cash first enters the financial system. Placement indicators include cash volumes inconsistent with the business type, structured deposits, and geographic concentration of cash activity." },
  { id:6310, domain:3, domainName:D3, question:"The 'prima facie' standard in SAR filing means:", options:["The institution must prove money laundering has occurred before filing a SAR","The institution needs only a basis for suspicion at face value — not conclusive proof — to file a SAR","SAR filing requires consensus among all compliance staff","SARs can only be filed after law enforcement confirms suspicious activity"], answer:1, explanation:"Prima facie (at first appearance) captures the SAR standard well — the institution needs sufficient apparent basis to suspect ML/TF from the available facts, without needing to prove the underlying crime. This enables timely reporting that preserves the value of the intelligence for law enforcement." },
  { id:6311, domain:3, domainName:D3, question:"Which of the following is MOST important for maintaining the quality of AML investigations?", options:["Filing as many SARs as possible to demonstrate program activity","Thorough documentation of the analytical process, facts considered, and rationale for each decision — whether or not a SAR is filed","Completing investigations as quickly as possible to meet productivity targets","Consulting with law enforcement before making any SAR filing decision"], answer:1, explanation:"Documentation quality is the foundation of AML investigation integrity — it creates an auditable record of good-faith compliance, enables supervisory review, supports law enforcement use of the SAR, and protects the institution in regulatory examinations." },
  { id:6312, domain:3, domainName:D3, question:"FinCEN Advisories and Geographic Targeting Orders (GTOs) are BEST described as:", options:["Mandatory regulations with civil and criminal penalties for non-compliance","Guidance and targeted information requests from FinCEN that help financial institutions identify specific risks or focus monitoring on particular geographic areas or transaction types","Voluntary industry guidelines with no legal force","Requirements issued exclusively by the DOJ for law enforcement investigations"], answer:1, explanation:"FinCEN Advisories alert institutions to specific typologies, geographic risks, or emerging threats (e.g., COVID-19 fraud ML, ransomware payment typologies). GTOs are targeted reporting requirements for specific industries and geographies (e.g., all-cash real estate purchases in certain markets). Both are legally significant tools." },
  { id:6313, domain:3, domainName:D3, question:"'Open-source intelligence' (OSINT) in AML investigations refers to:", options:["Intelligence obtained from classified government sources","Publicly available information from news, court records, corporate filings, social media, and other open sources used to supplement CDD and investigation","Intelligence shared between financial institutions through 314(b)","Data obtained through court-ordered subpoenas of financial records"], answer:1, explanation:"OSINT is a critical complement to transaction monitoring — it provides context about customers (adverse news, corporate relationships, public beneficial ownership information) that internal transaction data alone cannot provide, enabling more informed suspicious activity assessments." },
  { id:6314, domain:3, domainName:D3, question:"A 'currency seizure' at the border by CBP or ICE can generate financial intelligence that is MOST useful for:", options:["Prosecuting the individual for money laundering based solely on the seizure","Generating investigative leads about ML/TF networks through subsequent financial investigation","Automatically triggering SAR filing by all financial institutions in the area","Generating CTR filing requirements for the individual's accounts"], answer:1, explanation:"Border cash seizures provide law enforcement with an investigative starting point — identifying the individual, the amount, and potentially their travel route. Subsequent financial investigation (following bank records, 314(a) queries, SAR review) can reveal the full ML network." },
  { id:6315, domain:3, domainName:D3, question:"The primary limitation of SAR data as an investigative tool is:", options:["SARs are not legally admissible as evidence in court","SAR data only reflects suspicious activity that financial institutions detected and reported — potentially missing ML/TF activity that was not caught by the AML system","SARs are available to the public through FOIA","SARs contain only limited transaction information, not narrative explanations"], answer:1, explanation:"SAR data represents the visible portion of financial crime — what was detected and reported by the financial sector. Sophisticated ML schemes designed to evade detection, or those operating through non-reporting entities, may not appear in SAR data at all, creating intelligence gaps." },
  { id:6316, domain:3, domainName:D3, question:"'Risk-based alert disposition' in AML means:", options:["Closing alerts faster by prioritizing smaller transaction amounts","Focusing investigative resources on alerts with higher ML/TF risk potential based on customer risk rating, alert type, and other contextual factors","Filing a SAR for every alert without investigation to maximize reporting volume","Assigning alerts exclusively to automated systems for disposition"], answer:1, explanation:"Risk-based disposition allocates analyst time proportionally — high-risk alerts (from high-risk customers, involving high-risk transaction types or jurisdictions) receive more thorough investigation, while lower-risk alerts may receive more streamlined review. This is the risk-based approach applied to the investigation process itself." },
  { id:6317, domain:3, domainName:D3, question:"'Money laundering through gaming' is MOST likely detected by monitoring for:", options:["Customers who play at casinos more than once per week","Purchase of casino chips with cash followed by minimal gambling activity and redemption for casino checks or wire transfers","Any customer who uses a Players Club card at a casino","Customers who win large jackpots at slot machines"], answer:1, explanation:"Casino ML typically involves converting illicit cash to chips, conducting minimal gambling (or none), and then cashing the chips for a casino check or wire — which creates an apparently legitimate gambling payment. Monitoring for customers with high chip purchases and minimal game play is a key detection control." },
  { id:6318, domain:3, domainName:D3, question:"A financial institution should file a 'SAR on transactions' rather than a 'SAR on account activity' when:", options:["The SAR involves more than one transaction","The suspicious activity involves specific identifiable transactions rather than an ongoing pattern across the full relationship","The transaction involved exceeds $10,000","Only one department is involved in reviewing the suspicious activity"], answer:1, explanation:"SAR categorization (transaction SAR vs. account activity SAR) affects what historical period of activity is covered and what detail is provided. Transaction SARs focus on specific suspicious transactions; account SARs cover the broader activity pattern — both have their appropriate uses depending on the nature of the suspicious activity." },
  { id:6319, domain:3, domainName:D3, question:"The purpose of a 'case management system' in AML compliance is to:", options:["Automatically file SARs based on pre-set criteria","Track and document the full lifecycle of AML investigations — from alert generation through investigation, disposition, and SAR filing — providing audit trails and management reporting","Manage customer relationship information for marketing purposes","Track regulatory examination findings and remediation progress only"], answer:1, explanation:"AML case management systems integrate TMS alerts, investigation documentation, SAR drafting and filing, and management reporting into a single platform. They enable consistent process, comprehensive documentation, regulatory reporting, and quality review — essential for both effectiveness and regulatory compliance." },
  { id:6320, domain:3, domainName:D3, question:"'Account takeover fraud' proceeds are typically laundered by:", options:["The victim converting their own funds to cryptocurrency","The fraudster rapidly moving funds from the victim's account through multiple domestic and/or foreign accounts before withdrawing as cash or converting to cryptocurrency","The fraudster depositing funds directly into their business account","The victim's bank blocking all outgoing transfers and holding funds pending investigation"], answer:1, explanation:"ATO proceeds must be moved quickly before the fraud is detected. Fraudsters immediately initiate wire transfers or ACH payments to other accounts (often money mule accounts), then move funds again, convert to cryptocurrency, or withdraw as cash — creating rapid layering before the victim or institution can react." },
  { id:6321, domain:3, domainName:D3, question:"The PRIMARY challenge in detecting 'trade finance-based money laundering' at the transaction level is:", options:["Trade finance transactions are not subject to AML reporting","Financial institutions rarely process trade finance payments","Financial institutions process trade finance payments based on documents they cannot independently verify for accuracy","Trade finance transactions never involve cash"], answer:2, explanation:"Banks process trade finance payments (Letters of Credit, documentary collections) based on documents — invoices, bills of lading, inspection certificates — whose accuracy they typically cannot independently verify. A fraudulent invoice that overstates value looks identical to a legitimate one." },
  { id:6322, domain:3, domainName:D3, question:"'FinCEN Advisories' are MOST useful for financial institutions because they:", options:["Provide legally binding instructions for SAR filing","Identify specific typologies, methods, and red flags that can be used to calibrate TMS scenarios and inform SAR decisions","Grant institutions legal immunity for SAR filings related to the advisory subject","Replace the need for independent risk assessments"], answer:1, explanation:"FinCEN Advisories provide actionable intelligence — specific red flags, transaction patterns, and typologies identified by government analysis of real cases. This intelligence directly informs TMS calibration, training updates, and investigation standards, making the institution's AML program more effective against current threats." },
  { id:6323, domain:3, domainName:D3, question:"When FinCEN issues a '314(a)' request, financial institutions must respond:", options:["Only if they find a matching account — no response is required if there is no match","Within 14 business days regardless of whether a match is found","Only to their primary federal regulator, not to FinCEN directly","Within 48 hours for terrorism-related requests and 14 days for all others"], answer:1, explanation:"Institutions must respond to 314(a) requests within 14 calendar days — even if no match is found (they report a negative result). The strict deadline ensures law enforcement can act on leads quickly and confirms that all covered institutions actually searched their records." },
  { id:6324, domain:3, domainName:D3, question:"'Deconfliction' in law enforcement AML investigations refers to:", options:["Removing conflicting allegations from SAR filings","A process where agencies identify and coordinate their investigations to avoid compromising each other's cases or investigation subjects","Resolving contradictions in a suspect's financial records","Eliminating false positive alerts from transaction monitoring systems"], answer:1, explanation:"Deconfliction prevents different law enforcement agencies from independently approaching the same subject, potentially tipping off a target or compromising related investigations. It enables agencies to coordinate strategy, share intelligence, and present a unified investigative front." },
  { id:6325, domain:3, domainName:D3, question:"A 'Suspicious Activity Report' becomes legally protected from discovery in civil proceedings once it is:", options:["Approved by the institution's legal department","Filed with FinCEN — it becomes protected from mandatory disclosure by the tipping-off prohibition and SAR confidentiality provisions","Reviewed by the institution's board of directors","Confirmed as related to an active law enforcement investigation"], answer:1, explanation:"Once filed with FinCEN, a SAR is protected from compelled disclosure in civil litigation under 31 U.S.C. § 5318(g)(2) — courts have generally upheld SAR confidentiality in civil discovery proceedings, recognizing the important policy interest in protecting the SAR reporting system." },
  { id:6326, domain:3, domainName:D3, question:"Which type of financial institution has the HIGHEST volume of SAR filings with FinCEN?", options:["Investment advisers","Casinos","Depository institutions (banks and credit unions)","Money services businesses"], answer:2, explanation:"Banks and credit unions are the largest category of SAR filers by volume, reflecting their central position in the financial system — they process the vast majority of payments, hold most accounts, and have the most developed AML monitoring infrastructure relative to other sectors." },
  { id:6327, domain:3, domainName:D3, question:"'Financial sanctions screening' should occur:", options:["Only at account opening","At account opening and whenever a transaction occurs, with periodic re-screening between transactions for name list updates","Only for cross-border transactions","Only when a customer's risk rating is high"], answer:1, explanation:"OFAC compliance requires real-time transaction screening (every wire, ACH, or other payment), onboarding screening, and periodic re-screening of existing customers against updated sanctions lists — since new designations can be added to the SDN List at any time without prior notice." },
  { id:6328, domain:3, domainName:D3, question:"'Financial crime compliance' as a broader concept encompasses:", options:["Only BSA/AML requirements","BSA/AML, OFAC sanctions compliance, anti-bribery and corruption (ABC), fraud prevention, and market integrity — the full spectrum of financial crime prevention","Only those requirements enforced by FinCEN","Only activities required by federal banking regulators"], answer:1, explanation:"Modern financial crime compliance (FCC) addresses the full spectrum of financial crime risks — ML/TF, sanctions, ABC/FCPA, fraud, tax evasion facilitation, and market abuse. These disciplines are increasingly integrated because the underlying criminal actors and methods often overlap." },
  { id:6329, domain:3, domainName:D3, question:"An 'acute risk' in AML compliance differs from a 'chronic risk' in that:", options:["Acute risks require immediate SAR filing; chronic risks require ongoing monitoring","Acute risks represent sudden, specific events or information requiring immediate response; chronic risks are ongoing vulnerabilities embedded in the institution's business model or environment","Acute risks only arise during regulatory examinations","Chronic risks are always higher-priority than acute risks"], answer:1, explanation:"Acute risks (e.g., a newly sanctioned counterparty, a breaking news story about a customer, a 314(a) hit) require immediate, specific action. Chronic risks (e.g., operating in a high-risk market segment, serving a customer population with elevated ML risk) require systematic, ongoing management through the AML program." },
  // Domain 4 for exam3 (31 questions)
  { id:6330, domain:4, domainName:D4, question:"The 'Racketeering Influenced and Corrupt Organizations Act' (RICO) is relevant to AML because:", options:["RICO established the CTR filing requirements","RICO allows prosecution of criminal enterprises as a whole, enabling ML charges based on a pattern of criminal activity rather than requiring proof of individual transactions","RICO eliminated the requirement for a specific predicate offense in ML prosecutions","RICO is used exclusively for drug trafficking prosecutions"], answer:1, explanation:"RICO enables prosecutors to charge entire criminal organizations (not just individual crimes) — a pattern of racketeering activity. Money laundering derived from RICO predicates (e.g., drug trafficking, fraud, extortion) can be charged under RICO as well as under 18 U.S.C. § 1956, enabling broader forfeiture and prosecution." },
  { id:6331, domain:4, domainName:D4, question:"'Criminal forfeiture' in ML cases requires:", options:["Only probable cause that property is connected to crime","A criminal conviction — forfeiture is part of the criminal sentence and is in personam against the convicted defendant","Only a preponderance of evidence standard","Unanimous approval by the grand jury"], answer:1, explanation:"Criminal forfeiture follows conviction — it is part of the criminal sentence. The government must prove beyond a reasonable doubt that the defendant committed the crime, and then prove the connection between the specific property and the offense at the same standard or by preponderance." },
  { id:6332, domain:4, domainName:D4, question:"'Substitute assets' in forfeiture proceedings refers to:", options:["Replacing seized assets with cash equivalents","When direct criminal proceeds cannot be found, the government may forfeit other assets of the defendant of equivalent value","Returning seized assets to victims and confiscating different property","Assets that are substituted for cash in ML schemes"], answer:1, explanation:"The substitute asset provision (18 U.S.C. § 982(b)) allows forfeiture of other assets when the direct proceeds: cannot be located; have been transferred to third parties; are beyond jurisdiction; have commingled with other property; or have been reduced in value. This prevents criminals from evading forfeiture by spending or hiding proceeds." },
  { id:6333, domain:4, domainName:D4, question:"'Money laundering conspiracy' charges under 18 U.S.C. § 1956(h) allow:", options:["Charging the financial institution that processed the transactions","Prosecution of all members of a criminal scheme regardless of whether each person individually committed all elements of the underlying ML offense","Doubling the penalties applicable to individual ML charges","Charging ML offenses that occurred before the enactment of § 1956"], answer:1, explanation:"Conspiracy charges (§ 1956(h)) allow prosecution of the full conspiracy — everyone who agreed to participate in the ML scheme faces liability, even if they only performed a limited role. This is a powerful tool for dismantling criminal organizations." },
  { id:6334, domain:4, domainName:D4, question:"The 'USA PATRIOT Improvement and Reauthorization Act of 2005' primarily:", options:["Eliminated the CTR reporting requirement for cash transactions below $10,000","Extended and modified certain USA PATRIOT Act provisions, including AML information sharing requirements","Created FinCEN as a bureau of the Treasury Department","Established OFAC's sanctions enforcement authority"], answer:1, explanation:"The 2005 Reauthorization Act renewed and modified various PATRIOT Act provisions scheduled to sunset, including Section 215 (business records) and Section 218 (sharing classified information). It also made changes to AML-related provisions regarding information sharing." },
  { id:6335, domain:4, domainName:D4, question:"'Asset restraint' in international ML investigations is used to:", options:["Monitor but not seize suspected criminal assets during an investigation","Freeze criminal proceeds to prevent dissipation or transfer before final forfeiture at the conclusion of the case","Confiscate all assets belonging to suspected money launderers immediately upon suspicion","Restrict the movement of suspects during an AML investigation"], answer:1, explanation:"Asset restraint (through court orders, provisional measures, or emergency administrative action) prevents criminals from moving, spending, or hiding identified criminal proceeds during the investigation — preserving them for ultimate forfeiture upon conviction or civil court order." },
  { id:6336, domain:4, domainName:D4, question:"The 'Kleptocracy Asset Recovery Initiative' (KARI) is a program operated by:", options:["FATF to identify and freeze PEP assets globally","The DOJ to identify, seize, and forfeit assets stolen by corrupt foreign officials and return them to victim countries","OFAC to sanction kleptocratic governments","FinCEN to report on foreign PEP assets held in the United States"], answer:1, explanation:"The DOJ's KARI program specifically targets foreign corruption proceeds — assets stolen from foreign governments by corrupt officials that are hidden in the U.S. financial system. It coordinates with foreign governments on asset recovery and return, embodying a key international anti-corruption commitment." },
  { id:6337, domain:4, domainName:D4, question:"Under the USA PATRIOT Act, financial institutions are required to terminate correspondent accounts if:", options:["The correspondent bank has any customer subject to a FinCEN advisory","The correspondent bank is a foreign shell bank or after receiving a notification from the Secretary of the Treasury that the account poses a primary ML concern","The correspondent bank is not a member of the Wolfsberg Group","The correspondent bank is located in a FATF grey-listed country"], answer:1, explanation:"Section 319(b) of the PATRIOT Act requires U.S. banks to terminate correspondent accounts and block any assets of a foreign bank that the Secretary of Treasury or Attorney General certifies is a foreign bank with a correspondent relationship used to facilitate ML or TF." },
  { id:6338, domain:4, domainName:D4, question:"A 'financial action' in a terrorism financing investigation differs from a standard arrest in that:", options:["Financial actions are only available in federal (not state) terrorism prosecutions","Disrupting TF through account blocking, sanctions designations, or financial action can stop the funding before an attack occurs, whereas an arrest comes after a crime","Financial actions are less legally defensible than traditional law enforcement approaches","Financial actions can only be initiated by FinCEN, not law enforcement"], answer:1, explanation:"Financial disruption is a proactive counter-terrorism tool — blocking accounts, designating entities under OFAC, or seizing assets can prevent terrorist financing from reaching its intended purpose before an attack occurs. This makes financial intelligence and action critical components of counter-terrorism strategy." },
  { id:6339, domain:4, domainName:D4, question:"'Beneficial interest' vs. 'legal title' in ML investigations is important because:", options:["Legal title always follows beneficial interest in U.S. law","Criminals often hold legal title through nominees while retaining beneficial interest — proving beneficial interest is key to establishing that the property is criminal proceeds subject to forfeiture","Beneficial interest is irrelevant to forfeiture proceedings","Legal title holders are always the subject of ML prosecution"], answer:1, explanation:"Proving beneficial ownership (who actually benefits from and controls the asset, not who legally holds the title) is critical for forfeiture and prosecution — criminals use nominees precisely to separate legal title from beneficial interest, and investigators must establish the actual beneficial owner to proceed." },
  { id:6340, domain:4, domainName:D4, question:"'Immunity' from prosecution in ML cases may be offered to:", options:["Financial institutions that file the most SARs","Co-conspirators willing to cooperate with investigators and provide testimony against other members of the criminal enterprise","Individuals who voluntarily return criminal proceeds to authorities","Any suspect who can demonstrate they did not directly commit the predicate offense"], answer:1, explanation:"Prosecutorial immunity is a key investigative tool — providing immunity to lower-level participants in exchange for cooperation enables law enforcement to 'work up' the criminal organization, building cases against principals and leadership that would otherwise be difficult to reach." },
  { id:6341, domain:4, domainName:D4, question:"An AML 'compliance monitor' is MOST commonly appointed in connection with:", options:["Routine regulatory examinations of financial institution AML programs","Enforcement actions (DPAs, consent orders) requiring an independent party to assess and report on the institution's compliance remediation to the relevant authority","FATF mutual evaluation processes for national AML programs","Voluntary institution requests for external program assessment"], answer:1, explanation:"Independent compliance monitors — often former regulators, law enforcement officials, or experienced AML practitioners — are frequently required as part of enforcement settlements. They provide the government with ongoing independent assurance that the institution is implementing required remediation." },
  { id:6342, domain:4, domainName:D4, question:"The 'Egmont Group's' secure information exchange serves AML investigations by:", options:["Providing a public database of known money launderers for financial institutions to screen against","Enabling FIUs to share financial intelligence about specific subjects across international boundaries quickly and securely","Replacing the need for MLATs in international criminal investigations","Providing financial institutions with real-time alerts about new SAR filings"], answer:1, explanation:"The Egmont Secure Web enables FIUs to respond to international financial intelligence requests quickly and securely — a UK FIU investigating a suspected money launderer can query the U.S. FinCEN FIU for relevant financial intelligence about U.S. accounts or transactions, significantly accelerating cross-border investigations." },
  { id:6343, domain:4, domainName:D4, question:"A 'suspicious activity report' itself cannot be subpoenaed or produced in civil discovery because:", options:["SARs are destroyed after 5 years","The tipping-off prohibition and SAR confidentiality provisions protect SARs from compelled disclosure, and courts have generally upheld this protection","SARs are classified documents under federal law","Banks are not required to retain SARs after filing them with FinCEN"], answer:1, explanation:"31 U.S.C. § 5318(g) establishes SAR confidentiality — financial institutions may not produce SARs in response to civil subpoenas, and courts have consistently upheld this. The policy rationale: disclosure of SARs in civil litigation would chill reporting and tip off subjects that a SAR was filed." },
  { id:6344, domain:4, domainName:D4, question:"'Proactive financial intelligence' sharing by law enforcement with financial institutions (vs. reactive requests) can:", options:["Allow financial institutions to close all accounts potentially associated with subjects","Help financial institutions identify and report suspicious activity related to ongoing investigations, improving detection of ML networks that individual institutions cannot see","Eliminate the need for financial institutions to conduct their own AML monitoring","Replace the statutory SAR filing requirements"], answer:1, explanation:"Law enforcement sharing of financial intelligence typologies, trends, and (in some cases) specific subject information with financial institutions enables the private sector to focus its AML efforts more effectively. This public-private partnership is increasingly recognized as essential for effective AML/CFT." },
  { id:6345, domain:4, domainName:D4, question:"The 'Holding Foreign Companies Accountable Act' (HFCAA) is relevant to AML because:", options:["It requires foreign companies to file SARs with FinCEN when their shares are traded on U.S. exchanges","It addresses corporate transparency by requiring foreign companies listed on U.S. exchanges to submit to PCAOB auditing, reducing the ability of opaque foreign entities to use U.S. capital markets to launder funds","It prohibits foreign companies in FATF grey-listed countries from accessing U.S. financial services","It requires U.S. banks to collect beneficial ownership information for all foreign public company customers"], answer:1, explanation:"The HFCAA addresses transparency gaps for foreign companies listed on U.S. exchanges whose auditors are not subject to PCAOB oversight — a vulnerability that has been exploited by fraudulent companies (particularly from jurisdictions with secrecy laws) to access U.S. capital markets." },
  { id:6346, domain:4, domainName:D4, question:"'International freezing orders' in ML cases are typically executed through:", options:["Direct requests from U.S. law enforcement to foreign banks","MLATs or bilateral legal assistance agreements with foreign governments, or under UN Security Council Resolutions","FATF enforcement mechanisms against non-compliant member countries","Egmont Group FIU information exchange requests"], answer:1, explanation:"International asset freezing requires legal authority in the foreign jurisdiction. MLATs provide the legal framework for requesting foreign governments to freeze and ultimately forfeit assets. Emergency requests may also be made through informal law enforcement channels (e.g., INTERPOL), but formal legal process is needed to sustain the freeze." },
  { id:6347, domain:4, domainName:D4, question:"Under AMLA 2020, FinCEN's 'AML/CFT Priorities' require financial institutions to:", options:["File SARs for all transactions related to the priority areas","Consider the AML/CFT priorities in their risk assessments and programs, ensuring their programs address identified priority risks","Report directly to FinCEN on all transactions related to priority areas","Immediately exit business relationships with customers in priority risk categories"], answer:1, explanation:"AMLA 2020 required FinCEN to publish national AML/CFT priorities — these must be incorporated into financial institutions' risk assessments and programs. Institutions don't automatically file SARs on priority-related activity, but must ensure their programs are designed to detect and report it." },
  { id:6348, domain:4, domainName:D4, question:"A 'Financial Action Task Force' mutual evaluation can result in all of the following EXCEPT:", options:["Grey-listing of the country for strategic AML/CFT deficiencies","Recommendations for technical improvements to the country's AML/CFT legal framework","Direct criminal prosecution of government officials responsible for AML failures","Enhanced scrutiny of the country's financial institutions by other FATF member states"], answer:2, explanation:"FATF has no direct enforcement power — it cannot prosecute individuals or impose legal sanctions on countries. Its power is through peer pressure, reputational consequences, and the practical impact of grey/black listing on access to international financial markets." },
  { id:6349, domain:4, domainName:D4, question:"The 'Bank Secrecy Act's' extraterritorial application means:", options:["The BSA only applies to transactions originating in the United States","The BSA can apply to foreign banks that voluntarily maintain U.S. accounts or process U.S.-dollar transactions through U.S. correspondent banks","The BSA applies to all financial institutions worldwide","The BSA's requirements are enforceable only against U.S. citizens abroad"], answer:1, explanation:"Through correspondent banking relationships and U.S. dollar clearing, U.S. authorities have asserted jurisdiction over foreign financial institutions — if a foreign bank processes dollar transactions through a U.S. correspondent, it may be subject to BSA requirements for those transactions and to U.S. enforcement action for violations." },
  { id:6350, domain:4, domainName:D4, question:"'Ponzi scheme' proceeds are considered ML predicate offense proceeds because:", options:["Ponzi schemes are only relevant to securities law, not AML law","Investment fraud (securities fraud) is a designated predicate offense under 18 U.S.C. § 1956, so moving fraudulently obtained investor funds constitutes money laundering","Ponzi schemes always involve cash transactions above the CTR threshold","Ponzi scheme operators are automatically subject to forfeiture regardless of ML charges"], answer:1, explanation:"Securities fraud (18 U.S.C. § 1341/1343) is a specified unlawful activity (SUA) for ML purposes. Ponzi scheme operators who move investor funds — paying earlier investors with new investor money, or siphoning funds for personal use — are engaged in ML of fraud proceeds." },
  { id:6351, domain:4, domainName:D4, question:"'Designated non-financial businesses' (DNFBPs) are typically supervised for AML compliance by:", options:["FinCEN directly for all DNFBP categories","Sector-specific regulators (e.g., state bar associations for lawyers, state real estate boards) or FinCEN for sectors without a sector-specific supervisor","The Federal Reserve for all DNFBPs","The IRS for all DNFBPs because of their involvement in financial transactions"], answer:1, explanation:"DNFBP AML supervision varies by sector and jurisdiction. In the U.S., FinCEN has direct supervisory responsibility for certain DNFBP categories (MSBs, casinos), while others rely on sector-specific regulators (state bar associations for attorneys, state licensing boards for real estate agents) — a noted gap in the U.S. AML system." },
  { id:6352, domain:4, domainName:D4, question:"When a financial institution is presented with a 'civil investigative demand' (CID) from the DOJ, it should:", options:["Respond the same way as to a grand jury subpoena — produce documents immediately without notification to the customer","Consult legal counsel immediately, assess the scope of the demand, and produce responsive documents within the specified timeframe while protecting legitimately privileged information","Notify the customer subject of the demand before producing any documents","File a SAR before complying with the CID"], answer:1, explanation:"A CID is a pre-litigation investigative tool used by DOJ in civil AML enforcement. It requires production of documents and answers to written questions. The institution should comply while consulting counsel regarding scope, privilege (attorney-client, work product), and appropriate procedures — and without notifying the customer." },
  { id:6353, domain:4, domainName:D4, question:"'Correspondent banking' enforcement actions against foreign banks have been based on the theory that:", options:["Foreign banks that process U.S. dollar transactions voluntarily submit to U.S. jurisdiction for those transactions","All foreign banks are automatically subject to U.S. law","U.S. correspondent banking relationships can only be terminated by OFAC","DOJ lacks authority to prosecute foreign financial institutions for ML"], answer:0, explanation:"U.S. prosecutors have successfully asserted jurisdiction over foreign banks by virtue of their use of U.S. dollar clearing accounts at U.S. correspondent banks. Processing transactions through U.S. financial infrastructure — even when the foreign bank itself is not physically present — creates a sufficient U.S. nexus for prosecution." },
  { id:6354, domain:4, domainName:D4, question:"'Restitution' in an ML criminal case differs from 'forfeiture' in that:", options:["Restitution is paid to the government; forfeiture is paid to victims","Restitution compensates identified victims for losses caused by the crime; forfeiture is the government's confiscation of criminal proceeds and instrumentalities","Restitution is only available in civil proceedings; forfeiture is only criminal","There is no meaningful difference between restitution and forfeiture"], answer:1, explanation:"Restitution is victim-focused — compensating identifiable victims for proven losses. Forfeiture is state-focused — the government confiscates criminal proceeds and property used to commit crimes. Both may be ordered in the same case; they serve complementary (but distinct) purposes in the criminal justice system." },
  { id:6355, domain:4, domainName:D4, question:"The 'Bank of New York Mellon' correspondent banking enforcement cases established the principle that:", options:["U.S. banks are not liable for the actions of their foreign correspondent bank customers","U.S. banks have obligations to conduct adequate due diligence on entities for whom they process transactions, even when those entities are themselves financial institutions","Correspondent banking relationships are exempt from AML monitoring requirements","Foreign banks are solely responsible for AML compliance on transactions they originate"], answer:1, explanation:"Major correspondent banking enforcement actions (BNY Mellon, HSBC, Standard Chartered, Citibank) have established that U.S. institutions processing transactions on behalf of foreign banks bear AML responsibility for those transactions — they cannot simply act as a 'pass-through' without adequate due diligence and monitoring." },
  { id:6356, domain:4, domainName:D4, question:"'Financial intelligence' generated by SARs is most effective when:", options:["SARs are filed for every transaction over $10,000","SARs are well-written, factually detailed, timely, and filed by institutions with effective monitoring programs — enabling law enforcement to use them as actionable investigative intelligence","All institutions file SARs using identical formats and threshold triggers","SARs are filed only after law enforcement confirms that an investigation is ongoing"], answer:1, explanation:"SAR quality matters more than volume. A well-crafted SAR narrative that clearly describes the suspicious activity, the parties involved, the financial pattern, and the basis for suspicion provides law enforcement with actionable intelligence. Generic or incomplete SARs, while technically filed, add little investigative value." },
  { id:6357, domain:4, domainName:D4, question:"A 'politically motivated' criminal prosecution (one where enforcement action is driven by political pressure rather than legal merit) is MOST prevented in AML enforcement by:", options:["Requiring congressional approval for all ML prosecutions","Maintaining prosecutorial independence and applying established legal standards consistently across all enforcement decisions","Limiting AML enforcement authority to state attorneys general","Requiring FATF approval before any domestic ML prosecution"], answer:1, explanation:"Prosecutorial independence is a cornerstone of the rule of law — enforcement decisions should be based on evidence, legal standards, and prosecutorial guidelines, not political considerations. Consistent application of standards across similar cases is the best protection against politically motivated enforcement." },
  { id:6358, domain:4, domainName:D4, question:"'International cooperation' in AML matters is MOST effective when based on:", options:["Informal relationships between individual law enforcement officers","Bilateral and multilateral treaties (MLATs), established FIU networks (Egmont), and international organizations (FATF) that provide legal frameworks and secure channels for information exchange","Direct bank-to-bank information sharing outside formal legal channels","Unilateral imposition of sanctions against non-cooperative countries"], answer:1, explanation:"Durable international AML cooperation requires institutional frameworks, not personal relationships. MLATs provide legal authority for evidence requests; Egmont provides a secure FIU network; FATF provides standards and peer pressure for national compliance — together creating a comprehensive international architecture." },
  { id:6359, domain:4, domainName:D4, question:"The 'HSBC Holdings settlement' (2012) was significant for AML enforcement because:", options:["It was the first time a U.S. bank was charged with money laundering","It established that non-U.S. banks are not subject to U.S. BSA requirements","It demonstrated that a major global financial institution could face multi-billion dollar penalties for systematic AML failures, including facilitating transactions for sanctioned countries and drug cartels","It resulted in the first criminal conviction of a bank for money laundering"], answer:2, explanation:"The $1.9 billion HSBC settlement — involving failures to monitor transactions, allowing drug cartel proceeds to be laundered, and processing transactions for sanctioned countries — demonstrated that no institution is too large to be held accountable and set a precedent for large-scale AML enforcement against global banks." },
  { id:6360, domain:4, domainName:D4, question:"The AMLA 2020 provision expanding BSA subpoena authority to include 'foreign financial institutions' was designed to:", options:["Allow U.S. regulators to directly supervise foreign banks","Enable U.S. law enforcement to obtain correspondent banking records from foreign institutions that process U.S. dollar transactions, strengthening the reach of AML investigations across borders","Prohibit foreign financial institutions from maintaining U.S. correspondent accounts","Require foreign banks to register with FinCEN before processing U.S. dollar transactions"], answer:1, explanation:"AMLA 2020 significantly expanded law enforcement's ability to reach records held by foreign financial institutions — particularly important for investigating complex international ML schemes where critical records are held outside U.S. jurisdiction." },
];

// ═══════════════════════════════════════════════════════════════════════════
// EXAM 4  (IDs 6361–6480)
// ═══════════════════════════════════════════════════════════════════════════
const exam4: ExamQuestion[] = [
  { id:6361, domain:1, domainName:D1, question:"The 'integration' stage of money laundering is MOST similar to which legitimate financial activity?", options:["Opening a new bank account","Receiving payment for services rendered or proceeds from an asset sale — both of which can mask the return of laundered funds to the criminal","Making cash deposits into a business account","Filing a CTR for large cash transactions"], answer:1, explanation:"Integration produces funds that appear identical to legitimate receipts — proceeds from a property sale, business income, loan repayment, or investment returns. This makes the integration stage hardest to detect post-hoc, because the funds' appearance is indistinguishable from legitimate economic activity." },
  { id:6362, domain:1, domainName:D1, question:"'Politically exposed persons' in the AML context include all of the following EXCEPT:", options:["A former head of state who left office 5 years ago","A sitting judge on a country's supreme court","A low-level municipal employee who does not exercise significant public authority","A senior executive of a state-owned enterprise"], answer:2, explanation:"PEP status relates to the exercise of prominent public functions — heads of state, senior government officials, legislative members, judicial officials, military leaders, and senior SOE executives. Low-level government employees without significant decision-making authority or public trust are not generally considered PEPs." },
  { id:6363, domain:1, domainName:D1, question:"'Deconstructing' a corporate chain to identify the ultimate beneficial owner requires:", options:["Accepting the first corporate entity listed as the beneficial owner","Working through each layer of the corporate structure until reaching a natural person who owns 25% or more or exercises significant control","Contacting the registered agent of each entity in the chain","Relying on publicly available corporate registration information without further investigation"], answer:1, explanation:"Beneficial ownership determination requires following the ownership chain — identifying who owns Company A (itself owned by Company B) — until reaching the natural persons at the top. Chains of companies in multiple jurisdictions are specifically designed to make this process difficult." },
  { id:6364, domain:1, domainName:D1, question:"'Overpayment fraud' is linked to ML because:", options:["Overpayment fraud involves only small amounts below reporting thresholds","Fraudulently obtained funds from overpayment schemes must be laundered through the financial system before criminals can access and use them","Overpayment fraud is not a predicate offense for money laundering","Overpayment fraud proceeds are automatically reported by banks to law enforcement"], answer:1, explanation:"Overpayment fraud (where a fraudster sends a fraudulent check exceeding the purchase price and asks the victim to wire back the difference) generates criminal proceeds that must be laundered. The rapid movement of wired funds through multiple accounts is the ML dimension of the scheme." },
  { id:6365, domain:1, domainName:D1, question:"'Cryptocurrency mixer' transactions are a form of which ML stage?", options:["Placement","Layering","Integration","Pre-placement"], answer:1, explanation:"Cryptocurrency mixing is a layering technique — funds already in the crypto ecosystem are run through a mixing service (which pools and redistributes funds from multiple sources) to break the blockchain transaction trail, creating distance from the funds' criminal origin." },
  { id:6366, domain:1, domainName:D1, question:"The AML risk presented by 'money service businesses' (MSBs) is primarily that:", options:["MSBs are exempt from all BSA requirements","MSBs handle large volumes of cash and provide financial services to populations without traditional bank accounts — creating potential placement and layering vulnerabilities","MSBs are not subject to OFAC sanctions screening requirements","MSBs are not required to file SARs"], answer:1, explanation:"MSBs (money transmitters, currency exchangers, check cashers) present ML risk because: they handle large cash volumes; serve unbanked populations with limited KYC; are widely distributed and operated by diverse individuals; and provide services (anonymous remittances, check cashing) that can be exploited for ML/TF." },
  { id:6367, domain:1, domainName:D1, question:"'Round-tripping' in money laundering describes:", options:["Conducting multiple cash exchanges in the same day","Moving funds out of a country through offshore structures and back as apparently legitimate foreign investment","Making multiple wire transfers to the same account","Cycling through multiple currencies to obscure the money trail"], answer:1, explanation:"Round-tripping moves funds out of a jurisdiction (often as capital flight or criminal proceeds), through one or more offshore accounts or structures, and back to the origin country — allowing them to return disguised as foreign direct investment or a foreign loan, appearing clean." },
  { id:6368, domain:1, domainName:D1, question:"Which characteristic of 'cryptocurrency' makes it MOST attractive for money laundering?", options:["Cryptocurrency cannot be traced by law enforcement","Cryptocurrency transactions are fully anonymous and untraceable","Cryptocurrency can be transferred across borders instantly with reduced friction compared to traditional banking, and pseudonymous addresses can complicate beneficial ownership attribution","Cryptocurrency is not subject to any financial regulations globally"], answer:2, explanation:"Cryptocurrency offers: rapid cross-border transfer; no geographic restrictions; pseudonymous (not anonymous) addresses that require additional investigation to attribute to real-world identities; and in some cases, privacy-enhancing features (privacy coins, mixers) — making it useful for layering and transfer of value across jurisdictions." },
  { id:6369, domain:1, domainName:D1, question:"'Smurfing networks' are characterized by:", options:["A single individual making multiple small deposits","Multiple individuals (smurfs or couriers) coordinated by an organizer to collectively deposit large amounts of cash in smaller transactions across multiple banks and dates","Automated software systems that structure electronic transactions","Shell companies making structured corporate deposits"], answer:1, explanation:"Smurfing networks involve coordination — an organizer distributes cash to multiple individuals who each make individually sub-threshold deposits at different banks and branches. The organizer then consolidates the deposited funds through subsequent transactions." },
  { id:6370, domain:1, domainName:D1, question:"'Asset protection trusts' in offshore jurisdictions present AML concerns because:", options:["All offshore trusts are presumed to be used for money laundering","Offshore asset protection trusts may be used to shelter criminal assets from domestic law enforcement and creditors, using secrecy and legal protections of the offshore jurisdiction","Asset protection trusts are prohibited under FATF Recommendation 25","Offshore trusts cannot hold real property and are therefore limited as ML vehicles"], answer:1, explanation:"Offshore asset protection trusts (often in jurisdictions with strong trust secrecy laws) can shield criminal assets from domestic creditors, divorce proceedings, civil judgments, and law enforcement forfeiture — particularly when nominee trustees in secrecy jurisdictions hold the assets, obscuring the beneficial owner." },
  { id:6371, domain:1, domainName:D1, question:"The 'Financial Action Task Force on Money Laundering' (FATF) was established by:", options:["The United Nations General Assembly in 1989","The G7 Summit in Paris in 1989","The Basel Committee on Banking Supervision in 1988","The International Monetary Fund in 1990"], answer:1, explanation:"FATF was established in 1989 by the G7 (Group of Seven) Summit in Paris, initially to examine and develop measures to combat money laundering. Its mandate has since expanded to include terrorism financing (2001) and proliferation financing (2012)." },
  { id:6372, domain:1, domainName:D1, question:"'Professional money launderers' who offer ML as a service are MOST likely to be found operating:", options:["Within legitimate financial institutions exclusively","Through informal networks of accountants, lawyers, and financial specialists who move money across jurisdictions for criminal clients","Only in countries on the FATF blacklist","Exclusively through cryptocurrency exchanges"], answer:1, explanation:"Professional ML networks (PLMNs) are staffed by financial professionals — accountants, lawyers, money brokers, bankers — who use their expertise and legitimate business facades to launder money for multiple criminal clients simultaneously, providing a sophisticated, reliable service." },
  { id:6373, domain:1, domainName:D1, question:"The term 'specified unlawful activity' (SUA) in U.S. ML law refers to:", options:["Any activity that violates state law","The list of predicate offenses enumerated in 18 U.S.C. § 1956 whose proceeds can support a money laundering charge","Activities specifically listed by FinCEN as requiring SAR filing","Conduct deemed unlawful by FATF but not necessarily by U.S. law"], answer:1, explanation:"SUAs are the predicate offenses enumerated in § 1956 — drug trafficking, fraud, corruption, terrorism, human trafficking, and many others. For a financial transaction to support an ML charge, the funds must be proceeds of a listed SUA." },
  { id:6374, domain:1, domainName:D1, question:"'Rental income fraud' is linked to ML when:", options:["Rent is received from legitimate tenants","Properties are listed as generating rental income but actually receive illicit cash, which is reported as rental receipts to explain the criminal's income source","Landlords accept cash payments from tenants","Property management companies file CTRs on rental payments over $10,000"], answer:1, explanation:"Rental income fraud involves claiming that cash criminal proceeds are rent payments from tenants (who may be fictitious or complicit). This gives the criminal a seemingly legitimate explanation for their cash income, converting criminal proceeds into documented rental revenue." },
  { id:6375, domain:1, domainName:D1, question:"Which of the following scenarios BEST illustrates 'integration' of laundered funds?", options:["Depositing drug proceeds as a cash deposit at a bank","Running wire transfers through five different countries to obscure the source","Using a shell company to purchase a commercial property, then selling it years later and using the proceeds to fund a legitimate business","Converting drug cash to money orders at multiple MSBs"], answer:2, explanation:"This scenario illustrates integration: the illicit funds (placed into a shell company, layered through the property purchase, then integrated through the property sale) re-enter the legitimate economy as the proceeds of a real estate investment — appearing as legitimate business capital." },
  { id:6376, domain:1, domainName:D1, question:"'Cybercrime proceeds' are increasingly relevant to AML because:", options:["Cybercrime is not a predicate offense for money laundering","Cybercriminals generate large illicit proceeds (ransomware payments, fraud, theft) that must be laundered, often through cryptocurrency and complex international transactions","Cybercriminals exclusively use cash and are outside the traditional financial system","FinCEN does not require SAR filing for cybercrime-related suspicious activity"], answer:1, explanation:"Cybercrime (fraud, ransomware, business email compromise, crypto theft) generates significant criminal proceeds. These proceeds must be laundered — often through cryptocurrency (tumblers, P2P transfers, DeFi protocols), online gambling, or traditional financial channels. AML programs must specifically address cybercrime-related ML typologies." },
  { id:6377, domain:1, domainName:D1, question:"A financial institution observes that a customer has rapidly increased their wire transfer volume to a jurisdiction that is inconsistent with their stated business. This MOST likely indicates:", options:["The customer has legitimately expanded their business internationally","A potential layering or TBML pattern requiring further investigation and possible SAR filing","Normal business evolution that should be documented and accepted","The customer is evading foreign exchange controls, which is not an AML concern"], answer:1, explanation:"Unexplained changes in transaction patterns — especially involving high-risk jurisdictions inconsistent with stated business — are a core AML red flag. The combination of: (1) rapid volume increase; (2) unfamiliar jurisdiction; (3) inconsistency with stated business profile; strongly warrants investigation." },
  { id:6378, domain:1, domainName:D1, question:"'Environmental crime' proceeds (illegal logging, wildlife trafficking, illegal fishing) are relevant to AML because:", options:["Environmental crimes do not generate significant financial proceeds","Environmental crimes generate billions in proceeds annually that must be laundered through the global financial system using methods similar to other organized crime proceeds","FATF does not consider environmental crime a predicate offense","Environmental crime proceeds are always recovered by customs authorities before reaching the financial system"], answer:1, explanation:"Environmental crime is among the world's most profitable criminal industries — the UNODC estimates it generates $110-281 billion annually. Proceeds are laundered through trade finance, real estate, cash businesses, and offshore accounts. FATF has designated environmental crime as a priority focus area." },
  { id:6379, domain:1, domainName:D1, question:"'Proliferation financing typologies' identified by FATF include:", options:["Only state-sponsored transactions from designated countries","Use of front companies, procurement networks, financial intermediaries, and trade-based techniques to acquire goods and technology for WMD programs, often circumventing sanctions","Only large-value single transactions over $1 million","Only transactions involving countries on the FATF blacklist"], answer:1, explanation:"FATF's proliferation financing guidance identifies complex supply chains, front companies in multiple jurisdictions, deceptive shipping practices, misrepresentation of goods on invoices, and use of third-country intermediaries as key PF typologies — often mirroring trade-based ML methods." },
  { id:6380, domain:1, domainName:D1, question:"'Ancient Egyptian ML' (centuries-old trust and agency arrangements) is referenced in AML education to illustrate:", options:["That ML is a modern problem requiring modern solutions","That using intermediaries and agents to hold property on behalf of others — obscuring true ownership — is a fundamental ML/TF technique that has existed across cultures and centuries","That AML regulations have always existed throughout history","That traditional banking systems are inherently resistant to ML"], answer:1, explanation:"Historical references illustrate that the core ML challenge — obscuring beneficial ownership through intermediaries, nominees, and agents — is not a modern invention but a fundamental human technique for concealing wealth. Modern AML tools must address timeless human ingenuity in hiding value." },
  { id:6381, domain:1, domainName:D1, question:"Which of the following is MOST characteristic of 'placement' through a cash-intensive business?", options:["A restaurant owner depositing legitimate daily cash sales","A restaurant owner depositing cash sales that include illicit criminal proceeds commingled with legitimate receipts","A restaurant owner making large wire transfers to foreign suppliers","A restaurant owner reducing their daily cash deposit amounts"], answer:1, explanation:"Cash-intensive businesses (restaurants, car washes, laundromats) provide ideal placement vehicles — illicit cash is mixed with legitimate receipts, and the daily deposit appears consistent with normal business operations. Without a detailed forensic analysis, the illicit component is nearly impossible to identify from the deposit alone." },
  { id:6382, domain:1, domainName:D1, question:"'Beneficial ownership transparency' is considered essential for AML because:", options:["Transparency allows the public to assess whether businesses pay appropriate taxes","Without knowing who ultimately owns and controls legal entities, it is impossible to effectively assess ML/TF risk or trace criminal proceeds through corporate structures","Beneficial ownership information is required for credit assessments","Transparency enables marketing of financial products to appropriate customer segments"], answer:1, explanation:"Opacity of beneficial ownership is the single greatest enabler of ML through corporate structures. Without knowing the UBO, institutions cannot screen against sanctions lists, assess PEP risk, or conduct meaningful CDD — and law enforcement cannot trace criminal proceeds through the corporate veil." },
  { id:6383, domain:1, domainName:D1, question:"A 'high-value dealer' in precious stones is considered a DNFBP because:", options:["They handle large cash transactions for high-value portable assets that can easily convert criminal cash into valuable goods with limited documentation","They are regulated as financial institutions under the BSA","Precious stones are exclusively used as criminal currency","All dealers in precious stones are required to be licensed by FinCEN"], answer:0, explanation:"Dealers in precious metals and stones are included as DNFBPs because: they handle large cash transactions; high-value, portable gems can quickly and discretely convert large amounts of cash; valuations are subjective, making price manipulation easier; and the international market provides ready resale opportunities." },
  { id:6384, domain:1, domainName:D1, question:"The concept of 'risk-based supervision' for AML/CFT means that regulators:", options:["Apply identical examination intensity to all supervised institutions","Allocate examination resources based on each institution's ML/TF risk profile — more intensive oversight for higher-risk institutions and products","Only examine institutions that have prior AML violations","Delegate all AML supervision to the private sector"], answer:1, explanation:"Risk-based supervision mirrors the risk-based approach required of financial institutions — regulators focus their limited examination resources on the institutions and sectors that present the greatest ML/TF risk, enabling more effective use of supervisory capacity." },
  { id:6385, domain:1, domainName:D1, question:"'Domestic wire transfers' present a lower AML risk than international wire transfers PRIMARILY because:", options:["Domestic wire transfers are not subject to the travel rule","Domestic transfers occur within a single jurisdiction where both sending and receiving institutions are subject to BSA requirements and monitoring","Domestic transfers can never exceed CTR thresholds","Domestic transfers are always documented by FinCEN"], answer:1, explanation:"International transfers move funds across regulatory boundaries — from one jurisdiction's AML regime to another's — creating potential gaps. Both the sending and receiving institution in a domestic transfer are subject to U.S. BSA/AML requirements, providing continuous regulatory coverage of both ends of the transaction." },
  { id:6386, domain:1, domainName:D1, question:"FATF's 'non-cooperative countries and territories' (NCCT) list (now replaced by the grey/black list) was significant because:", options:["It established criminal penalties for money launderers in listed countries","It was the first systematic international mechanism for publicly identifying jurisdictions with inadequate AML frameworks and applying international pressure for reform","It granted FATF authority to impose trade sanctions on listed countries","It enabled FATF to directly prosecute financial institutions in listed countries"], answer:1, explanation:"The NCCT list (1999-2006) was a pioneering transparency and accountability mechanism — making it public knowledge which jurisdictions were not meeting international AML standards, creating reputational and financial pressure that motivated reform. It was replaced by the current grey/black list system." },
  { id:6387, domain:1, domainName:D1, question:"'Cyber-laundering' (money laundering through online platforms) poses unique challenges because:", options:["Online platforms are regulated more strictly than traditional financial institutions","The speed, anonymity features, and global reach of online payments, gaming platforms, and cryptocurrency enable rapid cross-border layering with limited paper trails","Cyber-laundering always involves amounts too small to meet SAR reporting thresholds","Online platforms are exempt from FATF recommendations"], answer:1, explanation:"Cyber-laundering exploits the internet's characteristics — speed (funds can be moved globally in seconds), global reach (across multiple jurisdictions simultaneously), and potential for pseudonymity (gaming platforms, digital currencies) — creating ML opportunities that traditional AML systems struggle to detect." },
  { id:6388, domain:1, domainName:D1, question:"The 'integration' stage often involves investing in which types of assets?", options:["Only low-value assets to avoid attracting attention","Real estate, legitimate businesses, luxury goods, securities, and other high-value assets that can later generate apparently legitimate income or be resold for clean proceeds","Only cryptocurrency, because it is difficult to trace","Only domestic assets, to minimize international legal exposure"], answer:1, explanation:"Integration typically targets stable, high-value assets: real estate (generates rental income, appreciates, can be mortgaged), legitimate businesses (generate business income), securities (generate dividends and capital gains), and luxury goods (portable stores of value). These provide both a store of value and a source of apparently legitimate future income." },
  { id:6389, domain:1, domainName:D1, question:"'Overhauling' a traditional ML typology with cryptocurrency technology typically:", options:["Eliminates the need for the placement stage","Adds a new layer of complexity by incorporating virtual asset transfers between the traditional steps, making the overall scheme more difficult to trace but not eliminating the fundamental stages","Eliminates the layering stage entirely","Reduces the time required for the integration stage from years to days"], answer:1, explanation:"Adding cryptocurrency to traditional ML schemes doesn't eliminate the fundamental stages — it adds complexity within them. For example: illicit cash is placed through traditional means → converted to crypto → layered through multiple crypto wallets and mixers → converted back to fiat → integrated through real estate or business investment." },
  { id:6390, domain:1, domainName:D1, question:"'Suspicious activity' in AML refers to:", options:["Any transaction that is unusual compared to the general population's behavior","Activity that, based on available facts and circumstances, a reasonable compliance professional would suspect involves funds from illegal activity, is designed to evade reporting requirements, or lacks a lawful purpose","Only transactions exceeding $10,000 in cash","Only transactions involving foreign parties or accounts"], answer:1, explanation:"The SAR filing trigger — knowing, suspecting, or having reason to suspect — is judged by the standard of a reasonable person with the knowledge available to the institution. It is activity-specific (not just large transactions) and includes suspected regulatory evasion as well as suspected criminal proceeds." },
  { id:6391, domain:1, domainName:D1, question:"A customer's behavior described as 'evasive or nervous when questions about the source of funds are asked' constitutes:", options:["Sufficient basis on its own to file a SAR","A red flag that should be documented and considered in combination with other factors in assessing whether to file a SAR","An immediate requirement to close the account","Normal customer behavior that should not be noted in compliance records"], answer:1, explanation:"Behavioral red flags — nervousness, evasiveness, reluctance to provide information, unwillingness to explain the purpose of transactions — are documented indicators of potential suspicious activity. However, behavior alone rarely constitutes sufficient basis for SAR filing; it should be considered alongside transactional and other red flags." },
  // Domain 2 Exam 4 (28 questions)
  { id:6392, domain:2, domainName:D2, question:"The 'four-eyes principle' in AML refers to:", options:["Monitoring customers with four or more financial accounts","Requiring two independent reviewers for significant AML decisions to reduce the risk of errors or improper influence","Using four separate monitoring scenarios for each customer transaction","Reviewing customer files four times per year as part of ongoing monitoring"], answer:1, explanation:"The four-eyes principle (dual control) requires that important AML decisions — approving high-risk customer relationships, SAR filing decisions, account closure decisions — involve at least two qualified, independent reviewers. This reduces the risk of single-point failure, bias, or corruption." },
  { id:6393, domain:2, domainName:D2, question:"'AML governance' at the board level includes:", options:["The board filing SARs directly with FinCEN","Board approval of the overall AML program, regular reporting on AML risk and program effectiveness, and board accountability for the institution's AML culture and tone at the top","The board conducting annual independent testing of the AML program","Board members personally conducting EDD on high-risk customers"], answer:1, explanation:"Board governance in AML means: approving the AML program and risk appetite; receiving regular management information about ML/TF risks and program performance; understanding key regulatory and enforcement developments; and demonstrating leadership commitment to a strong AML culture throughout the organization." },
  { id:6394, domain:2, domainName:D2, question:"'Transaction monitoring calibration' involves:", options:["Adjusting transaction amounts to stay below CTR thresholds","Regularly testing and tuning monitoring scenarios to balance detection effectiveness (catching suspicious activity) with efficiency (minimizing false positives)","Calibrating the institution's CTR filing thresholds to its customer base","Setting the SAR filing threshold at a level consistent with industry peers"], answer:1, explanation:"TMS calibration is an ongoing process — reviewing alert disposition rates, false positive ratios, missed suspicious activity (identified through lookbacks or law enforcement feedback), and emerging typologies to continuously improve the system's effectiveness and efficiency." },
  { id:6395, domain:2, domainName:D2, question:"The concept of 'control' in beneficial ownership identification includes:", options:["Only direct ownership of more than 50% of the entity","The ability to direct management or policy decisions, regardless of ownership percentage — typically capturing executives, managers, and others with effective control even without majority ownership","Any individual listed on the entity's corporate formation documents","The right to receive dividends from the entity"], answer:1, explanation:"The FinCEN CDD rule's control prong captures the 'functional equivalent' of beneficial ownership — individuals who, even without ownership, exercise effective control over the entity (e.g., a CEO, managing member, or general partner). This prevents circumvention through complex ownership structures that disperse formal ownership below the 25% threshold." },
  { id:6396, domain:2, domainName:D2, question:"'Nested accounts' in correspondent banking create AML risk because:", options:["They allow the respondent bank to monitor the correspondent bank's transactions","They allow the respondent bank to provide correspondent banking services to third-party financial institutions, creating further layers between the ultimate customers and the U.S. correspondent bank","All nested accounts are prohibited under U.S. law","Nested accounts require OFAC approval before transactions can occur"], answer:1, explanation:"When a respondent bank uses a U.S. correspondent account to provide services to other (nested) banks, the U.S. correspondent bank has no visibility into the customers of those nested institutions. This creates additional anonymity layers and expands the ML risk associated with the single correspondent relationship." },
  { id:6397, domain:2, domainName:D2, question:"'Annual certification' of AML training completion by employees is best described as:", options:["The primary evidence that an AML training program is effective","Necessary documentation demonstrating that training occurred, but insufficient on its own to demonstrate program effectiveness — which also requires evidence of practical application","A substitute for actual AML training content","A regulatory requirement that eliminates all institutional liability for employee AML violations"], answer:1, explanation:"Training completion records are necessary but not sufficient. Effective training programs must also demonstrate content relevance, role-specific delivery, practical application (employees can identify and escalate suspicious activity), and outcome metrics (e.g., quality of alert investigation, SAR filing accuracy)." },
  { id:6398, domain:2, domainName:D2, question:"Under FinCEN's CDD rule, financial institutions must update beneficial ownership information when:", options:["Never — information collected at account opening is permanent","At the institution's sole discretion","When the institution becomes aware of a change in beneficial ownership, or as part of the institution's normal ongoing CDD update cycle","Only when the customer voluntarily discloses a change"], answer:2, explanation:"The CDD rule requires updating beneficial ownership information when the institution becomes aware of information about changes. 'Becomes aware' includes: direct customer disclosure; information obtained through monitoring or CDD review; public information (news, corporate filings); or 314(a)/314(b) information." },
  { id:6399, domain:2, domainName:D2, question:"A 'foreign correspondent bank' should be evaluated for AML purposes based on all of the following EXCEPT:", options:["The foreign bank's ownership and management","The regulatory environment of the foreign bank's home jurisdiction","The foreign bank's customer base and service offerings","The personal credit history of the foreign bank's individual customer account holders"], answer:3, explanation:"Correspondent due diligence focuses on the foreign institution itself — not the individual customers of that institution (who are not the direct customers of the U.S. correspondent). The individual customers are the foreign bank's CDD responsibility." },
  { id:6400, domain:2, domainName:D2, question:"The PRIMARY difference between a 'SAR on a transaction' and a 'voluntary disclosure' to law enforcement is:", options:["Voluntary disclosures are filed with FinCEN; SARs are filed with law enforcement agencies","A SAR is a confidential filing with legal protection; a voluntary disclosure involves directly sharing information with law enforcement outside the SAR process","Voluntary disclosures always require customer consent; SARs do not","There is no meaningful difference; both serve the same legal purpose"], answer:1, explanation:"SARs are filed with FinCEN, are confidential (tipping-off prohibition applies), and carry legal protection. Voluntary disclosures to law enforcement are a different type of cooperation — they may involve sharing customer information directly with investigators and carry different legal implications for the institution." },
  { id:6401, domain:2, domainName:D2, question:"'Enterprise-wide AML' refers to:", options:["Applying identical AML procedures to all subsidiaries regardless of local law","Implementing a consistent AML governance framework across all business lines, subsidiaries, and jurisdictions while allowing for appropriate local customization","Centralizing all AML functions in one department regardless of business size","Requiring all departments to file SARs independently"], answer:1, explanation:"Enterprise-wide AML provides consistent governance (risk appetite, policies, accountability) while allowing subsidiaries to adapt implementation to local legal requirements and business specifics. Without enterprise-wide governance, different parts of the same institution may have dramatically different AML standards — creating systemic vulnerability." },
  { id:6402, domain:2, domainName:D2, question:"'Merger and acquisition' (M&A) activity raises specific AML concerns because:", options:["Acquired institutions are automatically exempt from BSA requirements for 24 months post-acquisition","Integrating a new institution may introduce customers, products, and legacy AML program deficiencies that increase ML/TF risk in the acquirer's portfolio","M&A transactions are exempt from SAR filing requirements","M&A activity always reduces the acquirer's overall AML risk profile"], answer:1, explanation:"Acquisitions may bring: customers who weren't subjected to the acquirer's CDD standards; products with different risk profiles; legacy AML program gaps; and cultural differences that affect compliance behavior. Due diligence before acquisition and careful integration planning are essential AML considerations." },
  { id:6403, domain:2, domainName:D2, question:"The term 'AML red line' refers to:", options:["A regulatory violation threshold above which criminal prosecution is automatic","Customer or business types that the institution has determined present unacceptable ML/TF risk and will not serve — a hard limit in the customer acceptance policy","The maximum CTR filing volume before regulators require an examination","The point at which an alert must be escalated from an analyst to a manager"], answer:1, explanation:"AML red lines are the 'never do' rules in a customer acceptance policy — categories of customers or relationships that pose unacceptable risk (shell banks, certain OFAC-adjacent businesses, operators in prohibited sectors) that the institution will not accept regardless of the potential revenue." },
  { id:6404, domain:2, domainName:D2, question:"'Politically exposed person' programs must address which aspect MOST frequently overlooked?", options:["Foreign PEPs seeking private banking relationships","Family members and close associates of PEPs who may hold assets or conduct transactions on behalf of the PEP","Senior executives of multinational corporations","Former PEPs who left office more than 10 years ago"], answer:1, explanation:"PEP programs frequently focus on the PEP themselves but miss family members and close associates — the individuals most commonly used by corrupt PEPs to hold assets and conduct financial transactions. FATF Recommendation 12 explicitly requires institutions to extend PEP risk management to family members and close associates." },
  { id:6405, domain:2, domainName:D2, question:"A 'no match' response to a 314(a) request means:", options:["The institution has no obligation to search its records","The institution searched its records and found no accounts or transactions matching the subject — but must still file a response within 14 days","The institution declines to respond to the request","No SAR is required for the subject"], answer:1, explanation:"Institutions must respond to 314(a) requests within 14 days regardless of whether a match is found — the negative response is itself meaningful and required. The response is sent directly to FinCEN (not to the requesting law enforcement agency), maintaining confidentiality." },
  { id:6406, domain:2, domainName:D2, question:"'Cryptocurrency exchange' AML programs must specifically address:", options:["Traditional banking wire transfer monitoring only","Customer identification (KYC) for wallet holders, transaction monitoring for suspicious blockchain activity patterns, OFAC screening of wallet addresses, and Travel Rule compliance for applicable transfers","Only transactions involving fiat currency conversions over $10,000","None of the above, as cryptocurrency exchanges are exempt from AML requirements"], answer:1, explanation:"Virtual asset service providers (VASPs) including crypto exchanges face AML requirements specific to their business model: KYC for customers (including for hosted wallet holders), blockchain analytics for suspicious activity detection, OFAC screening against sanctioned addresses, and Travel Rule compliance for transfers above applicable thresholds." },
  { id:6407, domain:2, domainName:D2, question:"A financial institution's 'high-risk customer segment' list should be based on:", options:["The institution's historical SAR filing data for different customer types","A comprehensive risk assessment considering customer types, business activities, geographies, and transaction profiles that present elevated ML/TF risk given the institution's specific business model","Industry benchmarks for what other institutions consider high-risk","Regulatory examiner guidance about which customer types to flag"], answer:1, explanation:"Risk segmentation should reflect the institution's own risk profile — a community bank serving local businesses and retail customers has different high-risk segments than a global private bank. The assessment should be data-driven and grounded in the institution's actual customer base and product offerings." },
  { id:6408, domain:2, domainName:D2, question:"The 'model risk management' framework applied to AML transaction monitoring systems requires:", options:["Using transaction monitoring models developed by regulators only","Regular validation of the TMS models — including conceptual soundness review, ongoing monitoring, and outcomes analysis — to ensure they are accurately identifying suspicious activity","Eliminating all automated monitoring in favor of human review","Only testing TMS models at initial implementation, not ongoing"], answer:1, explanation:"Regulatory guidance (e.g., OCC Bulletin 2011-12 on Model Risk Management) applies to AML TMS models. Institutions must validate: that the model correctly identifies the suspicious activity it was designed to detect; that it hasn't degraded due to changes in customer behavior; and that alert thresholds remain appropriately calibrated." },
  { id:6409, domain:2, domainName:D2, question:"'Suspicious mail' or 'suspicious inquiries' from customers asking about reporting requirements or thresholds:", options:["Always result in automatic SAR filing","Must be kept confidential but may serve as a red flag that the customer is attempting to structure transactions","Are protected under consumer privacy laws and cannot be used in SAR decisions","Are irrelevant to AML compliance and should be ignored"], answer:1, explanation:"Customer inquiries about reporting thresholds, documentation requirements, or what triggers a SAR are themselves red flags — they may indicate the customer is planning structuring or attempting to evade reporting. These inquiries should be documented and considered in the overall assessment of the customer's AML risk." },
  { id:6410, domain:2, domainName:D2, question:"'Effectiveness' in AML compliance programs is BEST measured by:", options:["The number of SARs filed annually","The absence of regulatory enforcement actions","The program's ability to detect suspicious activity (leading to SAR filings used by law enforcement), prevent ML/TF risks, and maintain compliance with all applicable requirements","The compliance department's budget as a percentage of total revenue"], answer:2, explanation:"An effective AML program produces real outcomes — suspicious activity is detected and reported, law enforcement investigations are supported, and ML/TF risks are managed. None of the proxy metrics (SAR count, enforcement absence, budget size) alone demonstrates effectiveness; it requires holistic assessment against risk and outcomes." },
  { id:6411, domain:2, domainName:D2, question:"'Fragmentation of accounts' as a structuring indicator specifically refers to:", options:["A customer using multiple banks for different types of transactions","A customer opening multiple accounts at the same or different institutions and using them to disperse large amounts below CTR thresholds, then consolidating the funds","A customer frequently changing accounts within the same institution","A customer maintaining separate personal and business accounts"], answer:1, explanation:"Account fragmentation for structuring purposes involves deliberately spreading cash deposits across multiple accounts to keep each below CTR threshold while subsequently consolidating the deposits. This is a classic structuring method that transaction monitoring should be designed to detect across multiple accounts." },
  { id:6412, domain:2, domainName:D2, question:"Under the BSA, financial institutions are required to have AML compliance programs. 'Program' in this context means:", options:["A one-page compliance checklist updated annually","A comprehensive written set of policies, procedures, and controls covering all required BSA obligations, implemented and tested in practice — not just on paper","Only the SAR filing process and CTR reporting system","A software tool used for transaction monitoring"], answer:1, explanation:"A BSA AML 'program' is a comprehensive, living compliance framework — not merely documentation. It encompasses policies, procedures, training, monitoring systems, reporting processes, governance structures, and ongoing testing — all working together to prevent, detect, and report ML/TF." },
  { id:6413, domain:2, domainName:D2, question:"'Source of wealth' (SOW) and 'source of funds' (SOF) are different concepts because:", options:["SOW and SOF are identical; the terms are used interchangeably","SOW refers to how a customer accumulated their overall net worth (career, inheritance, business history); SOF refers specifically to the origin of funds being deposited or transacted in this particular relationship","SOW is required for all customers; SOF is required only for PEPs","SOF refers to the country of origin; SOW refers to the industry sector"], answer:1, explanation:"Both are important EDD tools but they answer different questions. SOW establishes the legitimacy of the customer's overall wealth — does their lifestyle and assets match their legitimate income history? SOF addresses the specific funds: where did THIS money (being deposited or invested) actually come from?" },
  { id:6414, domain:2, domainName:D2, question:"A CTR 'exemption' for a business customer can be revoked if:", options:["The customer files a SAR against the institution","The customer's transaction patterns change in a way that makes the exemption no longer appropriate, or if the customer no longer meets exemption criteria","The customer changes its business address","The customer opens a new account at the same institution"], answer:1, explanation:"CTR exemptions must be actively managed — institutions must revoke exemptions if the business no longer qualifies (e.g., it's no longer a listed public company, or its transaction patterns have changed from the basis on which the exemption was granted). Annual review of exemptions is a BSA best practice." },
  { id:6415, domain:2, domainName:D2, question:"'Customer segmentation' in AML compliance allows institutions to:", options:["Market different financial products to different customer demographics","Group customers with similar risk profiles to apply consistent, risk-appropriate due diligence and monitoring standards efficiently across the portfolio","Exempt certain customer groups from all AML requirements","Require all customers in a segment to use the same transaction monitoring system"], answer:1, explanation:"Segmentation enables proportionate, systematic AML management — rather than making ad hoc decisions for each customer, the institution applies consistent standards to all customers in similar risk segments. This creates scalability while maintaining risk-based differentiation." },
  { id:6416, domain:2, domainName:D2, question:"A financial institution should file a SAR even when:", options:["The suspicious activity has been resolved and the customer has provided a satisfactory explanation","A law enforcement investigation is already known to be ongoing for the same subject","The customer is no longer a customer at the institution, if the activity occurred while they were a customer","Both B and C"], answer:3, explanation:"SAR filing continues regardless of: known law enforcement investigations (SARs provide additional intelligence even when investigations are ongoing); account closure (suspicious activity that occurred while the customer was active should still be reported even post-closure). Both scenarios require SAR filing." },
  { id:6417, domain:2, domainName:D2, question:"The 'audit committee' of a financial institution's board is most directly responsible for AML compliance by:", options:["Directly supervising the BSA officer's day-to-day activities","Reviewing the results of independent AML testing, monitoring management's remediation of identified deficiencies, and ensuring the AML audit function has sufficient independence and resources","Filing SARs on behalf of the institution","Conducting customer due diligence reviews for high-risk customers"], answer:1, explanation:"The audit committee's AML governance role is oversight — it receives audit results, ensures management acts on findings, and provides board-level accountability for the independent testing function. It does not perform operational AML functions, which remain with the compliance function." },
  { id:6418, domain:2, domainName:D2, question:"'Geographic risk' in AML program design refers to:", options:["The risk of natural disasters in markets where the institution operates","The ML/TF risk associated with specific countries, regions, or cities based on factors such as corruption levels, drug trafficking routes, FATF status, and sanctions restrictions","The operational risk of financial institution branches in high-crime urban areas","The currency risk associated with transactions in foreign currencies"], answer:1, explanation:"Geographic risk assessment considers: FATF status (grey/black list); Transparency International CPI scores; OFAC sanctions programs; drug trafficking routes; terrorism risks; banking secrecy laws; and regulatory quality in each jurisdiction. High geographic risk triggers enhanced monitoring and potentially EDD for transactions or customers with those geographic connections." },
  { id:6419, domain:2, domainName:D2, question:"'AML policy exceptions' (permitting a higher-risk activity that would normally be prohibited) should:", options:["Be approved verbally by any supervisor","Never be granted under any circumstances","Be documented, require appropriate approval authority based on the level of risk, be time-limited where appropriate, and be tracked for management reporting","Be automatically reported to FinCEN"], answer:2, explanation:"Well-governed exception processes are essential — they prevent the exception process from being exploited to circumvent AML requirements while allowing legitimate business needs to be accommodated on a controlled, accountable basis. Every exception should have a documented rationale and approval at the level commensurate with its risk." },
  // Domain 3 exam 4 (30 questions)
  { id:6420, domain:3, domainName:D3, question:"A 'voluntary self-disclosure' by a financial institution to FinCEN or its regulator about AML program deficiencies is considered favorably by regulators because:", options:["It eliminates any civil or criminal liability for the disclosed violations","It demonstrates the institution's good faith, commitment to compliance, and control environment — typically resulting in more favorable resolution than if the deficiency were discovered in examination","It automatically suspends any regulatory examination for 12 months","It qualifies the institution for reduced CTR filing requirements"], answer:1, explanation:"Voluntary self-disclosure signals an effective compliance and governance culture — the institution discovered and reported its own problems rather than waiting to be caught. Regulators consistently give credit for VSDs in enforcement resolution, typically resulting in more favorable terms than examination-discovered violations." },
  { id:6421, domain:3, domainName:D3, question:"'Predictive analytics' in AML monitoring refers to:", options:["Predicting which customers will generate the most revenue for the institution","Using statistical models and machine learning to identify customers or transactions likely to be suspicious based on patterns and indicators, before a specific triggering transaction occurs","Predicting future regulatory changes in AML law","Forecasting the institution's SAR filing volume for budgeting purposes"], answer:1, explanation:"Predictive analytics represents the frontier of AML technology — using ML models trained on known suspicious activity to identify customers or accounts that exhibit precursor patterns, enabling proactive investigation before the suspicious activity fully manifests." },
  { id:6422, domain:3, domainName:D3, question:"'SAR quality' is MOST important because:", options:["Higher quality SARs result in reduced regulatory examination scrutiny","High-quality SARs with comprehensive narratives, accurate identifying information, and relevant transaction detail are most useful as law enforcement investigative leads","Higher quality SARs result in automatic civil immunity for the filing institution","SAR quality determines whether FinCEN will accept the filing"], answer:1, explanation:"Law enforcement relies on SAR quality — a well-written, factually rich SAR with clear identification of subjects, specific transaction details, and a coherent narrative explaining the suspicious activity is immediately actionable. A poorly written, vague, or incomplete SAR provides little investigative value despite being technically filed." },
  { id:6423, domain:3, domainName:D3, question:"'Counter-party risk' in AML refers to:", options:["The risk that a transaction counterparty will default on their financial obligation","The ML/TF risk presented by the entities and individuals on the other side of a financial institution's customers' transactions — wire beneficiaries, check payees, business partners","The risk that a counterparty will file a SAR on the institution","The operational risk of dealing with multiple financial counterparties simultaneously"], answer:1, explanation:"Counterparty risk assessment examines not just the institution's direct customers but also the entities they transact with. High-risk counterparties — those in sanctioned countries, with adverse media, or in high-risk industries — can elevate the overall risk profile of an otherwise lower-risk customer relationship." },
  { id:6424, domain:3, domainName:D3, question:"'AML investigations' are triggered by all of the following EXCEPT:", options:["Automated transaction monitoring alerts","Law enforcement inquiries under 314(a)","A customer opening a new account at the institution","Adverse media reports about an existing customer"], answer:2, explanation:"Account opening triggers a CDD/CIP process, not typically an investigation. Investigations are triggered by indicators of suspicious activity: TMS alerts, law enforcement inquiries, referrals from business lines, adverse media, or 314(a) matches — all of which suggest existing or potential suspicious activity requiring analysis." },
  { id:6425, domain:3, domainName:D3, question:"'Typology-based scenarios' in transaction monitoring are designed to:", options:["Replace all rule-based monitoring with ML models","Identify specific patterns of transactions associated with known ML/TF methods — such as structuring, funnel accounts, or trade-based ML — as informed by FinCEN advisories, FATF typology reports, and law enforcement feedback","Apply to only high-risk customers","Be implemented identically at all financial institutions regardless of their specific business model"], answer:1, explanation:"Typology-based scenarios translate intelligence about real-world ML/TF methods into monitoring rules. When FinCEN issues an advisory about, e.g., ransomware payment typologies or real estate ML, institutions incorporate the identified patterns and red flags into their TMS scenarios." },
  { id:6426, domain:3, domainName:D3, question:"The role of 'compliance testing' in AML differs from 'independent audit' in that:", options:["Compliance testing is conducted by the compliance department to verify that controls are working as designed; independent audit provides an objective third-party assessment","Compliance testing is conducted by external auditors; independent audit is internal","Compliance testing focuses on SAR filings; independent audit focuses on CTR filings","There is no meaningful difference between compliance testing and independent audit"], answer:0, explanation:"Compliance testing (second line of defense) is ongoing — the compliance department tests its own controls, identifies weaknesses, and remediates. Independent audit (third line of defense) provides an objective, external-to-compliance assessment of whether the entire AML framework is adequate and effectively implemented." },
  { id:6427, domain:3, domainName:D3, question:"'Digital forensics' in AML investigations can be used to:", options:["Automatically file SARs based on digital evidence","Recover and analyze electronic evidence from computers, mobile devices, and cloud systems to support ML/TF investigation and prosecution","Block suspicious transactions in real time","Generate CTR reports from digital transaction data"], answer:1, explanation:"Digital forensics is increasingly essential in financial crime investigations — cybercriminals and sophisticated money launderers create electronic evidence (communications, transaction records, cryptocurrency wallet data, device forensics) that, when properly recovered and analyzed, can establish the full scope of the ML scheme." },
  { id:6428, domain:3, domainName:D3, question:"The 'investigative hypothesis' approach in AML analysis means:", options:["Assuming all customers are engaged in money laundering until proven otherwise","Developing a theory about the nature of suspicious activity and testing it systematically against available data before reaching a SAR filing conclusion","Filing a SAR immediately without further investigation when an alert is generated","Consulting with law enforcement to develop the investigative theory"], answer:1, explanation:"A structured analytical approach — form a hypothesis (is this structuring? Is this a money mule account? Is this TF-related?), then test it against available data (transaction patterns, customer profile, external information) — produces more rigorous, defensible SAR decisions than simply reacting to alerts without analysis." },
  { id:6429, domain:3, domainName:D3, question:"'Whistleblower information' received by a financial institution about a customer's potential ML activity should be:", options:["Disregarded as it is not generated by the institution's own AML systems","Evaluated as relevant intelligence that may inform an AML investigation and potential SAR filing, while protecting the whistleblower's identity","Immediately shared with the customer in question","Reported to regulators before being used to inform a SAR filing decision"], answer:1, explanation:"Third-party information — including from whistleblowers, tip lines, or referrals — is a legitimate and potentially valuable source of AML intelligence. It should be evaluated objectively, potentially investigated further, and considered alongside the institution's own data in SAR filing decisions." },
  { id:6430, domain:3, domainName:D3, question:"'Continuous transaction monitoring' differs from 'periodic batch monitoring' in that:", options:["Continuous monitoring monitors less frequent transaction types","Continuous monitoring screens transactions in real time as they occur; batch monitoring reviews transactions after the fact on a scheduled basis","Periodic batch monitoring is required by regulation; continuous monitoring is optional","There is no difference in effectiveness between the two approaches"], answer:1, explanation:"Real-time monitoring enables immediate alerts and potentially prevents suspicious transactions from completing. Batch monitoring (reviewing prior periods' transactions) is a retrospective approach that may miss time-sensitive activity. Most sophisticated AML programs combine both: real-time for high-risk scenarios, batch for pattern analysis." },
  { id:6431, domain:3, domainName:D3, question:"An AML analyst finds that a customer's international wire transfers consistently go to accounts in jurisdictions associated with trade-based ML. The BEST next step is:", options:["Immediately file a SAR without additional investigation","Close the account immediately","Investigate further — examining the customer's stated business, existing trade documentation, counterparty information, and whether the amounts and frequency are consistent with the customer's documented trade activity","Contact the receiving institution to request information about the beneficiary account"], answer:2, explanation:"A potential TBML pattern requires structured investigation — does the customer have documented trade relationships in those jurisdictions? Are the amounts consistent with their declared trade volume? Are the counterparties consistent with legitimate trade? Only after this investigation can a well-supported SAR decision be made." },
  { id:6432, domain:3, domainName:D3, question:"'Financial intelligence products' produced by FIUs for the private sector include:", options:["SAR data made available to financial institutions for customer screening","FinCEN Advisories, typology reports, and geographic targeting guidance that help institutions understand current ML/TF risks and calibrate their AML programs","Real-time alerts about suspicious customers identified by law enforcement","Access to classified intelligence about known money launderers"], answer:1, explanation:"FIUs produce public-facing intelligence products that help financial institutions understand and respond to ML/TF risks: FinCEN Advisories alert on specific typologies; typology reports document ML methods; GTOs target specific markets; and FinCEN's financial trend analyses share insights from SAR data analysis." },
  { id:6433, domain:3, domainName:D3, question:"'Transactional due diligence' (TDD) differs from 'customer due diligence' (CDD) in that:", options:["TDD is required only for cash transactions; CDD applies to all account relationships","TDD examines specific transactions (particularly high-value, unusual, or complex transactions) for ML/TF risk; CDD establishes an ongoing understanding of the customer's overall profile and relationship","TDD is conducted at account opening; CDD is ongoing","TDD is a regulatory requirement; CDD is a voluntary best practice"], answer:1, explanation:"TDD is transaction-specific due diligence — applied to specific high-risk, high-value, or unusual transactions (particularly in correspondent banking, trade finance, or private banking) to understand the purpose, parties, and legitimacy of the specific transaction, beyond what the customer's general profile provides." },
  { id:6434, domain:3, domainName:D3, question:"'Dark web' monitoring for AML purposes involves:", options:["Monitoring all customer internet activity for suspicious behavior","Using specialized tools to identify whether a customer's information appears in dark web criminal marketplaces — indicating they may be a victim of identity theft or an active participant in illicit online activity","Monitoring all cryptocurrency transactions involving dark web-associated addresses","Screening all customer email addresses against dark web databases"], answer:1, explanation:"Dark web monitoring is an emerging OSINT tool in AML — identifying whether customers appear in dark web forums, criminal marketplaces, or data breach compilations can reveal whether they are fraud victims (relevant for account takeover risk) or active participants in illicit online communities." },
  { id:6435, domain:3, domainName:D3, question:"A financial institution that fails to file a SAR for suspicious activity it detected may face consequences including:", options:["Only enhanced examination scrutiny in the next regulatory examination","Civil money penalties, reputational harm, potential criminal prosecution for willful failure, and regulatory enforcement actions","Only an informal letter of concern from its primary regulator","Only enhanced SAR filing requirements for the following year"], answer:1, explanation:"Willful failure to file SARs can result in: civil money penalties from FinCEN/regulators; criminal prosecution of the institution and responsible individuals; consent orders or cease-and-desist orders; reputational damage; and in extreme cases, loss of charter or correspondent banking relationships." },
  { id:6436, domain:3, domainName:D3, question:"'Post-SAR monitoring' refers to:", options:["Monitoring the status of SARs with FinCEN after filing","Continuing to monitor a customer's activity after a SAR has been filed, as suspicious activity may continue and additional SAR filings (continuations) may be required","Monitoring law enforcement's investigation following a SAR filing","Stopping all monitoring of a customer once a SAR has been filed"], answer:1, explanation:"Filing a SAR does not conclude the institution's AML obligations regarding the customer — the account may remain open, and suspicious activity may continue. Ongoing monitoring is required, with continuation SARs filed every 90 days as long as suspicious activity continues." },
  { id:6437, domain:3, domainName:D3, question:"The term 'suspicious activity' in AML contexts encompasses behavior that goes BEYOND merely illegal activity to include:", options:["Any customer behavior that the relationship manager finds unusual","Any activity that may involve funds from illegal sources, is designed to evade reporting requirements, or lacks a lawful purpose — even if no specific crime has yet been identified","Only activity that exceeds applicable reporting thresholds","Only activity involving foreign parties or accounts"], answer:1, explanation:"The SAR standard captures three distinct types of suspicious activity: (1) funds from illegal activity; (2) designed to evade BSA reporting; or (3) no lawful purpose and no reasonable explanation. This broad scope ensures institutions report beyond just obvious crimes to include suspicious regulatory evasion." },
  { id:6438, domain:3, domainName:D3, question:"'Sanctions compliance' intersects with AML compliance in that:", options:["They are entirely separate regulatory programs with no overlap","Both require ongoing screening of customers and transactions; sanctions violations may involve ML (moving sanctioned parties' assets); and sanctions evasion is a predicate offense for money laundering","Sanctions compliance eliminates the need for AML monitoring of sanctioned jurisdictions","AML compliance automatically satisfies all OFAC sanctions requirements"], answer:1, explanation:"Sanctions and AML are distinct but deeply interrelated. Both require robust screening programs. Sanctions violations (e.g., processing transactions for SDN-listed parties) may constitute ML; ML networks are often linked to sanctioned regimes; and evasion of sanctions is itself a federal crime whose proceeds constitute ML predicate offenses." },
  { id:6439, domain:3, domainName:D3, question:"'Regulatory technology' (RegTech) in AML refers to:", options:["Technology used exclusively by regulators to examine financial institutions","Technology solutions — including AI, machine learning, cloud computing, and advanced analytics — used by financial institutions to improve AML compliance efficiency and effectiveness","Software used to file SARs electronically with FinCEN","Technology that automatically generates SAR narratives without human review"], answer:1, explanation:"RegTech encompasses the technology solutions that help institutions comply with AML/CFT requirements more efficiently and effectively — from AI-powered TMS and KYC automation, to blockchain analytics, NLP for SAR narrative writing assistance, and cloud-based case management systems." },
  { id:6440, domain:3, domainName:D3, question:"'Network effects' in financial crime investigations refer to:", options:["The impact of social media networks on money laundering","The observation that criminal networks — once identified — reveal connected individuals, accounts, and transactions, enabling investigators to work 'outward' from an initial lead to map the full criminal enterprise","The spread of ML/TF typologies through international criminal networks","The competitive dynamics among money laundering organizations"], answer:1, explanation:"One of the most powerful investigation techniques is mapping the criminal network — each identified co-conspirator, shell company, or associated account potentially reveals more of the network. Sophisticated financial crime investigation systematically exploits these network effects to dismantle entire criminal organizations." },
  { id:6441, domain:3, domainName:D3, question:"'Model-based suspicious activity reporting' (as opposed to rule-based) uses:", options:["Predetermined fixed thresholds for all transaction types","Statistical and machine learning models that analyze patterns across many variables to identify outliers and likely suspicious activity","Regulatory model prescriptions for specific types of suspicious activity","Only behavioral analysis models without any rules-based components"], answer:1, explanation:"ML/AI models in AML monitoring analyze many variables simultaneously — customer history, peer group behavior, transaction characteristics, geographic patterns — to identify complex, non-obvious suspicious patterns that rules-based systems (designed for simple scenarios) cannot detect." },
  { id:6442, domain:3, domainName:D3, question:"When law enforcement contacts a financial institution 'informally' about a potential suspect prior to issuing legal process, the institution should:", options:["Immediately produce all account records and transaction history","Consult with legal counsel before sharing any customer information or account data, and direct law enforcement to the appropriate formal process for obtaining records","File a SAR on the customer before responding to law enforcement","Ignore the inquiry until formal legal process is served"], answer:1, explanation:"Privacy laws (Right to Financial Privacy Act, state equivalents) restrict voluntary disclosure of customer financial information. Absent legal process (subpoena, court order, NSL) or specific statutory exceptions, institutions should consult counsel and direct law enforcement to use appropriate formal channels to obtain records." },
  { id:6443, domain:3, domainName:D3, question:"The 'key risk indicators' (KRIs) for an AML program might include all of the following EXCEPT:", options:["SAR filing timeliness and quality","CTR exemption review completion rates","Alert-to-SAR conversion rate and false positive ratio","The BSA officer's personal investment portfolio performance"], answer:3, explanation:"AML KRIs measure program performance and risk exposure: SAR timeliness, quality, and count; CTR filing accuracy; alert productivity; training completion rates; EDD refresh completion; high-risk account review completion. The BSA officer's personal finances are irrelevant to program performance measurement." },
  { id:6444, domain:3, domainName:D3, question:"'De-anonymization' of cryptocurrency in AML investigations refers to:", options:["Converting cryptocurrency to cash","Using blockchain analytics tools and other investigative techniques to attribute pseudonymous blockchain addresses to real-world identities","Anonymizing criminal records related to cryptocurrency offenses","Converting private cryptocurrency to public blockchain records"], answer:1, explanation:"Blockchain analytics (e.g., Chainalysis, Elliptic, TRM Labs) cluster addresses, identify exchange interactions, and use on-chain and off-chain data to attribute blockchain addresses to real-world entities — supporting law enforcement and AML investigators in tracing cryptocurrency ML schemes." },
  { id:6445, domain:3, domainName:D3, question:"'ML/TF risk categorization' of products and services should consider:", options:["Only whether the product involves cash transactions","The product's anonymity features, delivery channels, customer base, geographic reach, and historical ML/TF typologies associated with similar products","Only the regulatory classification of the product","Only the transaction volume associated with the product"], answer:1, explanation:"Product risk assessment considers multiple dimensions: anonymity (can transactions be conducted without identification?); delivery channel (branch vs. digital vs. agent); customer base (retail vs. institutional); geography (domestic vs. cross-border); and known typologies (has this product been used in documented ML schemes?)." },
  { id:6446, domain:3, domainName:D3, question:"'Quality assurance' in AML SAR programs involves:", options:["Requiring all SAR filings to be approved by the board of directors","Systematically reviewing completed SARs and investigation decisions to identify patterns, errors, and opportunities for improvement in the SAR process","Requiring law enforcement to confirm that each SAR was useful before the next one is filed","Comparing the institution's SAR filing rate to industry benchmarks"], answer:1, explanation:"SAR QA programs review filed SARs and closed investigations to assess: narrative quality and completeness; accuracy of transaction data; timeliness of filing; consistency of decision-making; and whether the investigation process was thorough. Findings drive training and process improvement." },
  { id:6447, domain:3, domainName:D3, question:"'Financial investigation training' for law enforcement focused on AML should cover:", options:["Only CTR and SAR filing procedures","How to trace fund flows, use BSA data (FinCEN databases), understand ML typologies, work with financial institutions cooperatively, and build forfeiture cases","Only cryptocurrency investigation techniques","Only the legal standards for ML prosecution"], answer:1, explanation:"Effective financial investigation training equips law enforcement to: use FinCEN's BSA database; engage financial institutions effectively; trace funds through complex transaction patterns; understand corporate structures used for ML; build forfeiture cases; and work with FIUs internationally." },
  { id:6448, domain:3, domainName:D3, question:"'Cross-border wire transfer monitoring' in AML requires specific attention to:", options:["Only wire transfers over $10,000","All wire transfers regardless of amount — with particular attention to transfers involving high-risk jurisdictions, unusual counterparties, and patterns inconsistent with the customer's established business profile","Only wire transfers to sanctioned countries","Only wire transfers that are part of a correspondent banking relationship"], answer:1, explanation:"Cross-border wire monitoring should be comprehensive: all international wires (not just large ones) require scrutiny for OFAC compliance; TMS scenarios should flag patterns (frequency, amount, jurisdiction, counterparty) inconsistent with the customer's profile; and travel rule compliance must be maintained for covered transactions." },
  { id:6449, domain:3, domainName:D3, question:"'Account reconciliation' as an AML tool is used to:", options:["Verify the accuracy of customers' account statements","Reconcile an institution's internal transaction records with FinCEN's BSA filing records to ensure all required reports have been filed","Compare a customer's reported income with their account activity to identify unexplained discrepancies that may indicate unreported criminal income","Match wire transfer records with corresponding trade documentation to identify TBML"], answer:2, explanation:"Income reconciliation — comparing a customer's documented income (tax returns, pay stubs, financial statements) with their account activity — is a key EDD and investigation tool. Significant unexplained discrepancies between documented income and deposited/withdrawn funds suggest criminal income being laundered." },
  // Domain 4 exam 4 (31 questions)
  { id:6450, domain:4, domainName:D4, question:"The 'Bank Secrecy Act' was enacted to:", options:["Protect customer financial information from government access","Require financial institutions to create records and file reports useful to law enforcement in detecting and preventing money laundering, tax evasion, and other financial crimes","Establish deposit insurance for bank customers","Create the Federal Reserve System's regulatory authority over banks"], answer:1, explanation:"The BSA (1970) recognized that financial institutions' records could be valuable law enforcement tools — and required institutions to maintain records and file reports that give investigators a 'paper trail' for financial crimes. Despite its name, it does not create bank secrecy; it creates a framework for financial transparency to government." },
  { id:6451, domain:4, domainName:D4, question:"'Horizontal enforcement' in AML refers to:", options:["Enforcing AML requirements across multiple jurisdictions simultaneously","Holding all levels of an institution — from front-line employees to senior management and the board — accountable for AML failures, not just the compliance department","Enforcing AML requirements across an entire industry sector simultaneously","Requiring all financial institutions to apply identical AML standards"], answer:1, explanation:"Horizontal enforcement holds institutions accountable at every level — recent DOJ/OCC emphasis on individual accountability means that senior executives, not just institutions, may face personal consequences for willful AML failures. This creates incentive for genuine cultural compliance, not just paper compliance." },
  { id:6452, domain:4, domainName:D4, question:"'Supervisory colleges' for AML purposes involve:", options:["Training seminars for financial institution compliance officers","Forums where regulators from multiple jurisdictions coordinate their supervision of global financial institutions, sharing information and aligning supervisory approaches","Colleges and universities that offer AML compliance certification programs","Groups of senior compliance officers who share best practices"], answer:1, explanation:"Supervisory colleges bring together regulators from different countries who supervise the same global financial institution — enabling information sharing, coordination of examination approaches, and joint assessment of group-wide AML risk. This addresses the challenge of supervising institutions that operate across multiple regulatory jurisdictions." },
  { id:6453, domain:4, domainName:D4, question:"'AML task forces' that combine law enforcement, intelligence, and regulatory agencies are effective because:", options:["They eliminate the need for financial institutions to file SARs","They pool different agencies' intelligence, legal authorities, and expertise — enabling more comprehensive investigations than any single agency could conduct alone","They provide financial institutions with real-time alerts about subjects under investigation","They are authorized to directly access financial institutions' systems without a subpoena"], answer:1, explanation:"Multi-agency task forces (e.g., the OCDETF fusion center, FinCEN's liaison with DEA/FBI/HSI) pool each agency's unique authorities, intelligence, and expertise. Law enforcement has investigative authority; intelligence agencies have foreign intelligence; regulators have supervisory access — together they can tackle complex international ML networks more effectively." },
  { id:6454, domain:4, domainName:D4, question:"The 'three lines of defense' model in AML assigns which responsibility to the THIRD line?", options:["Business units identifying and escalating suspicious activity","The AML compliance department developing policies and monitoring transactions","Internal audit independently assessing the effectiveness of the AML program and controls","External regulators examining the institution's AML program"], answer:2, explanation:"The three lines: First = business lines (own the risk, implement controls); Second = compliance (develop policies, monitoring, oversight); Third = internal audit (independent testing of both first and second lines). External regulators are not a 'line of defense' — they are the external accountability mechanism." },
  { id:6455, domain:4, domainName:D4, question:"'Consent to forfeiture' in ML cases refers to:", options:["A criminal suspect voluntarily agreeing to forfeit criminal assets as part of a plea agreement","A financial institution agreeing to have customer funds forfeited without the customer's authorization","The government agreeing to return forfeited assets to the criminal","A court agreeing to forfeiture without a jury trial"], answer:0, explanation:"In many ML plea agreements, defendants consent to the forfeiture of specified assets — acknowledging that those assets represent proceeds or instrumentalities of the criminal offense. This waiver of contest accelerates asset recovery and is a key negotiating point in ML resolution." },
  { id:6456, domain:4, domainName:D4, question:"'Letters rogatory' are MOST commonly used when:", options:["A country is a signatory to an MLAT and a more formal process is preferred","There is no MLAT with the relevant foreign country, requiring use of diplomatic channels to request judicial assistance","A country refuses to cooperate with informal law enforcement requests","Criminal charges have already been filed in the requesting country"], answer:1, explanation:"Letters rogatory are the alternative when no MLAT exists — they are slower (months to years) and depend on the foreign court's discretion about whether to assist. Countries with MLATs or other bilateral agreements provide faster, more reliable mutual legal assistance." },
  { id:6457, domain:4, domainName:D4, question:"The 'Proceeds of Crime' concept under FATF requires that AML measures apply to:", options:["Only proceeds from drug trafficking","All proceeds from FATF-designated predicate offenses, regardless of which specific crime generated the proceeds","Only proceeds exceeding $10,000 in value","Only proceeds held in bank accounts"], answer:1, explanation:"Modern ML law and FATF standards apply broadly — any proceeds from any designated predicate offense (not just drugs) are subject to ML prosecution if subjected to a financial transaction designed to conceal their criminal origin. This broad scope reflects the diversity of criminal enterprises that generate laundered funds." },
  { id:6458, domain:4, domainName:D4, question:"'Civil forfeiture' is particularly useful in ML cases when:", options:["The criminal has already been convicted","A prosecution is not feasible (insufficient evidence for criminal charges, subject is deceased, or subject is a fugitive outside U.S. jurisdiction), but sufficient evidence exists to connect specific property to criminal activity","The criminal has voluntarily returned stolen assets","The property to be forfeited is worth less than $50,000"], answer:1, explanation:"Civil forfeiture's in rem nature (against the property, not a person) enables asset recovery without a criminal conviction — useful when: the criminal is dead, fled, or immune from prosecution; evidence is insufficient for prosecution; or property has been transferred to third parties who cannot be criminally charged." },
  { id:6459, domain:4, domainName:D4, question:"'Pre-conviction restraint orders' in international ML cases serve to:", options:["Prevent suspects from leaving the country during an investigation","Freeze assets to prevent dissipation while the case is pending, ensuring they are available for forfeiture if the defendant is convicted","Force defendants to disclose all their assets to the court","Prevent financial institutions from engaging with suspected money launderers"], answer:1, explanation:"Pre-conviction restraint is essential in complex ML cases — without it, sophisticated criminals can quickly transfer, spend, or hide assets during the investigation period. MLATs enable the U.S. to request foreign jurisdictions to issue restraining orders against assets held abroad while the U.S. case proceeds." },
  { id:6460, domain:4, domainName:D4, question:"The 'Egmont Group' information sharing protocols require that exchanged FIU information:", options:["Be immediately shared with the media to deter money laundering","Be used only for the authorized purpose stated in the request, be protected from unauthorized disclosure, and be subject to the same confidentiality protections as domestically generated financial intelligence","Be made available to any requesting government agency","Be shared with all Egmont Group member FIUs simultaneously"], answer:1, explanation:"Egmont information sharing is highly controlled — the Egmont Principles establish strict 'use' and 'confidentiality' rules. Information received from a foreign FIU cannot be used for purposes other than those stated in the request, and cannot be further disseminated (e.g., to prosecutors or police) without prior consent from the providing FIU." },
  { id:6461, domain:4, domainName:D4, question:"'Non-conviction based asset forfeiture' (NCB forfeiture) is significant for international ML asset recovery because:", options:["It is recognized by all countries and automatically enforceable internationally","It allows recovery of criminal assets even without a criminal conviction — particularly useful when suspects are in different jurisdictions or have died","It eliminates due process requirements for suspected criminals","It requires no judicial involvement"], answer:1, explanation:"NCB forfeiture (similar to U.S. civil forfeiture) is a tool being adopted by more countries (encouraged by FATF Recommendation 4) — it enables recovery of criminal assets without requiring a criminal conviction, which is particularly valuable when: suspects are beyond jurisdiction; prosecuting in multiple jurisdictions; or assets have been transferred to third parties." },
  { id:6462, domain:4, domainName:D4, question:"A 'concurrent investigation' involving both AML and tax evasion charges benefits from:", options:["Combining the investigations into a single case and charging both offenses together","The IRS-CI and DOJ's ability to combine financial investigation expertise, with ML charges providing broader forfeiture authority while tax charges provide additional evidence of unexplained income","Automatically resolving both charges through a single plea agreement","Sharing all grand jury evidence between the investigations immediately"], answer:1, explanation:"Combined ML and tax investigations leverage complementary authorities — tax charges can be proven using indirect methods (net worth, expenditure analysis) that establish criminal income, while ML charges allow broader asset forfeiture and higher penalties. IRS-CI and DOJ frequently work these cases together." },
  { id:6463, domain:4, domainName:D4, question:"'Asset recovery' returned to victim countries is prioritized under:", options:["The FATF 40 Recommendations which require all recovered assets to be returned","The Merida Convention (UNCAC) and various bilateral agreements, which encourage returning assets stolen from foreign governments to those governments","U.S. domestic forfeiture law which automatically returns all forfeited assets abroad","FinCEN regulations requiring victim country notification for all international forfeiture actions"], answer:1, explanation:"The UN Convention Against Corruption (UNCAC/Merida Convention) includes specific provisions on asset recovery and return — recognizing that assets stolen from foreign governments belong to those countries' citizens. The DOJ's Kleptocracy Asset Recovery Initiative specifically focuses on this." },
  { id:6464, domain:4, domainName:D4, question:"'Proactive financial investigation' differs from 'reactive financial investigation' in that:", options:["Proactive investigation involves going to trial; reactive settles cases","Proactive investigation identifies and acts on ML/TF patterns before they become larger scale or before the predicate offense has been fully completed; reactive investigation responds to identified crime after it occurs","Proactive investigation uses only open-source intelligence; reactive uses court-ordered process","There is no meaningful difference between proactive and reactive financial investigation"], answer:1, explanation:"Proactive investigations — identifying and disrupting ML networks before they cause maximum harm — are increasingly prioritized. This requires sophisticated intelligence work: pattern analysis, FIU intelligence, SAR data analytics, and international cooperation, often identifying criminal activity before traditional law enforcement methods would." },
  { id:6465, domain:4, domainName:D4, question:"The 'Racketeer Influenced and Corrupt Organizations Act' (RICO) and ML charges are often combined in organized crime prosecutions because:", options:["RICO and ML charges are mutually exclusive — prosecutors choose one or the other","RICO establishes the criminal enterprise/pattern, while ML charges address how the proceeds were laundered — together enabling prosecution of the entire criminal organization and comprehensive asset forfeiture","RICO automatically includes ML charges for all drug trafficking cases","ML charges are easier to prove than RICO charges"], answer:1, explanation:"RICO (18 U.S.C. § 1961-1968) enables prosecution of the criminal organization as a whole, with forfeiture of the organization's assets. ML charges (§ 1956-1957) address the financial movement of criminal proceeds. Together they provide comprehensive coverage of organized crime's criminal conduct AND its financial infrastructure." },
  { id:6466, domain:4, domainName:D4, question:"An 'independent AML compliance monitor' appointed following a major enforcement action typically:", options:["Has authority to override the institution's management decisions on compliance matters","Reports to the relevant government authority on the institution's progress in implementing required AML remediation — serving as the government's eyes and ears inside the institution","Conducts law enforcement investigations using the institution's internal systems","Replaces the institution's BSA officer during the monitorship period"], answer:1, explanation:"Compliance monitors (formerly called 'bank examiners-in-residence') report to the government (DOJ, OCC, or FinCEN) rather than the institution — providing independent assessment of whether the institution is genuinely implementing required remediation. They serve as the oversight mechanism ensuring that enforcement commitments are actually fulfilled." },
  { id:6467, domain:4, domainName:D4, question:"'Financial investigation' of an ML suspect typically begins with:", options:["Requesting all bank records via subpoena","Identifying all known financial accounts and building a comprehensive picture of financial activity, then tracing anomalies between documented income and actual assets/expenditures","Filing criminal charges based on suspicious activity alone","Consulting with a forensic accountant to determine the total amount laundered"], answer:1, explanation:"Financial investigations start with intelligence gathering — identifying all financial footprints (accounts, property, vehicles, businesses), then building a comprehensive financial picture. The discrepancy between documented legitimate income and actual assets/expenditures provides the foundation for indirect proof of criminal income." },
  { id:6468, domain:4, domainName:D4, question:"'Grand jury secrecy rules' in ML cases mean that:", options:["All grand jury proceedings are open to the public","Grand jury materials — testimony, documents, and deliberations — are confidential and generally cannot be disclosed outside the proceedings without court authorization","Financial institutions are required to notify their customers when grand jury subpoenas are received","Grand jury proceedings are only available for domestic ML cases, not international ones"], answer:1, explanation:"Federal Rule of Criminal Procedure 6(e) imposes strict secrecy on grand jury proceedings — the government, witnesses, and recipients of grand jury subpoenas are all restricted from disclosing grand jury matters without court authorization. Financial institutions must comply with grand jury subpoenas while generally maintaining confidentiality about having received them." },
  { id:6469, domain:4, domainName:D4, question:"'Enterprise-wide enforcement' against financial institutions for AML failures means:", options:["The enforcement action applies to every branch of the institution globally","Enforcement authorities hold the entire institution responsible for systemic AML failures — not just specific individuals or business lines — including its governance, culture, systems, and management oversight","Enforcement applies only to the parent company, not its subsidiaries","Enforcement is limited to the specific transactions that violated AML requirements"], answer:1, explanation:"Enterprise-wide enforcement reflects the principle that systemic AML failures are institutional failures — of governance, culture, risk management, and oversight — not just individual misconduct. Major enforcement actions against HSBC, Standard Chartered, and others established this principle clearly." },
  { id:6470, domain:4, domainName:D4, question:"'Victims of ML' may include:", options:["Only the government agencies that fail to detect the ML activity","The communities harmed by the predicate crimes that generate the proceeds, as well as legitimate businesses harmed by competition from criminal enterprises that can underprice them using laundered proceeds","Only the direct victims of the predicate offense","Only financial institutions that unknowingly process ML transactions"], answer:1, explanation:"ML's harm is broad — it perpetuates criminal enterprises (drug trafficking, human trafficking, corruption) by ensuring criminals profit from crime, harms communities through associated criminal activity, distorts markets (legitimate businesses cannot compete with money-laundering 'businesses' that don't need to profit), and corrupts institutions." },
  { id:6471, domain:4, domainName:D4, question:"The 'forfeiture ratio' (forfeited assets as a percentage of estimated criminal proceeds) remains low globally because:", options:["Most countries have no forfeiture laws","Criminals are sophisticated in hiding assets across multiple jurisdictions using complex corporate structures, making full recovery difficult despite significant law enforcement effort","Law enforcement rarely pursues asset recovery","Most ML involves amounts too small to warrant asset forfeiture proceedings"], answer:1, explanation:"Despite significant investment in financial investigation and international cooperation, the UNODC estimates that less than 1% of criminal proceeds are seized or frozen globally. The gap reflects the sophistication of criminal financial structures, jurisdictional challenges, and resource limitations in asset recovery." },
  { id:6472, domain:4, domainName:D4, question:"'Financial crimes enforcement' in the United States involves which COMBINATION of agencies?", options:["FinCEN alone","FinCEN (rule-writing and intelligence), DOJ (prosecution), federal banking regulators (AML supervision), and law enforcement agencies (investigation)","DOJ and FinCEN only","The Treasury Department, through OFAC, alone"], answer:1, explanation:"U.S. AML/financial crime enforcement is a complex ecosystem: FinCEN writes rules and provides financial intelligence; DOJ prosecutes; OCC, Fed, FDIC, NCUA supervise for BSA compliance; IRS-CI, FBI, DEA, HSI investigate; OFAC enforces sanctions. Effective AML requires all these components working together." },
  { id:6473, domain:4, domainName:D4, question:"'Technical compliance' vs. 'effective compliance' in FATF evaluations means:", options:["Technical compliance measures policies on paper; effective compliance measures actual outcomes in preventing and detecting ML/TF","Technical compliance applies to technology requirements; effective compliance applies to human procedures","Technical compliance is evaluated by FATF; effective compliance is evaluated by national authorities","There is no distinction — FATF evaluates only technical compliance"], answer:0, explanation:"FATF's dual-component evaluation framework assesses: (1) Technical compliance — does the country have the laws, regulations, and institutions required by the 40 Recommendations? And (2) Effectiveness — is the AML/CFT system actually achieving the intended outcomes (Immediate Outcomes)? A country can be technically compliant but ineffective." },
  { id:6474, domain:4, domainName:D4, question:"A 'financial intelligence cell' within a law enforcement agency is responsible for:", options:["Filing SARs on behalf of financial institutions that lack AML programs","Analyzing financial intelligence (BSA data, SARs, bank records) to identify criminal networks, develop investigative leads, and support prosecutions","Regulating financial institutions for BSA compliance","Conducting anti-corruption investigations of financial institution employees"], answer:1, explanation:"Financial intelligence cells (staffed by financial analysts, forensic accountants, and intelligence specialists) are dedicated to extracting maximum value from financial intelligence data — FinCEN's BSA database, SAR narratives, bank records, and other financial information — to support active investigations and generate new leads." },
  { id:6475, domain:4, domainName:D4, question:"'Criminal enterprise' forfeiture under RICO enables:", options:["Forfeiture of only the specific property directly used in the commission of the crime","Forfeiture of all interests in the enterprise, any proceeds from racketeering, and any property used or intended to be used to facilitate the racketeering — providing much broader forfeiture than individual ML charges alone","Forfeiture only upon conviction of all members of the enterprise","Automatic forfeiture of all assets of anyone convicted of an associated crime"], answer:1, explanation:"RICO forfeiture (18 U.S.C. § 1963) is exceptionally broad — it reaches the entire criminal enterprise and all racketeering-derived proceeds, not just the specific criminal transactions proven in court. This makes RICO an extraordinarily powerful tool for dismantling criminal organizations and recovering their accumulated wealth." },
  { id:6476, domain:4, domainName:D4, question:"'AML fines and penalties' assessed against financial institutions serve all of the following purposes EXCEPT:", options:["Deterring future AML violations by the institution and the industry","Remedying harms caused by the institution's AML failures to government agencies and victims","Providing direct financial compensation to ML victims","Creating incentive for institutions to invest appropriately in AML compliance"], answer:2, explanation:"Civil money penalties go to the U.S. Treasury (or supervising agency), not to victims of the underlying crimes. Victim compensation — where available — comes from restitution orders in criminal proceedings or civil litigation. AML penalties serve deterrence and regulatory functions, not victim compensation." },
  { id:6477, domain:4, domainName:D4, question:"'Correspondent banking termination' as an AML enforcement tool means:", options:["The correspondent bank files SARs on all the respondent bank's customers","The correspondent bank closes the respondent bank's account — cutting off the respondent bank's access to U.S. dollar clearing and international financial services","FinCEN terminates the correspondent bank's BSA registration","The correspondent bank transfers the respondent bank's assets to OFAC"], answer:1, explanation:"Terminating a correspondent account is one of the most powerful AML enforcement tools available — it effectively cuts the respondent bank off from the U.S. dollar financial system. Section 319(b) of the PATRIOT Act provides specific authority to require termination of accounts for foreign shell banks and other high-risk entities." },
  { id:6478, domain:4, domainName:D4, question:"A financial institution subject to a 'monitoring order' from a banking regulator must:", options:["File a SAR for every transaction conducted during the monitoring period","Report regularly on its AML program implementation and specific compliance metrics to the regulator during the monitoring period","Allow regulators unrestricted access to all customer accounts","Suspend new customer account openings during the monitoring period"], answer:1, explanation:"Monitoring orders typically require regular (often monthly or quarterly) reporting to the regulator on the institution's progress in implementing required AML remediation — providing the regulator with ongoing visibility into the institution's compliance trajectory without requiring constant on-site examination." },
  { id:6479, domain:4, domainName:D4, question:"'Equitable sharing' in federal asset forfeiture refers to:", options:["Dividing forfeited assets equally between federal and state prosecutors","The DOJ/Treasury program that shares a portion of federally forfeited assets with state and local law enforcement agencies that participated in the investigation, incentivizing cooperation","Returning an equal share of forfeited assets to ML victims","Sharing forfeited assets equally between the prosecuting agency and the courts"], answer:1, explanation:"Equitable sharing encourages federal-state-local law enforcement cooperation on ML cases — state and local agencies that participate in federal investigations receive a share of resulting forfeitures, providing a financial incentive for the multi-agency cooperation that complex ML cases require." },
  { id:6480, domain:4, domainName:D4, question:"The 'deterrence effect' of AML enforcement is MOST effectively achieved through:", options:["Maximizing the number of SAR filings","Consistent, predictable enforcement of AML requirements — with penalties proportionate to violations — creating a credible expectation that AML failures will be detected and punished","Publicly naming individuals involved in money laundering","Reducing AML compliance requirements to make compliance more feasible"], answer:1, explanation:"Deterrence theory holds that penalties deter when: (1) they are certain (violations will be detected); (2) they are swift (consequences follow promptly); and (3) they are severe (proportionate to the harm). Consistent, credible enforcement — more than the size of any individual penalty — creates the most effective deterrence." },
];

// ═══════════════════════════════════════════════════════════════════════════
// EXAM 5  (IDs 6481–6600)
// ═══════════════════════════════════════════════════════════════════════════
const exam5: ExamQuestion[] = [
  { id:6481, domain:1, domainName:D1, question:"The 'Strasbourg Convention' (1990) on ML was significant because:", options:["It was the first international convention to criminalize money laundering","It required signatory countries to make money laundering a criminal offense beyond drug trafficking and to assist each other in ML investigations and asset recovery","It established FATF as the global AML standard setter","It created the Egmont Group of financial intelligence units"], answer:1, explanation:"The Council of Europe's Strasbourg Convention on Laundering, Search, Seizure and Confiscation of the Proceeds from Crime (1990) expanded the ML offense beyond drugs, required criminalization of ML, and provided a framework for international cooperation in asset recovery — a significant step in the evolution of international AML law." },
  { id:6482, domain:1, domainName:D1, question:"'Trade mispricing' in TBML encompasses:", options:["Only over-invoicing of imported goods","Both over-invoicing and under-invoicing of goods and services in international trade to facilitate value transfer between countries disguised as commercial transactions","Only under-invoicing of exported goods","Trade finance fraud targeting letters of credit"], answer:1, explanation:"TBML mispricing can go in either direction: over-invoicing the importer pays more than goods are worth (transfers value to exporter's country); under-invoicing the importer pays less (transfers value to importer's country). The direction depends on where the criminal wants to move value." },
  { id:6483, domain:1, domainName:D1, question:"'High-risk geographies' in AML include jurisdictions identified by:", options:["Only the FATF grey and black lists","FATF evaluations, OFAC sanctions programs, Transparency International CPI, State Department country reports, the Basel AML Index, and other credible public sources","Only the OFAC sanctions lists","Only the institution's own internal risk assessments"], answer:1, explanation:"No single source is sufficient — high-risk geography assessment should draw on multiple inputs: FATF status; sanctions programs (OFAC, UN, EU); corruption indices (TI CPI); banking secrecy strength; quality of law enforcement; drug trafficking routes; terrorism risk; and the institution's own experience with the jurisdiction." },
  { id:6484, domain:1, domainName:D1, question:"'Know your business' (KYB) in AML refers to:", options:["Understanding a financial institution's own internal business lines for AML purposes","The process of understanding a business customer's industry, ownership, operations, financial history, and expected transaction behavior as part of CDD for legal entity customers","Requiring business customers to provide annual financial statements","Verifying that a business customer's stated purpose matches their actual transactions"], answer:1, explanation:"KYB extends KYC principles to legal entity customers — understanding not just who owns and controls the entity, but what the business actually does, how it generates revenue, where it operates, who its customers are, and what its expected transaction profile looks like. This forms the baseline for ongoing transaction monitoring." },
  { id:6485, domain:1, domainName:D1, question:"Which characteristic is MOST associated with 'funnel account' schemes?", options:["Large, infrequent transactions from a single source","Numerous small deposits from multiple, often unrelated sources followed by rapid outbound transfers","Consistent, predictable transaction patterns matching the customer's business profile","Deposits that consistently match the customer's documented income"], answer:1, explanation:"Funnel accounts are designed to aggregate illicit cash from multiple sources (smurfs, criminal collaborators, money mules), then transfer the consolidated funds elsewhere quickly. The combination of: many diverse depositors; irregular amounts; and rapid outbound transfers after consolidation is the classic funnel account signature." },
  { id:6486, domain:1, domainName:D1, question:"'Layering through real estate renovation' involves:", options:["Paying contractors with illicit cash for renovation work that is never actually performed, creating inflated cost records that explain the injection of illicit funds into the property","Laundering money through legitimate real estate renovation projects","Using real estate renovation permits as false trade documents","Avoiding property taxes through renovation cost overstatements"], answer:0, explanation:"Renovation-based ML: illicit cash pays contractors (often complicit) who do little or no work, with false invoices creating records showing high renovation costs. When the property is sold, the inflated cost reduces taxable gains, and the 'renovation costs' become an explanation for the cash expenditure." },
  { id:6487, domain:1, domainName:D1, question:"FATF Recommendation 16 (the Wire Transfer or Travel Rule) requires:", options:["All wire transfers to be reported to FIUs","Wire transfers over applicable thresholds to include originator and beneficiary information transmitted with the funds throughout the payment chain","Wire transfers under $3,000 to be exempt from all AML requirements","Only international wire transfers to include identifying information"], answer:1, explanation:"The Travel Rule requires originating institutions to collect and include originator/beneficiary information with wire transfers at or above $3,000 (domestic US) or above threshold (FATF $1,000 international), and for all institutions in the payment chain to pass this information through — enabling tracing of transfers." },
  { id:6488, domain:1, domainName:D1, question:"'Environmental crime money laundering' is an emerging AML concern because:", options:["Environmental crimes do not generate significant criminal proceeds","Environmental crime generates hundreds of billions annually and ML proceeds must flow through the financial system; FATF has identified it as a priority area requiring enhanced FI attention","Environmental ML only occurs in developing countries","Environmental crime is exclusively addressed by environmental regulators, not AML authorities"], answer:1, explanation:"Environmental crime (illegal mining, logging, wildlife trafficking, waste dumping) generates massive illicit proceeds. FATF's 2021 report highlighted environmental crime ML as a priority — financial institutions must develop typology awareness and monitoring scenarios specific to this growing area of financial crime." },
  { id:6489, domain:1, domainName:D1, question:"'Human trafficking red flags' in banking include:", options:["A customer who owns multiple vehicles","Frequent hotel or motel payments in multiple cities, multiple persons using the same account, cash deposits inconsistent with stated employment, and evidence of controlling third parties in account transactions","A customer who frequently travels for business","A young customer without an established banking history"], answer:1, explanation:"Human trafficking financial signatures are distinctive: cash-intensive transactions in predictable patterns (hotel payments in vice-crime areas, grooming purchases), multiple victims using the same or similar accounts, a controller receiving funds from multiple individuals, and transaction patterns inconsistent with the victim's stated employment or demographics." },
  { id:6490, domain:1, domainName:D1, question:"'Beneficial ownership transparency' reforms globally have been driven PRIMARILY by:", options:["Financial institutions voluntarily improving their CDD practices","FATF standards, the G20's transparency agenda, national legislation (UK People with Significant Control register, U.S. Corporate Transparency Act), and EU Anti-Money Laundering Directives requiring public or government-accessible beneficial ownership registries","UN Security Council Resolution 1617 requiring beneficial ownership disclosure","The Basel Committee on Banking Supervision requiring beneficial ownership for capital adequacy purposes"], answer:1, explanation:"Global beneficial ownership transparency has been driven by: FATF Recommendations 24/25; G20 political commitments; EU's AML directives (including the 5th AMLD requiring public registers); individual countries' legislation (UK, Australia, EU members, and now the U.S. CTA). These reforms collectively are creating an international architecture for corporate transparency." },
  { id:6491, domain:1, domainName:D1, question:"'Ghost employees' as a money laundering technique involves:", options:["Companies hiring non-existent employees and paying their 'salaries' from illicit funds — creating payroll records that explain the cash expenditure","Using deceased persons' identities to open bank accounts","Hiring employees who are unaware that their payroll is funded with criminal proceeds","Creating fictitious employee expense reports to extract cash from corporate accounts"], answer:0, explanation:"Ghost employee schemes create fictitious payroll to absorb illicit cash — the criminal pays 'wages' to non-existent employees (or to complicit individuals who return the cash), generating payroll records and bank transfers that appear to be legitimate business expenses." },
  { id:6492, domain:1, domainName:D1, question:"'DeFi' (decentralized finance) platforms present novel AML challenges because:", options:["DeFi platforms are exclusively regulated by state banking authorities","DeFi platforms may operate without a central entity subject to KYC/AML requirements, potentially creating unregulated channels for value transfer and exchange","All DeFi transactions are automatically reported to FinCEN","DeFi platforms only process transactions under the SAR threshold"], answer:1, explanation:"DeFi protocols — automated smart contract-based financial services without centralized intermediaries — may not have a defined entity responsible for AML compliance. This creates regulatory gap questions: who is the 'financial institution' required to comply with KYC/AML? FATF and national regulators are grappling with this challenge." },
  { id:6493, domain:1, domainName:D1, question:"'Art market' vulnerabilities for money laundering include:", options:["All art transactions are conducted through regulated financial institutions that apply KYC","Subjective valuation, anonymous sales, high-value portable assets, limited beneficial ownership disclosure, and historically minimal AML regulation in many jurisdictions","Art cannot be used for ML because it is illiquid","Art dealers are required to file SARs for all cash transactions over $10,000"], answer:1, explanation:"The art market has been a well-documented ML vehicle: a Monet can be bought for millions in cash with limited questions asked; subjective valuation makes price manipulation easy; it can be stored in free ports with complete anonymity; and until recently, the sector faced minimal AML regulation globally." },
  { id:6494, domain:1, domainName:D1, question:"'Politically motivated financial crime' differs from traditional ML in that:", options:["Politically motivated financial crime involves smaller amounts","The motivation is political power or destabilization, not personal enrichment — though the financial techniques used (money laundering, sanctions evasion) may be identical","Politically motivated financial crime never involves organized crime","Traditional ML always involves political motivations"], answer:1, explanation:"State-sponsored financial crime, kleptocracy, and sanctions evasion may be motivated by geopolitical goals rather than personal enrichment — though the financial techniques are identical. Recognizing the political motivation context helps explain why seemingly irrational financial schemes may actually serve strategic objectives." },
  { id:6495, domain:1, domainName:D1, question:"'NFTs' (non-fungible tokens) are a potential ML vehicle because:", options:["NFTs are regulated as securities and subject to full KYC requirements","NFTs can be bought and sold with cryptocurrency, potentially without meaningful KYC, and their subjective valuation makes price manipulation easy — mirroring the art market ML typologies","NFT transactions are automatically reported to FinCEN","NFTs can only be purchased with fiat currency through regulated financial institutions"], answer:1, explanation:"NFTs exhibit similar characteristics to traditional art for ML purposes: high-value items that can be purchased with cryptocurrency; subjective valuation enabling price manipulation; limited KYC requirements on many NFT platforms; and the ability to move value globally with apparent legitimacy through 'NFT sales.'" },
  { id:6496, domain:1, domainName:D1, question:"'Sanctions evasion' techniques MOST commonly used by state actors include:", options:["Direct transactions through U.S. correspondent banking systems","Use of front companies in third countries, currency substitution (using currencies other than USD to avoid SWIFT), anonymous cryptocurrency transactions, and strategic use of jurisdictions with weak sanctions enforcement","Depositing funds directly into U.S. bank accounts in the sanctioned official's name","Requesting OFAC exemptions through diplomatic channels"], answer:1, explanation:"Sophisticated state-level sanctions evasion exploits multiple vulnerabilities: front companies in non-sanctioned jurisdictions; correspondent banking through third-country intermediaries; avoiding USD transactions to bypass SWIFT; using cryptocurrency; and exploiting jurisdictions with limited sanctions enforcement capacity." },
  { id:6497, domain:1, domainName:D1, question:"'Privacy coins' (such as Monero) present greater ML risk than Bitcoin because:", options:["Privacy coins are worth more than Bitcoin","Privacy coins are legal in more jurisdictions than Bitcoin","Privacy coins use cryptographic techniques (ring signatures, stealth addresses, ZK-proofs) that make transactions essentially untraceable — unlike Bitcoin's pseudonymous but analyzable blockchain","Privacy coins are exclusively used by criminal organizations"], answer:2, explanation:"Bitcoin's blockchain is pseudonymous but publicly auditable — blockchain analytics can trace transactions with reasonable effectiveness. Privacy coins use advanced cryptography to make transactions genuinely anonymous: ring signatures obscure senders, stealth addresses hide recipients, and confidential transactions hide amounts. This makes forensic tracing much more difficult." },
  { id:6498, domain:1, domainName:D1, question:"The 'travel rule' applied to virtual assets under FATF Recommendation 16 requires VASPs to transmit:", options:["Only the sender's name for virtual asset transfers","Originator and beneficiary identifying information for virtual asset transfers above the applicable threshold, similar to requirements for traditional wire transfers","All virtual asset transfer information to FIUs in real time","Identifying information only when funds are converted to fiat currency"], answer:1, explanation:"FATF extended the Travel Rule to virtual assets (updated Recommendation 16 in 2019) — requiring VASPs to collect, transmit, and screen originator and beneficiary information for VA transfers at or above the applicable threshold, creating accountability similar to traditional wire transfers." },
  { id:6499, domain:1, domainName:D1, question:"'Ransomware payment processing' creates AML risk for financial institutions because:", options:["All ransomware payments are automatically exempt from CTR requirements","Financial institutions that process ransomware payments may be facilitating payments to sanctioned actors and laundering criminal extortion proceeds","Ransomware payments are classified as legitimate insurance claims and are exempt from AML reporting","Ransomware payments under $10,000 are exempt from SAR filing requirements"], answer:1, explanation:"Ransomware payments create dual AML exposures: (1) potential OFAC violations if the ransomware group is sanctioned (OFAC has designated several ransomware groups); and (2) potential ML exposure for facilitating payment of extortion proceeds. FinCEN issued advisories specifically addressing ransomware ML risk." },
  { id:6500, domain:1, domainName:D1, question:"'Crypto-to-crypto' swaps on decentralized exchanges (DEXs) are a ML concern because:", options:["DEXs are required to maintain comprehensive KYC on all users","DEXs may operate without a central entity subject to AML requirements, allowing users to swap between cryptocurrencies without identity verification, potentially evading detection","All DEX transactions are monitored by FinCEN in real time","Crypto-to-crypto swaps are automatically taxable events that create reporting requirements"], answer:1, explanation:"DEXs operate through autonomous smart contracts without centralized intermediaries. This means: no single entity is responsible for KYC; users can swap tokens pseudonymously; and the ML typology involves converting traced cryptocurrency into different, potentially less-monitored tokens — complicating forensic investigation." },
  { id:6501, domain:1, domainName:D1, question:"'Transaction structuring' through multiple accounts at different banks is MOST effectively detected by:", options:["Each individual bank using its own monitoring for sub-threshold transactions","Information sharing between financial institutions (e.g., under 314(b)) and cross-industry reporting analysis by FinCEN using SAR data to identify patterns across institutions","Increasing CTR thresholds to $5,000 to capture more transactions","Requiring banks to share all customer transaction data with each other automatically"], answer:1, explanation:"Cross-institution structuring is specifically designed to evade any single bank's monitoring. Detecting it requires: inter-institutional intelligence sharing (314(b)); law enforcement tools like FinCEN's cross-institution SAR analysis; and multi-agency investigations that can access records across multiple banks simultaneously." },
  { id:6502, domain:1, domainName:D1, question:"'Cryptocurrency ATM' transactions present AML risk because:", options:["Crypto ATMs are the most regulated cryptocurrency transaction method","Some crypto ATMs operate with limited or no KYC requirements for small transactions, enabling cash-to-cryptocurrency conversion with limited identity verification at lower amounts","All crypto ATM transactions are automatically reported to FinCEN","Crypto ATMs can only be used by individuals with existing bank accounts"], answer:1, explanation:"Crypto ATMs allow cash to be converted to cryptocurrency with varying levels of KYC — some require phone verification or ID only at higher amounts, enabling placement of moderate cash amounts into the crypto ecosystem with limited identity trail. FinCEN has taken enforcement actions against operators with inadequate AML programs." },
  { id:6503, domain:1, domainName:D1, question:"'Economic coercion' in the context of financial crime refers to:", options:["Law enforcement coercing witnesses in financial crime investigations","State actors using financial instruments (sanctions, market access, currency manipulation) as tools of foreign policy or to pressure other states — sometimes crossing into financial crime territory","Companies coercing customers into accepting unfavorable financial terms","Criminals coercing financial institution employees into facilitating ML"], answer:1, explanation:"State-level economic coercion occupies a complex space between legitimate foreign policy (sanctions) and financial crime (sanctions evasion, money laundering by state actors). AML professionals must be aware of how geopolitical actors use financial tools and how their activities may require AML/sanctions responses." },
  { id:6504, domain:1, domainName:D1, question:"A 'relationship account' at a private bank is considered high-risk when:", options:["The customer has been a client for more than 10 years","The customer maintains a large average balance","The customer is a foreign PEP, uses complex corporate structures to hold assets, and has sources of wealth inconsistent with their documented public service income","The customer holds more than three accounts at the same institution"], answer:2, explanation:"The combination of PEP status + complex ownership structure + unexplained wealth is the highest-risk private banking profile. Legitimate public officials have known, documentable incomes — assets far exceeding those incomes without clear explanation suggests corruption proceeds that may be laundered through the private banking relationship." },
  { id:6505, domain:1, domainName:D1, question:"'Formal and informal' value transfer systems (FIVTS) are both relevant to AML because:", options:["Only informal systems like hawala present ML risk; formal wire transfer systems are fully monitored","Both formal (regulated wire transfers) and informal (hawala, fei-ch'ien) systems can transfer value; informal systems typically have less oversight and traceability, making them attractive for ML/TF","Informal systems are not used for significant ML amounts","Formal systems are exempt from AML requirements as they are already regulated"], answer:1, explanation:"Both systems move value internationally. Formal systems (SWIFT, ACH) are regulated but subject to exploitation through correspondent banking vulnerabilities. Informal systems (hawala) may move equivalent value with essentially no paper trail — presenting distinct AML challenges that require different detection approaches." },
  { id:6506, domain:1, domainName:D1, question:"'Criminal network mapping' in AML investigations typically uses:", options:["GPS tracking of suspected money launderers","Link analysis software to visualize relationships between accounts, transactions, entities, and individuals — revealing the structure of the criminal organization and its financial infrastructure","Public social media platforms to map criminal relationships","Physical surveillance of suspected criminal locations"], answer:1, explanation:"Financial crime network mapping uses link analysis tools (i2 Analyst Notebook, Palantir, Chainalysis Reactor for crypto) to connect the dots — graphically representing relationships that would be invisible in tabular data, revealing criminal hierarchies, money mule networks, shell company chains, and fund flow patterns." },
  { id:6507, domain:1, domainName:D1, question:"'Bearer shares' present significant ML risk because:", options:["Bearer shares are only issued by publicly traded companies subject to SEC oversight","Bearer shares convey ownership to whoever physically holds the paper certificate — making ownership transfer anonymous and untraceable, ideal for concealing beneficial ownership of shell companies","Bearer shares automatically register ownership with national corporate authorities","Bearer shares are prohibited in all FATF member countries"], answer:1, explanation:"Bearer share companies have no registered shareholder — ownership belongs to whoever holds the physical certificate, which can be transferred anonymously. While FATF Recommendation 24 requires countries to prevent ML misuse of bearer shares (most have now been abolished or immobilized), historical bearer share companies remain an issue." },
  { id:6508, domain:1, domainName:D1, question:"The 'staging' of a money laundering scheme refers to:", options:["The theatrical aspects of a criminal's lifestyle","Carefully planning and executing the ML process in deliberate steps designed to maximize distance between the illicit source and the ultimate beneficial owner of laundered funds","The placement stage of money laundering only","Structuring transactions to occur at specific time intervals"], answer:1, explanation:"Sophisticated ML involves careful planning and staging — not random, opportunistic transactions, but deliberate sequencing of placement, layering, and integration steps, often executed by different participants (money mules for placement, financial professionals for layering, legitimate businesses for integration) to maintain maximum separation between crime and proceeds." },
  { id:6509, domain:1, domainName:D1, question:"'Foreign Corrupt Practices Act' (FCPA) violations are relevant to AML because:", options:["FCPA violations require automatic SAR filing by financial institutions","FCPA violations (bribery of foreign officials) generate criminal proceeds that must be laundered — typically appearing as consulting fees, commission payments, or other legitimate business payments to shell companies controlled by the corrupt official","FCPA violations are exclusively a matter between corporations and the DOJ","Financial institutions that process FCPA-related payments are automatically guilty of money laundering"], answer:1, explanation:"FCPA violations generate illicit payments (bribes disguised as consulting fees, agent commissions, or business payments) that constitute criminal proceeds requiring laundering. These funds often flow through multiple jurisdictions and financial intermediaries, making FCPA compliance and AML monitoring inherently intertwined." },
  { id:6510, domain:1, domainName:D1, question:"'Cryptocurrency mining' using illicit energy resources (e.g., stolen electricity) represents which ML stage?", options:["Integration","Layering","Placement — converting the proceeds of energy theft into cryptocurrency","Structuring"], answer:2, explanation:"Mining with stolen electricity converts the economic benefit of the theft (free electricity) directly into cryptocurrency. The cryptocurrency mined has no transaction history, making it appear 'clean.' This is essentially a placement mechanism — the theft proceeds are placed directly into a cryptocurrency form without passing through traditional financial channels." },
  { id:6511, domain:1, domainName:D1, question:"Which professional services sector presents the GREATEST concern as AML gatekeepers?", options:["Medical professionals","Financial advisors at major wire houses","Trust and company service providers (TCSPs) who form companies and manage complex legal structures for clients, providing the infrastructure criminals use to obscure beneficial ownership","Retail banking relationship managers"], answer:2, explanation:"TCSPs — corporate service providers, registered agents, formation agents — are at the apex of the gatekeeper concern. They create and manage the very corporate structures (shell companies, trusts, foundations) that are the most exploited ML vehicles. FATF Recommendation 22 specifically requires AML measures for TCSPs." },
  // Domain 2 exam 5 (28 questions)
  { id:6512, domain:2, domainName:D2, question:"An effective 'AML compliance culture' is BEST evidenced by:", options:["The number of compliance certifications held by the compliance staff","Consistent behavior across all levels of the institution — where AML obligations are understood and applied in day-to-day decision-making, not just in compliance-related activities","The size of the compliance department's budget","The frequency of board compliance training sessions"], answer:1, explanation:"Culture is demonstrated through behavior — do front-line employees escalate suspicious activity? Do business managers support compliance decisions? Does senior management allocate appropriate resources? Does the board hold management accountable? Culture cannot be certified or purchased; it must be lived throughout the institution." },
  { id:6513, domain:2, domainName:D2, question:"'FinCEN's national AML/CFT priorities' published under AMLA 2020 include:", options:["Drug trafficking, cybercrime, human trafficking, and corruption as among the highest priority AML/CFT concerns that financial institutions should address","Specific SAR filing requirements for each priority area","Mandatory CTR exemptions for businesses operating in priority areas","A list of specific customers that all financial institutions must monitor"], answer:0, explanation:"FinCEN's 2021 AML/CFT Priorities (the first ever under AMLA 2020) identified: corruption, cybercrime, foreign and domestic TF, fraud, transnational criminal organizations, drug trafficking, human trafficking, ML via money services businesses, and proliferation financing as priorities requiring institutional focus." },
  { id:6514, domain:2, domainName:D2, question:"'Agent banking' and 'third-party agent' arrangements in AML compliance create risk because:", options:["Agent banks are not required to maintain BSA programs","Agents may conduct customer-facing AML functions (CIP, CDD) on behalf of the principal institution — with potentially varying quality and oversight — creating risk if agents do not apply equivalent standards","Agent banking is prohibited in all U.S. jurisdictions","Agents are exempt from all BSA reporting requirements"], answer:1, explanation:"Agent banking expands distribution but also distributes AML risk — the principal institution (which holds the regulatory responsibility) must ensure that agents applying CIP/CDD on its behalf maintain appropriate standards, training, and oversight. Agent failures are treated as the principal's failures by regulators." },
  { id:6515, domain:2, domainName:D2, question:"Under the 'common bond' doctrine in credit unions, AML risk considerations include:", options:["Credit union members are inherently lower risk than bank customers","The close-knit community nature of credit unions can create peer pressure that makes employees reluctant to escalate suspicious activity about members — requiring explicit compliance culture reinforcement","Credit unions are exempt from BSA requirements","Common bond means all members are pre-screened and do not require CDD"], answer:1, explanation:"Credit unions' community character is both a strength (customer knowledge) and a risk — the close relationships between employees and members may create reluctance to flag suspicious activity about community members, friends, or influential members. AML programs must explicitly address this dynamic." },
  { id:6516, domain:2, domainName:D2, question:"'Effectiveness metrics' for an AML training program include all of the following EXCEPT:", options:["Employee test scores post-training","SAR quality improvement correlated with training enhancements","Rate of suspicious activity escalations from trained business line staff","The number of training certificates printed annually"], answer:3, explanation:"Training certificates demonstrate completion, not effectiveness. Effectiveness metrics should measure whether training changed behavior and improved outcomes: improvement in suspicious activity identification rates; quality of SAR narratives post-training; accuracy of CDD information collected; and reduction in compliance deficiencies attributable to lack of knowledge." },
  { id:6517, domain:2, domainName:D2, question:"'Differential suspicious activity reporting' among peer institutions means:", options:["Different institutions file SARs at different rates for the same types of activity","Some institutions report every suspicious indicator while others wait for strong evidence — creating inconsistency in AML intelligence quality","All institutions are required to file SARs at the same rate","SARs filed by smaller institutions are weighted differently by FinCEN"], answer:0, explanation:"SAR filing rates vary significantly among peer institutions for similar activities — reflecting differences in risk appetite, AML culture, program sophistication, and interpretation of the 'reasonable suspicion' standard. This inconsistency affects the completeness of the financial intelligence picture available to law enforcement." },
  { id:6518, domain:2, domainName:D2, question:"Under the Bank Secrecy Act, which of the following is a 'financial institution' required to maintain an AML program?", options:["A non-U.S. bank with no U.S. operations","A domestic hotel that accepts cash payments only","A casino with annual gaming revenue exceeding $1 million","An informal money transfer service operated from a private residence"], answer:2, explanation:"Casinos with annual gaming revenues exceeding $1 million are 'financial institutions' under the BSA and must maintain AML programs, file SARs and CTRs, and comply with all applicable BSA requirements. The $1 million threshold distinguishes regulated casinos from small gaming establishments." },
  { id:6519, domain:2, domainName:D2, question:"'Legacy accounts' opened before enhanced AML requirements present compliance risk because:", options:["Legacy accounts are exempt from current BSA requirements","These accounts may lack updated CDD information — beneficial ownership, source of wealth, expected activity — that current onboarding standards would require, creating monitoring gaps","Legacy accounts automatically qualify for CTR exemptions","Legacy accounts cannot be subject to SARs under current law"], answer:1, explanation:"Pre-CDD rule accounts (opened before May 2018) may lack beneficial ownership information and updated CDD. Remediation programs must retroactively collect this information, prioritized by risk — high-risk legacy accounts first. This is a known gap in the U.S. AML framework following the CDD rule implementation." },
  { id:6520, domain:2, domainName:D2, question:"'Transaction monitoring governance' requires:", options:["The BSA officer personally reviewing every transaction monitoring alert","Defined policies for scenario management, alert disposition, escalation, and SAR decisions — with oversight, quality assurance, and regular management reporting on monitoring effectiveness","Regulators pre-approving all transaction monitoring scenarios before implementation","Transaction monitoring systems to be identical across all institutions regulated by the same federal regulator"], answer:1, explanation:"TMS governance provides the institutional framework for monitoring: who owns scenarios and ensures they remain current; how alerts are triaged and assigned; escalation paths for complex cases; QA processes for reviewing closed alerts; and management reporting that enables oversight of monitoring program performance." },
  { id:6521, domain:2, domainName:D2, question:"'Politically exposed person' exit procedures when a PEP's term in public office ends should include:", options:["Immediate account closure upon the PEP's departure from public office","Risk reassessment — a former PEP may still present elevated risk for a period after leaving office, requiring continued EDD for a risk-based period","Immediate downgrade to standard retail customer treatment","Automatic removal from the PEP monitoring list on the day they leave office"], answer:1, explanation:"FATF Recommendation 12 recognizes that PEP risk does not end the day someone leaves office — they retain connections, influence, and potentially still have access to funds accumulated during their tenure. Most jurisdictions require continued EDD for former PEPs for a risk-based period (often 12-24 months minimum)." },
  { id:6522, domain:2, domainName:D2, question:"'AML metrics' provided to the board should include:", options:["Only the total number of SARs filed","Comprehensive indicators: SAR filing volume and timeliness; CTR filing accuracy; alert volume and disposition rates; EDD completion rates; training completion; independent testing results; and regulatory examination status","Only negative metrics highlighting program deficiencies","Only metrics comparing the institution to peers"], answer:1, explanation:"Board-level AML metrics should provide a balanced, comprehensive picture of program health — covering compliance metrics (filing rates, training), operational metrics (alert volumes, productivity), quality indicators (SAR quality, investigation depth), and governance indicators (policy exceptions, key risk indicators). One-dimensional reporting creates blind spots." },
  { id:6523, domain:2, domainName:D2, question:"The term 'nested accounts' in the context of correspondent banking most directly refers to:", options:["Banks having accounts at multiple correspondent banks simultaneously","Correspondent banking arrangements where the respondent bank's customers include other financial institutions, which in turn have their own customers — creating multiple levels of unknown end users behind a single correspondent relationship","Foreign bank subsidiaries maintaining accounts with their parent bank","Payable-through accounts provided to the correspondent bank's retail customers"], answer:1, explanation:"Nested correspondent relationships create a 'matryoshka doll' structure — the U.S. correspondent bank cannot see beyond the immediate respondent bank to the institutions (and their customers) further back in the chain. This was a key vulnerability exploited in several major correspondent banking enforcement actions." },
  { id:6524, domain:2, domainName:D2, question:"'Customer communication' about AML policies should:", options:["Disclose that SARs have been filed on the customer to maintain transparency","Inform customers of their obligations to provide accurate information and documentation, without disclosing SAR filing activities or tipping off subjects","Include a list of all ML typologies the institution monitors for","Require customers to certify that they are not engaged in money laundering"], answer:1, explanation:"Customer-facing AML communications (e.g., customer disclosures about KYC requirements, data use) must balance transparency about data collection with the tipping-off prohibition. Customers may be told that their information is used for compliance purposes, but SAR filings and specific AML investigation targets must not be disclosed." },
  { id:6525, domain:2, domainName:D2, question:"'Voluntary information sharing' between financial institutions under Section 314(b) provides the following protection:", options:["Protection from civil liability for SAR tipping-off violations","A safe harbor from liability (civil and criminal) for sharing information about persons suspected of ML/TF, after the institution files a 314(b) notice with FinCEN","Exemption from OFAC screening requirements for shared subjects","Access to FinCEN's BSA database for researching shared subjects"], answer:1, explanation:"Section 314(b) provides a safe harbor — protecting participating institutions from civil and criminal liability that might otherwise arise from voluntary disclosure of customer information — as long as: FinCEN has been notified; sharing is limited to ML/TF-related information; and the information is used only for ML/TF purposes." },
  { id:6526, domain:2, domainName:D2, question:"'Patchwork compliance' in AML refers to:", options:["A comprehensive, well-integrated AML program","A compliance approach with isolated, disconnected controls that address individual regulatory requirements without forming a coherent, integrated risk management framework — leaving gaps and creating inefficiencies","An approach that applies different standards to different customer segments","A compliance program developed through multiple regulatory examinations"], answer:1, explanation:"Patchwork compliance results from adding requirements reactively — each regulation addressed independently, without integration into a coherent whole. The result is an AML program that may technically check boxes but lacks the integration needed for genuine effectiveness: gaps between controls, inconsistent standards, and redundant efforts." },
  { id:6527, domain:2, domainName:D2, question:"Under the BSA, a 'currency transaction report' must be filed by:", options:["Law enforcement when they seize currency","Financial institutions when a customer conducts a cash transaction exceeding $10,000 in one business day","FinCEN when it analyzes suspicious patterns in large cash movements","State banking authorities when they examine bank cash handling procedures"], answer:1, explanation:"CTRs are filed by financial institutions (not law enforcement or regulators) with FinCEN, for cash transactions (not wire or ACH) that aggregate to more than $10,000 in a single business day by or for the same person. The requirement creates a comprehensive database of large-cash transactions available to law enforcement." },
  { id:6528, domain:2, domainName:D2, question:"'Non-face-to-face' customer relationships (digital banking, online account opening) require special AML attention because:", options:["Online accounts are exempt from CIP requirements","The absence of in-person interaction limits the opportunity to observe behavioral indicators and verify document authenticity through direct inspection","Digital banking customers are inherently lower risk than branch customers","Non-face-to-face accounts cannot be subject to CTR filing requirements"], answer:1, explanation:"Digital customer onboarding creates CIP/CDD challenges: documents cannot be physically inspected; behavioral cues (nervousness, evasiveness) cannot be observed; and identity fraud risk is higher. Robust digital KYC solutions — biometric verification, database checks, device fingerprinting — are essential to maintain equivalent AML standards." },
  { id:6529, domain:2, domainName:D2, question:"'Correspondent banking withdrawal' (de-risking) by large global banks has particularly harmed:", options:["Major financial centers in Europe and North America","Smaller, developing-country financial institutions that lose access to U.S. dollar clearing — limiting their economies' access to global trade and remittances","Large multinational corporations conducting international trade","Regulatory agencies that rely on correspondent banking for transaction data"], answer:1, explanation:"De-risking's greatest victims are smaller, developing-economy banks in regions like the Caribbean, Africa, and Pacific Island nations. When major banks exit correspondent relationships in these regions, local banks lose dollar clearing access, potentially pushing transactions into less transparent channels and harming legitimate economies." },
  { id:6530, domain:2, domainName:D2, question:"The 'Customer Acceptance Committee' process at a financial institution typically involves:", options:["Automatically approving all new customer applications","Reviewing and approving high-risk customer relationships at an appropriate management level before account opening, ensuring AML risk has been properly assessed and documented","Filing a SAR before opening accounts for any high-risk customer","Requiring board approval for all new business customer relationships"], answer:1, explanation:"High-risk customer approval processes (committees, multi-level sign-off) ensure that elevated-risk relationships receive proportionate scrutiny before the institution commits to the relationship. The approval level should match the risk level — routine accounts require limited approval; PEPs and complex entity accounts require senior management or committee review." },
  { id:6531, domain:2, domainName:D2, question:"'Reasonable procedures' under the USA PATRIOT Act CIP requirements means:", options:["Using the same identity verification procedures regardless of account type","Risk-based identity verification procedures appropriate to the type of account, method of account opening, and available information about the customer","Verifying identity through a U.S. government database for all customers","Requiring in-person verification for all customers regardless of account type"], answer:1, explanation:"CIP 'reasonable procedures' are contextually appropriate — the level of verification should be proportionate to the risk: a digital account with ACH access requires more verification than a savings account with low transaction limits; a foreign national requires different documentation than a U.S. citizen; and non-face-to-face accounts require enhanced documentary alternatives." },
  { id:6532, domain:2, domainName:D2, question:"'AML policy review' frequency should be:", options:["Every five years, to allow sufficient time for meaningful policy changes","At least annually, and more frequently when significant regulatory changes occur, new ML/TF typologies emerge, or material changes occur in the institution's business model or risk profile","Only when a regulatory examination is scheduled","Only when the institution's primary regulator issues new guidance"], answer:1, explanation:"AML policies must remain current — annual review is a baseline, with additional reviews triggered by: regulatory changes (new rules, amended guidance); significant business changes (new products, M&A, new markets); examination findings; emerging typologies identified through intelligence products; or internal risk assessment updates." },
  { id:6533, domain:2, domainName:D2, question:"'Terminating a customer relationship for AML reasons' requires:", options:["Filing a SAR before termination in all cases","A regulatory examination finding before termination can occur","No specific process — institutions may terminate any relationship at any time for any reason","Documentation of the AML basis for termination and consideration of whether SAR filing is required — with account closure not eliminating the SAR filing obligation if suspicious activity was identified"], answer:3, explanation:"Account termination for AML reasons should be documented (protecting the institution from breach of contract claims) and should trigger evaluation of whether a SAR is required — closing the account does not eliminate the filing obligation if suspicious activity was identified before or during the closure process." },
  { id:6534, domain:2, domainName:D2, question:"The 'ACAMS CAMS certification' is significant in the AML compliance profession because:", options:["CAMS certification is legally required to serve as a BSA officer","CAMS certification demonstrates a validated level of AML knowledge and expertise recognized globally by employers, regulators, and peers as a professional standard","CAMS-certified professionals are exempt from regulatory examinations","CAMS certification provides legal immunity for AML compliance decisions made in good faith"], answer:1, explanation:"CAMS (Certified Anti-Money Laundering Specialist) is the leading AML certification globally — it tests comprehensive knowledge of ML/TF typologies, compliance programs, investigations, and law enforcement cooperation. While not legally required, it is widely recognized as the professional standard for AML practitioners." },
  { id:6535, domain:2, domainName:D2, question:"'Customer segmentation' for AML risk purposes should be:", options:["Based primarily on the customer's income level","Based on ML/TF risk factors including customer type, business activity, geographic footprint, transaction types, and product usage — not on protected class characteristics such as race, ethnicity, or national origin","Based on the customer's profitability to the institution","Based exclusively on geography"], answer:1, explanation:"AML risk segmentation must be based on genuine risk factors, not on protected characteristics (race, ethnicity, religion, national origin) which would constitute illegal discrimination. Geography-based risk assessment (e.g., high-risk countries) is permissible when based on documented ML/TF risk factors, not on the customer's national origin." },
  { id:6536, domain:2, domainName:D2, question:"'Integrated financial crime compliance' refers to:", options:["Combining AML, fraud, and cybercrime functions under a single compliance officer","A holistic approach that recognizes the interconnection of AML, sanctions, anti-bribery, fraud, and market integrity — with integrated governance, shared intelligence, and coordinated controls","Requiring all financial crime compliance to be managed by one department in all institutions","Integrating all financial crime compliance functions with the legal department"], answer:1, explanation:"Modern financial crime compliance recognizes that criminals exploit overlaps between AML, sanctions, fraud, and bribery — and that a siloed approach creates gaps. Integrated FCC programs share intelligence across disciplines, coordinate controls, and present a unified view of financial crime risk to senior management and the board." },
  { id:6537, domain:2, domainName:D2, question:"'Continuous improvement' in AML programs is achieved through:", options:["Replacing the BSA officer whenever regulatory findings occur","Systematic identification of program gaps through testing, examination findings, SAR quality review, and typology intelligence — followed by documented, prioritized remediation and monitoring of improvement","Filing more SARs than the prior year","Matching industry peers' compliance spending as a percentage of revenue"], answer:1, explanation:"Continuous improvement reflects a mature compliance culture — not just fixing what regulators find, but proactively identifying and addressing gaps through the institution's own testing, QA, intelligence monitoring, and governance processes. This is the hallmark of an effective, risk-based AML program." },
  { id:6538, domain:2, domainName:D2, question:"'Non-profit organization' (NPO) AML due diligence should SPECIFICALLY address:", options:["Whether the NPO is incorporated in the institution's home state","The NPO's stated mission, funding sources, geographic areas of operation and beneficiary populations, and whether these create TF risk — particularly for NPOs operating in conflict zones or serving vulnerable populations","Whether the NPO has more than 100 employees","Whether the NPO files annual Form 990 returns with the IRS"], answer:1, explanation:"NPO AML due diligence focuses on TF risk specifically: Is the NPO's stated mission legitimate? Who are its funders? Does it move funds to or operate in TF-risk regions? Are its beneficiaries potentially exploited by TF actors? NPOs serving legitimate purposes in stable jurisdictions present lower risk than those with connections to conflict zones or extremist communities." },
  { id:6539, domain:2, domainName:D2, question:"The PRIMARY difference between AML 'compliance' and AML 'effectiveness' in the FATF framework is:", options:["Compliance is evaluated by national regulators; effectiveness is evaluated by FATF","Compliance measures whether required laws and structures are in place (technical compliance); effectiveness measures whether those measures actually achieve the intended AML/CFT results","Compliance applies to financial institutions; effectiveness applies to countries","There is no meaningful difference — compliant countries are always effective"], answer:1, explanation:"FATF's dual assessment framework (since 2013) recognizes that having the right laws on paper (technical compliance) is necessary but insufficient. Effectiveness measures actual outcomes — are ML proceeds being seized? Are TF networks being disrupted? Are beneficial owners actually identifiable? Countries with identical technical compliance can have vastly different effectiveness." },
  // Domain 3 exam 5 (30 questions)
  { id:6540, domain:3, domainName:D3, question:"'AML investigative software' used in financial investigations typically provides:", options:["Automatic SAR filing capabilities","Link analysis visualization, transaction pattern analysis, geospatial mapping, and integration with external data sources to support comprehensive investigation of complex suspicious activity","Automated account closure for high-risk customers","Direct access to FinCEN's BSA database for all financial institution employees"], answer:1, explanation:"Investigative software (Actimize, NICE, FiServ, SAS, and specialized tools like Chainalysis for crypto) enhances investigator productivity by: visualizing account relationships and fund flows; identifying pattern anomalies across large transaction datasets; mapping geographic activity; and integrating external data (adverse media, sanctions lists, corporate records) with internal transaction data." },
  { id:6541, domain:3, domainName:D3, question:"'AML alert disposition documentation' is important because:", options:["It is required to be submitted to FinCEN for all closed alerts","It creates a complete, auditable record of the investigation and decision-making process — demonstrating good faith compliance and enabling quality review and regulatory examination","It triggers automatic SAR filing for all closed alerts","It determines the alert threshold for future monitoring of the same customer"], answer:1, explanation:"Alert disposition documentation demonstrates that: the institution identified potential suspicious activity; conducted a genuine investigation; considered relevant factors; and reached a reasoned, documented conclusion. Without documentation, regulators cannot assess investigation quality and the institution cannot demonstrate good faith." },
  { id:6542, domain:3, domainName:D3, question:"'Financial forensics' as applied to ML investigations differs from traditional forensic accounting in that:", options:["Financial forensics only applies to criminal cases; forensic accounting applies to civil cases","Financial forensics specifically focuses on tracing illicit fund flows, identifying the source and disposition of criminal proceeds, and building the evidentiary basis for ML prosecution and forfeiture — beyond the general financial analysis of forensic accounting","Financial forensics is only performed by law enforcement; forensic accounting is only performed by auditors","There is no meaningful difference between the two disciplines"], answer:1, explanation:"Financial forensics in ML investigations is specifically oriented toward criminal law objectives — tracing criminal proceeds, establishing the connection between assets and crimes, building forfeiture cases, and preparing expert testimony. Forensic accounting (broader) may also address civil disputes, fraud investigation, and business valuation." },
  { id:6543, domain:3, domainName:D3, question:"The BEST way for an AML analyst to document the basis for NOT filing a SAR is:", options:["Send an email to the BSA officer noting the decision","Create a formal case record describing the alert, investigation steps, information reviewed, the customer's explanation (if any), and the specific rationale for concluding the activity is not suspicious","Simply close the alert in the TMS without additional documentation","File a 'precautionary SAR' rather than closing without documentation"], answer:1, explanation:"Non-filing documentation is as legally important as filing documentation — it demonstrates that: the institution identified the suspicious activity indicator; conducted a genuine, thorough investigation; received and evaluated any customer explanation; and reached a defensible, documented conclusion. This record protects the institution in regulatory examinations and potential litigation." },
  { id:6544, domain:3, domainName:D3, question:"'AML quality assurance reviews' of closed investigation decisions should assess:", options:["Only whether the SAR was filed within the 30-day deadline","The completeness of investigation, accuracy of the SAR (if filed), quality of the narrative, consistency of decision-making with similar cases, and whether the analyst correctly applied the institution's SAR standards","Only the technical formatting of the SAR filing","Whether the investigation used the correct number of data sources"], answer:1, explanation:"Comprehensive QA assesses every dimension of investigation quality: Was the full fact pattern considered? Was adverse media screened? Was prior SAR history reviewed? Is the decision consistent with how similar patterns were handled? Is the narrative clear, accurate, and sufficient for law enforcement use? This identifies training needs and systematic decision-making inconsistencies." },
  { id:6545, domain:3, domainName:D3, question:"A 'financial intelligence unit' (FIU) is considered most effective when it:", options:["Employs the largest number of staff","Receives the highest volume of STRs from financial institutions","Produces actionable financial intelligence that is used by law enforcement to identify, investigate, and prosecute ML/TF — and disseminates proactive intelligence to the financial sector","Maintains the strictest confidentiality about all received STRs"], answer:2, explanation:"FIU effectiveness is measured by outcomes, not inputs — the quality and utility of intelligence produced, the rate at which disseminations lead to investigations and prosecutions, and the quality of feedback and intelligence provided to the financial sector. An FIU that receives many STRs but produces little actionable intelligence is not effective." },
  { id:6546, domain:3, domainName:D3, question:"'AML information technology' governance at a financial institution should ensure:", options:["All transaction monitoring systems are developed in-house for maximum customization","IT systems supporting AML (TMS, case management, SAR filing, OFAC screening) are reliable, properly secured, regularly tested, and subject to change management processes that prevent unintended degradation of AML capabilities","The BSA officer has direct access to all customer banking systems","AML IT systems are never updated after initial implementation to maintain system stability"], answer:1, explanation:"AML IT governance addresses: system reliability (monitoring must run continuously); data quality (garbage in, garbage out); change management (system changes must be tested for AML impact before implementation); access controls (protecting sensitive AML data); and system testing (ensuring scenarios perform as designed). IT failures are AML program failures." },
  { id:6547, domain:3, domainName:D3, question:"'Machine learning' applied to AML transaction monitoring enables:", options:["Automatic SAR filing without human intervention","Dynamic identification of suspicious patterns using models trained on historical data — potentially detecting novel ML typologies and reducing false positives compared to static rule-based systems","Complete elimination of human analysts from the AML process","Prediction of specific criminal acts before they occur"], answer:1, explanation:"ML models in AML can: learn complex, multi-variable patterns associated with ML/TF; adapt to evolving criminal behavior over time; identify subtle anomalies invisible to rule-based systems; and (if properly calibrated) reduce false positive rates while maintaining detection sensitivity. Human analysts remain essential for investigation and final SAR decisions." },
  { id:6548, domain:3, domainName:D3, question:"'SAR voluntary disclosure' to law enforcement contacts (beyond the FinCEN filing) is:", options:["Prohibited by the tipping-off prohibition","Always required for terrorism-related SARs","Permissible in certain circumstances and can accelerate law enforcement response to time-sensitive suspicious activity, particularly potential terrorism financing","Required for all SARs involving transactions over $50,000"], answer:2, explanation:"While most SARs are filed only with FinCEN, institutions may in certain circumstances (particularly for potential TF or imminent harm) proactively contact the FBI or other law enforcement to ensure urgent attention. This voluntary disclosure is permissible and can be critical when time is of the essence." },
  { id:6549, domain:3, domainName:D3, question:"'Entity resolution' in AML data analytics refers to:", options:["Resolving legal disputes with corporate entity customers","The process of identifying and linking different records that refer to the same real-world person or entity across multiple data sources — enabling complete customer relationship visibility","Closing AML cases involving corporate entities","Resolving unclear beneficial ownership information through customer interviews"], answer:1, explanation:"Entity resolution (or identity resolution) is critical for AML — combining records across systems (accounts, transactions, third-party data) to build a complete picture of each unique person or entity. Without it, a money launderer using slightly different name variations across accounts may evade detection that would be obvious if all records were linked." },
  { id:6550, domain:3, domainName:D3, question:"'Natural language processing' (NLP) in AML is being applied to:", options:["Translating foreign-language documents in international ML investigations","Analyzing SAR narratives, adverse media, and customer communications to extract entities, relationships, and indicators of suspicious activity — supplementing structured transaction data with unstructured text intelligence","Automatically filing SARs based on text pattern recognition","Generating compliance documentation without human review"], answer:1, explanation:"NLP tools extract structured information from unstructured text — adverse media articles, SAR narratives, customer communications, court documents — identifying entities (people, companies, addresses), relationships (customer-entity, transaction-purpose), and risk indicators that structured data systems cannot capture." },
  { id:6551, domain:3, domainName:D3, question:"'SAR data analytics' by FinCEN generates value by:", options:["Making SAR data publicly available for academic research","Analyzing patterns across millions of SAR filings to identify criminal networks, geographic concentration of ML activity, emerging typologies, and links between subjects — producing intelligence impossible to derive from individual filings","Automatically sharing SAR information with all 314(b) registered institutions","Ranking financial institutions by SAR filing volume for examination prioritization"], answer:1, explanation:"FinCEN's BSA database containing decades of SAR filings is one of the world's largest repositories of financial crime intelligence. Cross-SAR analytics reveals patterns invisible at the individual institution level — criminal networks operating across multiple banks, geographic concentrations of ML activity, and emerging typological trends." },
  { id:6552, domain:3, domainName:D3, question:"'Anti-money laundering investigations' triggered by law enforcement referrals are MOST effective when:", options:["The institution immediately closes all accounts associated with the referral subject","The institution and law enforcement establish clear communication protocols, with the institution continuing to monitor and report while law enforcement investigates — using the institution's intelligence as an ongoing source","The institution files a SAR and considers the matter closed","The institution provides all customer records to law enforcement before a subpoena is issued"], answer:1, explanation:"Law enforcement and financial institution cooperation is most effective as a sustained relationship — the institution's ongoing monitoring can provide law enforcement with real-time intelligence as the investigation develops, while law enforcement may provide context (through appropriate channels) that enables more targeted monitoring." },
  { id:6553, domain:3, domainName:D3, question:"The 'financial investigation report' in an ML case typically includes:", options:["Only the amounts of money laundered by each defendant","A comprehensive analysis of all identified financial transactions, accounts, entities, and individuals — tracing the flow of funds from the predicate offense through the ML process to the ultimate disposition of criminal proceeds","Only information about criminal convictions related to the case","A SAR narrative prepared by the financial institution"], answer:1, explanation:"A financial investigation report documents the complete financial picture developed during the investigation — the predicate crime's financial proceeds, every financial account and entity involved, the transaction flow from source to ultimate disposition, and the connection between each identified asset and the criminal activity." },
  { id:6554, domain:3, domainName:D3, question:"'Coordinated SAR filing' (when multiple institutions file SARs on the same subject or transaction) creates value because:", options:["It allows one institution to stop monitoring while the other continues","The combination of multiple institutions' perspectives on the same subject's financial activity provides law enforcement with a more complete picture than any single SAR could offer","Coordinated SARs must all include identical narratives to ensure consistency","Coordinated SARs eliminate the need for 314(a) requests from law enforcement"], answer:1, explanation:"When multiple institutions independently file SARs on the same subject (often through 314(b) information sharing or just coincidentally), FinCEN can connect the dots — showing investigators the full scope of a subject's suspicious financial activity across the entire financial system, not just one institution's piece of the picture." },
  { id:6555, domain:3, domainName:D3, question:"'CAMS certification' (Certified Anti-Money Laundering Specialist) covers four primary domains of knowledge, which include:", options:["Accounting, Finance, Law, and Technology","Risks and Methods of ML/TF; AML/CFT Compliance Programs; Financial Investigations; and Supporting and Engaging with Law Enforcement","Banking, Insurance, Securities, and Money Services","Criminal Law, Civil Law, Regulatory Law, and International Law"], answer:1, explanation:"The ACAMS CAMS exam is organized around four domains that mirror the full lifecycle of AML: understanding how ML/TF works (Risks & Methods); building compliance programs (AML/CFT Compliance); conducting investigations (Financial Investigations); and working with law enforcement (Supporting LE). This structure reflects the holistic competency required for effective AML practice." },
  { id:6556, domain:3, domainName:D3, question:"'Cryptocurrency blockchain analytics' tools such as Chainalysis and Elliptic are used to:", options:["Mine cryptocurrency on behalf of law enforcement","Trace cryptocurrency transaction flows across blockchain networks, identify high-risk addresses (darknet markets, mixers, sanctioned entities), and attribute pseudonymous addresses to real-world entities","Automatically report cryptocurrency transactions to FinCEN","Block cryptocurrency transactions involving suspected criminals"], answer:1, explanation:"Blockchain analytics firms provide critical tools for cryptocurrency financial investigation: transaction clustering (identifying wallets controlled by the same entity); risk scoring (identifying transactions with sanctioned entities or darknet markets); and de-anonymization (attributing addresses to real-world entities through on-chain behavior patterns and off-chain intelligence)." },
  { id:6557, domain:3, domainName:D3, question:"'Financial investigation' of terrorism financing focuses MOST on:", options:["Finding large-value transactions that directly fund terrorist attacks","Identifying the funding sources, collection mechanisms, transfer channels, and destination of funds supporting terrorist organizations — regardless of amount","Only investigating fundraising from legitimate sources","Only investigating cross-border fund transfers related to known terrorist organizations"], answer:1, explanation:"TF financial investigation is comprehensive: mapping the entire funding ecosystem — how does the organization raise funds (donations, crime, state sponsorship); how are they collected and stored; how are they moved internationally; and how are they ultimately used operationally. Amount is less important than understanding the full financial infrastructure." },
  { id:6558, domain:3, domainName:D3, question:"'AML investigation teams' are typically organized as:", options:["Single analysts responsible for all functions from alert review through SAR filing","Tiered structures — L1 analysts triage and investigate alerts; L2 complex case specialists handle escalated cases; BSA officers make final SAR decisions — with clear escalation criteria between tiers","All AML investigations conducted by the BSA officer personally","Investigation teams without any quality assurance oversight"], answer:1, explanation:"Tiered investigation structures optimize resources — standard alerts are handled by experienced analysts; complex cases requiring deeper expertise (unusual corporate structures, international networks, high-risk customer types) are escalated to specialists; and final SAR decisions are made at a senior level with appropriate oversight." },
  { id:6559, domain:3, domainName:D3, question:"'Transaction monitoring program effectiveness' is assessed through:", options:["Only counting the number of alerts generated","A comprehensive approach including: detection rate (what percentage of known suspicious activity was caught?); false positive rate; SAR conversion rate; investigative quality; timeliness; and law enforcement feedback on SAR utility","Only measuring the time taken to close each alert","Only comparing alert volumes to prior year"], answer:1, explanation:"No single metric captures TMS effectiveness. A robust assessment examines the full picture: Is the system detecting the suspicious activity it should? Is it generating manageable alert volumes? Are investigations thorough? Are SARs timely and useful? Is law enforcement providing feedback that informs continuous improvement?" },
  { id:6560, domain:3, domainName:D3, question:"'Data quality' in AML transaction monitoring systems is critical because:", options:["Regulators assess AML programs based primarily on data quality metrics","Incomplete, inaccurate, or untimely transaction data prevents the monitoring system from detecting suspicious patterns — even the best monitoring scenarios cannot function properly if fed with poor quality data","Data quality only affects CTR filing accuracy, not SAR detection","All transaction monitoring data must be reviewed manually before feeding into automated systems"], answer:1, explanation:"AML TMS effectiveness is entirely dependent on data quality — if accounts are not properly mapped, transactions are missing or duplicated, counterparty information is incomplete, or data is delivered with delays, monitoring scenarios will generate false negatives (missed suspicious activity) regardless of their analytical sophistication." },
  { id:6561, domain:3, domainName:D3, question:"'Financial investigation of cybercrime' proceeds typically involves:", options:["Only tracing cash transactions from cybercrime victims","Combining traditional financial investigation (following bank account transactions) with cryptocurrency forensics and digital evidence to trace proceeds from cyber attacks, ransomware, fraud, and theft through complex multi-chain ML schemes","Only working with the cybercrime victim to identify their losses","Exclusively using government databases without bank cooperation"], answer:1, explanation:"Cybercrime proceeds investigation requires multi-disciplinary expertise: digital forensics (device and network evidence); traditional financial investigation (bank records, wire transfers); and cryptocurrency analytics (tracing blockchain transactions, identifying exchange interactions, following fund flows through mixers and cross-chain swaps)." },
  { id:6562, domain:3, domainName:D3, question:"The 'Systematic Illicit Finance Network Analysis' (SINA) approach involves:", options:["A standardized international approach to SAR filing","Using network analysis, machine learning, and financial intelligence to systematically map and disrupt entire criminal financial networks rather than focusing on individual transactions or accounts","An automated system that replaces human AML analysts","A FinCEN classification system for different types of suspicious activity"], answer:1, explanation:"SINA-type approaches recognize that ML is a network phenomenon — targeting the full financial infrastructure of criminal organizations rather than one account or transaction at a time. By mapping the entire network, investigators can identify key nodes (critical accounts, facilitators, service providers) whose disruption has maximum impact on the criminal enterprise." },
  { id:6563, domain:3, domainName:D3, question:"'Post-investigation review' of an AML case that resulted in a law enforcement referral should include:", options:["Closing all customer accounts associated with the case","Documenting the investigation process, identifying lessons learned, and considering whether monitoring scenarios should be updated to better detect similar patterns in the future","Filing a CTR for all transactions related to the case","Sharing the investigation file with other financial institutions through 314(b)"], answer:1, explanation:"Post-investigation review (particularly for cases that led to law enforcement action or revealed new typologies) is a key driver of program improvement. What worked in the investigation? What was missed? Are current monitoring scenarios adequate to detect similar patterns? This learning loop makes the AML program smarter over time." },
  { id:6564, domain:3, domainName:D3, question:"'SAR amendment' is appropriate when:", options:["The institution wants to withdraw a SAR that was filed in error","The original SAR contained incorrect or incomplete information, and new information is available that materially changes the information previously provided to FinCEN","The customer subject of the SAR requests a correction","A regulatory examiner requests modification of a previously filed SAR"], answer:1, explanation:"SAR amendments correct material errors or omissions in previously filed SARs — they do not withdraw a filing. If the institution discovers that a SAR contained incorrect subject information, wrong transaction amounts, or missing material facts, an amendment (filed the same way as the original) updates the intelligence available to law enforcement." },
  { id:6565, domain:3, domainName:D3, question:"The AML 'investigative horizon' for a typical SAR covers transactions:", options:["Only from the date the suspicious activity was first identified","Over the relevant look-back period — typically 12 months or more — necessary to establish the full pattern of suspicious activity, not just the most recent transactions that triggered the alert","Only from the date the SAR is filed","Only from the date the customer opened their account"], answer:1, explanation:"Effective SAR investigations examine the historical pattern — 12 months of transaction history is standard for most institutions, with longer periods for complex cases. The initial triggering transaction is rarely sufficient to establish the full picture; the pattern over time is what makes the ML case." },
  { id:6566, domain:3, domainName:D3, question:"'Cross-border information sharing' between financial institutions for AML purposes is MOST effectively accomplished through:", options:["Informal emails between compliance officers at different institutions","Bilateral 314(b)-equivalent agreements, FATF-encouraged inter-institutional cooperation frameworks, and formal legal mechanisms such as MLATs for law enforcement-related sharing","Direct sharing of SAR data between international branches of the same institution","International conventions that require mandatory sharing of all suspicious activity information"], answer:1, explanation:"Cross-border AML information sharing between private sector institutions is complex — privacy laws, bank secrecy laws, and data protection regulations vary significantly across jurisdictions. Effective sharing requires formal legal frameworks (MLAT for law enforcement-linked sharing, FATF-encouraged bilateral mechanisms for private sector) to ensure sharing is both legal and protected." },
  { id:6567, domain:3, domainName:D3, question:"The 'CAMS exam' tests AML practitioner competency across four domains. The domain covering the DETECTION of suspicious activity is primarily:", options:["Risks and Methods of ML/TF","AML/CFT Compliance Programs","Financial Investigations","Supporting and Engaging with Law Enforcement"], answer:2, explanation:"Domain 3 (Financial Investigations) covers the detection, investigation, and reporting of suspicious activity — transaction monitoring, SAR filing, AML investigation techniques, information gathering, and the role of FIUs. Domain 2 covers the program framework; Domain 1 covers what ML/TF looks like; Domain 4 covers law enforcement cooperation." },
  { id:6568, domain:3, domainName:D3, question:"'Risk tolerance' in AML SAR decision-making refers to:", options:["The maximum penalty the institution is willing to accept for AML violations","The institution's documented standard for what level of suspicious indicators is sufficient to trigger SAR filing — balancing over-filing (which reduces SAR quality) with under-filing (which fails compliance obligations)","The amount of AML compliance budget the institution is willing to spend","The maximum false positive rate the institution accepts in its TMS"], answer:1, explanation:"SAR filing standards reflect an implicit risk tolerance decision — filing too readily (on every indicator) floods FinCEN with low-value SARs and may tip off customers unnecessarily; filing too conservatively risks missing genuine suspicious activity and violating SAR obligations. Institutions should document their standards clearly and apply them consistently." },
  { id:6569, domain:3, domainName:D3, question:"The 'financial investigation lifecycle' in an ML case typically progresses through:", options:["Account opening → CTR filing → SAR filing → account closure","Intelligence collection and analysis → subject identification → account subpoena → transaction tracing → asset identification → restraint and forfeiture → prosecution support","Arrest → financial investigation → sentencing → asset forfeiture","SAR filing → law enforcement subpoena → prosecution → forfeiture"], answer:1, explanation:"Financial investigations in ML cases follow a logical progression: gather intelligence (SARs, 314(a) hits, human sources); identify all subjects and related entities; obtain financial records through legal process; trace funds from predicate offense through ML process; identify assets to be restrained; freeze assets; and support prosecution and forfeiture." },
  // Domain 4 exam 5 (31 questions)
  { id:6570, domain:4, domainName:D4, question:"'International standards for AML' developed by FATF are implemented domestically through:", options:["Automatic incorporation of FATF Recommendations into domestic law","Countries enacting their own legislation, regulations, and guidance consistent with FATF standards — monitored through mutual evaluations that assess both technical compliance and effectiveness","FATF directly issuing binding regulations in member countries","The UN Security Council mandating FATF standards as binding international law"], answer:1, explanation:"FATF Recommendations are not directly binding — they are international standards that countries voluntarily commit to implementing through their own domestic legal frameworks. The mutual evaluation process provides accountability for implementation, but FATF cannot directly legislate in any country." },
  { id:6571, domain:4, domainName:D4, question:"A 'financial investigation freeze order' obtained through MLAT means:", options:["The subject's financial institution is required to close their account","Assets identified as potentially criminal are frozen pending the outcome of the investigation and potential forfeiture proceedings","The subject is prohibited from leaving the country","The subject's bank must file a SAR on all their transactions"], answer:1, explanation:"MLAT-based asset freeze orders are critical tools for preserving criminal proceeds pending prosecution and forfeiture. Without a freeze, sophisticated criminals can rapidly dissipate assets during an investigation — particularly when they become aware that they are under scrutiny. International freezes coordinate preservation across multiple jurisdictions simultaneously." },
  { id:6572, domain:4, domainName:D4, question:"'The FATF plenary' makes decisions by:", options:["Majority vote of member countries","Consensus — all members must agree, reflecting FATF's intergovernmental nature and ensuring buy-in from all jurisdictions","Simple majority of the FATF Secretariat","Veto authority held by the G7 founding members"], answer:1, explanation:"FATF operates by consensus — each of its 37+ member jurisdictions and 2 regional organizations must agree to decisions, including adoption or revision of Recommendations, grey/black listing decisions, and admission of new members. This consensus requirement reflects FATF's intergovernmental character and the need for global buy-in." },
  { id:6573, domain:4, domainName:D4, question:"'Asset recovery statistics' show that globally, seized and frozen assets represent what estimated percentage of criminal proceeds?", options:["More than 25%","Approximately 10-15%","Less than 1%","Approximately 5%"], answer:2, explanation:"Despite significant international investment in AML infrastructure, UNODC and other bodies estimate that less than 1% of criminal proceeds are seized or frozen globally. This 'enforcement gap' reflects the sophistication of criminal financial structures, jurisdictional fragmentation, and resource constraints in financial investigation and recovery." },
  { id:6574, domain:4, domainName:D4, question:"A 'suspicious activity tip' received by a financial institution from an anonymous source should be:", options:["Immediately reported to law enforcement and ignored for AML purposes","Evaluated as potentially relevant intelligence — investigated against available internal data and external information to assess whether it warrants further investigation or SAR filing","Automatically dismissed as unreliable","Filed as a SAR without further investigation"], answer:1, explanation:"Anonymous tips can provide valuable intelligence leads — even if unverifiable in isolation, a tip may be corroborated by internal transaction data, adverse media, or other available information. The institution must evaluate the tip against all available information and make an appropriate compliance decision." },
  { id:6575, domain:4, domainName:D4, question:"'Beneficial forfeiture' versus 'forfeiture of specific property' in ML cases means:", options:["Beneficial forfeiture returns assets to ML victims; specific property forfeiture removes assets from the criminal","Beneficial forfeiture forfeits the value equivalent to criminal proceeds; specific property forfeiture targets specific assets identified as ML proceeds or instrumentalities","Beneficial forfeiture applies in civil proceedings; specific property forfeiture is criminal only","There is no legal distinction between the two types of forfeiture"], answer:1, explanation:"Courts may order forfeiture of: (1) specific identified assets (property directly connected to the crime); or (2) a money judgment in the amount of proceeds — allowing forfeiture of substitute assets if specific property has been dissipated. The combination provides comprehensive recovery tools." },
  { id:6576, domain:4, domainName:D4, question:"'International law enforcement cooperation' in ML cases is MOST effectively coordinated through:", options:["Informal personal contacts between investigators in different countries","Dedicated international law enforcement cooperation platforms including INTERPOL, Europol, ILEA, and bilateral liaison offices — supplemented by formal MLAT requests for evidence and asset restraint","Direct country-to-country government negotiations on a case-by-case basis","UN Security Council resolutions in each ML case"], answer:1, explanation:"International law enforcement networks — INTERPOL's financial crime division, Europol's Economic and Financial Crime Centre (EFECC), and U.S. agencies' international liaison programs (DEA, FBI, HSI offices abroad) — provide the day-to-day coordination channels that enable international ML investigations to function effectively alongside formal MLAT processes." },
  { id:6577, domain:4, domainName:D4, question:"The 'Staircase of Measures' in FATF's approach to non-compliant countries involves:", options:["Immediate sanctions against any country that fails a mutual evaluation","A graduated escalation — from enhanced monitoring (grey list) to countermeasures (black list) — with increasing international pressure designed to motivate countries to implement required AML/CFT reforms","Automatic expulsion from FATF for any member that fails technical compliance","Annual sanctions reviews for all countries on the grey list"], answer:1, explanation:"FATF's graduated response starts with identification of strategic deficiencies and encouragement to reform; escalates to grey listing (increased monitoring, international financial pressure) if improvements are insufficient; and culminates with black listing (call for countermeasures from all FATF member countries) for the most serious, persistent non-compliance." },
  { id:6578, domain:4, domainName:D4, question:"'Judicial assistance' in international ML investigations under MLATs typically includes:", options:["Criminal prosecution of defendants in the requesting country's courts","Search and seizure orders, production of bank records, taking of witness statements, asset freezing, and service of legal process — all executed under the legal authority of the requested country's courts","Automatic extradition of ML suspects between treaty countries","Sharing of classified intelligence between countries' intelligence services"], answer:1, explanation:"MLAT assistance is judicial assistance — it involves the requested country's courts executing formal judicial procedures (search warrants, production orders, asset freezes) on behalf of the requesting country's investigation. Extradition is a separate process with its own treaty framework; intelligence sharing goes through intelligence community channels." },
  { id:6579, domain:4, domainName:D4, question:"'FATF Recommendation 38' addresses:", options:["Virtual assets and VASPs","Politically exposed persons","Mutual legal assistance for confiscation and provisional measures — requiring countries to assist each other in asset freezing and forfeiture","Financial intelligence units"], answer:2, explanation:"Recommendation 38 requires countries to take action quickly on requests from foreign counterparts to identify, trace, and ultimately forfeit criminal assets — implementing provisional measures to freeze assets pending final forfeiture orders. It is the international asset recovery pillar of the FATF framework." },
  { id:6580, domain:4, domainName:D4, question:"'Financial crime reporting' to senior management should occur:", options:["Only after a regulatory examination identifies deficiencies","Only when a SAR is filed that relates to a senior management-approved customer","Regularly — through periodic AML dashboards, escalation of significant matters, and event-driven reporting of significant suspicious activity or regulatory developments","Only when requested by the board of directors"], answer:2, explanation:"Regular management reporting is a governance requirement and a best practice — it keeps senior management informed of AML program health, significant suspicious activity, regulatory developments, and key risk indicators, enabling them to make informed decisions about resources and risk appetite." },
  { id:6581, domain:4, domainName:D4, question:"'International asset tracing' requires which combination of capabilities?", options:["Only a single investigator with international law enforcement experience","Legal authorities (MLATs, court orders), financial investigation skills (tracing through accounts and corporate structures), intelligence resources (FIU data, law enforcement databases), and international cooperation channels (INTERPOL, Egmont)","Access to SWIFT transaction data and a cryptocurrency analytics tool","A public registry of criminal proceeds held in each country"], answer:1, explanation:"Complex international asset tracing requires: legal authority to access financial records across jurisdictions; financial investigation expertise to trace complex corporate and account structures; intelligence resources to identify where assets are located; and international cooperation channels to execute asset freezing orders in foreign jurisdictions simultaneously." },
  { id:6582, domain:4, domainName:D4, question:"The 'FATF Presidency' rotates among member countries to:", options:["Ensure that each country has the opportunity to impose its domestic AML standards on other members","Provide rotating leadership and diverse perspectives, while maintaining consistency through the permanent Secretariat","Allow member countries to shape enforcement actions against rivals","Give each member country veto authority over mutual evaluations for one year"], answer:1, explanation:"The rotating FATF Presidency (1-year term) provides fresh leadership perspectives while the permanent FATF Secretariat in Paris maintains institutional continuity. The rotation ensures that no single country permanently dominates FATF's agenda, reflecting its intergovernmental, consensus-based character." },
  { id:6583, domain:4, domainName:D4, question:"'Financial penalties' for ML offenses under U.S. law can include:", options:["Only criminal fines with no civil alternatives","Criminal fines (up to $500,000 or twice the ML amount), civil money penalties, forfeiture of all proceeds and instrumentalities, and in corporate cases, debarment from government contracting","Only civil money penalties for financial institutions","Penalties are capped at $10,000 per transaction for individual offenders"], answer:1, explanation:"ML penalties are comprehensive: criminal fines under § 1956 can reach $500,000 or twice the laundered amount; forfeiture covers all criminal proceeds and instrumentalities; civil money penalties from FinCEN apply to BSA violations; and corporate ML convictions can lead to debarment from federal contracting. The combined exposure creates powerful deterrence." },
  { id:6584, domain:4, domainName:D4, question:"'Coordinated international law enforcement action' against ML networks (such as Operation Trojan Shield) is effective because:", options:["It eliminates the need for MLAT requests","Multiple countries' simultaneous action prevents criminals from evading enforcement in one jurisdiction by moving operations to another, and enables comprehensive asset recovery across the full international network","It allows one country's courts to prosecute criminals from all participating countries","It bypasses the need for formal legal process in each participating country"], answer:1, explanation:"Coordinated operations (like Operation Trojan Shield, which used an encrypted phone network to infiltrate organized crime globally) execute arrests, asset seizures, and searches simultaneously across multiple countries — preventing the warning one country's action would give criminals in other jurisdictions, maximizing the overall network disruption." },
  { id:6585, domain:4, domainName:D4, question:"'Public-private partnerships' in AML (such as the FinCEN Exchange and JMLIT in the UK) demonstrate that:", options:["Private sector institutions should replace government AML functions","Sharing intelligence between government (FIUs, law enforcement) and the private sector (financial institutions) creates an AML ecosystem more effective than either sector can achieve working independently","Public-private partnerships eliminate the need for SARs","Private sector AML should only be coordinated through industry trade associations"], answer:1, explanation:"Public-private partnerships leverage the complementary capabilities of each sector: governments have intelligence, investigative authority, and the ability to connect the dots across institutions; financial institutions have deep customer knowledge and real-time transaction visibility. Together they can detect and disrupt ML networks that neither could address alone." },
  { id:6586, domain:4, domainName:D4, question:"The 'Financial Crimes Enforcement Network' (FinCEN) serves simultaneously as:", options:["Only a regulatory agency","Only a law enforcement agency","The U.S. FIU, BSA administrator, financial intelligence analytics center, and AML regulatory standard-setter — combining regulatory, intelligence, and analytical functions","A criminal prosecution authority with arrest powers"], answer:2, explanation:"FinCEN's unique multi-functional role reflects the BSA's design: it administers the BSA (regulatory function); serves as the U.S. FIU in the Egmont Group (intelligence function); analyzes BSA data to produce financial intelligence (analytical function); and sets AML regulatory standards (policy function). This integration makes FinCEN uniquely positioned at the center of U.S. AML." },
  { id:6587, domain:4, domainName:D4, question:"A 'deferred prosecution agreement' differs from a 'non-prosecution agreement' (NPA) primarily in that:", options:["DPAs are only available for corporate defendants; NPAs apply to individuals","A DPA involves filing criminal charges that are held in abeyance pending compliance; an NPA does not involve filing criminal charges at all","NPAs require more substantial penalties than DPAs","DPAs are negotiated by DOJ; NPAs are negotiated by FinCEN"], answer:1, explanation:"Under a DPA, the government files criminal charges but agrees not to prosecute as long as the institution complies with the agreement's terms — the charges serve as a sword of Damocles. Under an NPA, no charges are filed at all. The DPA's filed-charges structure provides more deterrence and is reserved for more serious violations." },
  { id:6588, domain:4, domainName:D4, question:"'AML compliance monitors' in enforcement agreements are required to:", options:["Report solely to the financial institution's board of directors","Report to both the government authority (DOJ, OCC, FinCEN) and the institution's board — providing independent assessment of remediation progress to both parties","Conduct their work in complete secrecy with no public disclosure","Approve all SAR filing decisions during the monitorship period"], answer:1, explanation:"Monitors serve as the government's independent verification mechanism — reporting to the government on whether the institution is genuinely implementing required reforms. Simultaneously, they report to the institution's board, ensuring board-level accountability for remediation progress. This dual reporting is essential to the monitor's independence and effectiveness." },
  { id:6589, domain:4, domainName:D4, question:"'Whistleblower awards' under AMLA 2020 are paid to individuals who:", options:["File the most SARs with FinCEN in a calendar year","Provide original information to FinCEN or other authorities about BSA violations that leads to a successful enforcement action resulting in sanctions over $1 million — with awards ranging from 10-30% of sanctions collected","Report AML violations to the institution's internal compliance hotline","Identify structuring patterns in their institution's transaction data"], answer:1, explanation:"AMLA 2020's whistleblower program (31 U.S.C. § 5323) provides significant financial incentives for original information about BSA/AML violations — awards of 10-30% of sanctions over $1 million are intended to encourage reporting of institutional violations that might otherwise remain hidden, particularly when internal reporting is ineffective or retaliated against." },
  { id:6590, domain:4, domainName:D4, question:"'Asset repatriation' in international ML cases refers to:", options:["Returning a foreign ML suspect to the U.S. for prosecution","Returning criminal assets recovered by U.S. law enforcement to the foreign government from which they were stolen — particularly in kleptocracy and public corruption cases","Converting foreign currency assets to USD before forfeiture","Returning incorrectly seized assets to their innocent owners"], answer:1, explanation:"Asset repatriation is a key foreign policy dimension of international AML enforcement — the U.S. has returned hundreds of millions in assets to victim countries including Ukraine, Nigeria, Bangladesh, Malaysia, and others. UNCAC encourages repatriation, and the DOJ's Kleptocracy Asset Recovery Initiative specifically focuses on this." },
  { id:6591, domain:4, domainName:D4, question:"Which feature of U.S. forfeiture law most distinguishes it from the legal systems of many other countries?", options:["The U.S. requires a criminal conviction for all forfeiture","The U.S. system allows civil forfeiture without a criminal conviction — enabling asset recovery even when criminal prosecution is impossible or a conviction cannot be obtained","The U.S. does not have asset forfeiture laws","U.S. forfeiture requires higher proof standards than most other countries"], answer:1, explanation:"Civil forfeiture (in rem action against property) is a distinctive and controversial feature of U.S. law — it enables asset recovery without a criminal conviction by a preponderance of evidence standard. Many other countries (particularly civil law systems) have no civil forfeiture equivalent, requiring either a criminal conviction or NCB forfeiture legislation to recover assets." },
  { id:6592, domain:4, domainName:D4, question:"'Sanctions violation' reporting obligations differ from SAR filing obligations in that:", options:["Sanctions violations must always be reported to FinCEN using the SAR form","OFAC violations (blocked transactions, rejected payments) must be reported directly to OFAC within specified timeframes using OFAC's blocking/rejection reports — separate from and in addition to any SAR filing obligation","Only one of the two reports is required for any given incident","SAR filing supersedes OFAC reporting obligations"], answer:1, explanation:"Sanctions compliance has its own distinct reporting regime — OFAC blocking reports (10 business days for blocked transactions) and rejection reports (10 business days for rejected transactions) are separate from SAR filing obligations. An OFAC match may result in both a SAR filing (to FinCEN) AND an OFAC report (to OFAC) — different reports serving different regulatory purposes." },
  { id:6593, domain:4, domainName:D4, question:"'Formal and informal law enforcement cooperation' in AML means:", options:["Formal cooperation uses MLATs; informal cooperation uses bribery","Formal cooperation involves MLATs, court orders, and official legal channels; informal cooperation involves direct communication between law enforcement personnel, intelligence sharing, and voluntary assistance — complementing formal channels","Informal cooperation is prohibited by international law","Formal cooperation only occurs through INTERPOL; informal cooperation occurs bilaterally"], answer:1, explanation:"Both channels serve essential functions: formal (MLAT, court orders, official requests) for evidence that will be used in court proceedings; informal (law enforcement-to-law enforcement communication, intelligence tips, liaison arrangements) for developing investigative leads, coordinating strategy, and sharing intelligence that guides investigation before formal process is invoked." },
  { id:6594, domain:4, domainName:D4, question:"'Economic sanctions' as a component of the AML/CFT architecture are designed to:", options:["Generate government revenue from fined financial institutions","Deny access to the international financial system to individuals, entities, and regimes whose conduct poses national security or foreign policy threats — including terrorism financing, WMD proliferation, drug trafficking, and human rights violations","Punish all financial institutions operating in sanctioned countries","Automatically freeze the assets of anyone suspected of money laundering"], answer:1, explanation:"Economic sanctions serve national security and foreign policy objectives — they restrict designated parties' access to the U.S. financial system and the global dollar-clearing infrastructure, creating significant financial pressure that is designed to change behavior (e.g., stopping a weapons program, ending support for terrorism) rather than simply punish past conduct." },
  { id:6595, domain:4, domainName:D4, question:"The 'prosecution of money laundering' without prosecuting the predicate offense is:", options:["Never permitted under U.S. law","Specifically permitted under 18 U.S.C. § 1956(c)(7) — a defendant can be prosecuted for ML even if the predicate offense occurred in another country or was never charged","Only permitted in federal courts, not state courts","Only permitted when the predicate offense also involves drugs"], answer:1, explanation:"Section 1956 permits ML prosecution even when the predicate offense is not separately charged — prosecutors just need to prove that the proceeds come from a specified unlawful activity. This enables ML charges when: the predicate occurred abroad (where U.S. courts may lack jurisdiction); the statute of limitations on the predicate has run; or the ML case is stronger than the predicate case." },
  { id:6596, domain:4, domainName:D4, question:"'AML supervision' by banking regulators focuses PRIMARILY on:", options:["The quantity of SARs filed","Examining whether the institution has an effective, risk-based AML program that complies with applicable BSA requirements — with emphasis on governance, risk assessment, transaction monitoring quality, and the institution's ability to detect and report suspicious activity","Approving the institution's transaction monitoring scenarios before implementation","Reviewing every SAR filed by the institution for quality"], answer:1, explanation:"AML examination focuses on program effectiveness — not on second-guessing individual SAR filing decisions (examiners cannot require or prevent specific SAR filings), but on assessing whether the institution has adequate governance, risk assessment, monitoring systems, investigation processes, and training to fulfill its BSA obligations." },
  { id:6597, domain:4, domainName:D4, question:"'Correspondent banking enforcement actions' have consistently found that significant ML occurred because:", options:["Foreign banks deliberately structured transactions to avoid detection","U.S. correspondent banks failed to conduct adequate due diligence on respondent banks and their customers, and/or failed to monitor transactions for suspicious activity — allowing illicit funds to flow through U.S. financial infrastructure","OFAC sanctions lists were outdated and failed to identify the respondent banks","FinCEN failed to issue adequate guidance on correspondent banking risk"], answer:1, explanation:"Major enforcement actions (HSBC, Standard Chartered, Deutsche Bank, Citibank, Wachovia) consistently identified the same root causes: inadequate due diligence on respondent banks; insufficient transaction monitoring on correspondent accounts; inadequate controls for processing transactions from high-risk jurisdictions; and governance failures that allowed these deficiencies to persist." },
  { id:6598, domain:4, domainName:D4, question:"'FATF's methodology' for conducting mutual evaluations assesses countries against:", options:["40 Technical Compliance criteria only","40 Recommendations for Technical Compliance AND 11 Immediate Outcomes for Effectiveness — providing both a 'checklist' assessment of legal structures and an outcomes-based assessment of whether those structures actually work","A single overall AML effectiveness score","Only the countries' AML legislation, not their implementation"], answer:1, explanation:"The 2013 FATF Methodology introduced the dual-component evaluation: 40 Technical Compliance ratings (how well the country's laws and institutions conform to FATF standards) and 11 Immediate Outcomes (whether those laws and institutions achieve actual AML/CFT results). Both dimensions are necessary for a complete picture of a country's AML/CFT system." },
  { id:6599, domain:4, domainName:D4, question:"'Return on investment' of AML compliance spending is BEST measured by:", options:["Comparing AML budget to revenue generated by compliance activities","Quantifying enforcement penalties avoided, intelligence value provided to law enforcement, reputational risks mitigated, and the financial crime that the program detected and prevented — though many of these benefits are difficult to quantify precisely","Counting the number of SARs filed per compliance dollar spent","Comparing the institution's compliance costs to industry peers as a percentage of revenue"], answer:1, explanation:"AML ROI is conceptually clear but practically difficult to quantify — the benefits include: enforcement penalties avoided; reputational harm prevented; financial crimes stopped (though quantification is inherently uncertain); law enforcement intelligence provided; and regulatory trust maintained. While imprecise, this framework is more meaningful than simple cost benchmarking." },
  { id:6600, domain:4, domainName:D4, question:"A financial institution's CAMS-certified compliance officer is MOST valuable because:", options:["CAMS certification provides legal immunity for SAR filing decisions made in good faith","The CAMS certification demonstrates comprehensive, validated knowledge of ML/TF typologies, AML compliance program design, financial investigation techniques, and law enforcement cooperation — directly applicable to building and operating an effective AML program","CAMS certification is legally required for all BSA officers under FinCEN regulations","CAMS certification guarantees a clean regulatory examination for the certifying institution"], answer:1, explanation:"CAMS-certified professionals bring validated, comprehensive expertise to AML compliance — the certification's four-domain structure (Risks & Methods; Compliance Programs; Investigations; Law Enforcement) mirrors the full lifecycle of AML compliance. This breadth of knowledge enables CAMS holders to design effective programs, investigate complex cases, and engage productively with law enforcement partners." },
];

